Build me an app to Do this:

- Input data for Transaction
- Visualize Transactions Total and Day wise
- Sync Data with Google Sheets (use as database for data persistence)


Currently using google script to data entry to Google sheets.
Script code:
function doGet() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const ws = ss.getSheetByName("Transcations");
  const data = ws.getDataRange().getValues();
  const headers = data.shift(); // Remove header row

  const json = data.map(row => ({
    date: row[0] instanceof Date ? row[0].toISOString().split('T')[0] : row[0],
    amount: row[1],
    name: row[2]
  }));

  return ContentService.createTextOutput(JSON.stringify(json))
    .setMimeType(ContentService.MimeType.JSON);
}

function doPost(e) {
  const params = JSON.parse(e.postData.contents);
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const ws = ss.getSheetByName("Transcations");

  ws.appendRow([
    params.date,
    params.amount,
    params.name
  ]);

  return ContentService.createTextOutput("Success")
    .setMimeType(ContentService.MimeType.TEXT);
}

