import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Transaction {
  date: string;
  amount: number;
  name: string;
}

export interface DailyTotal {
  date: string;
  total: number;
}

export type ViewType = 'dashboard' | 'transactions' | 'settings';

import { Transaction } from '../types';

export class GoogleSheetsService {
  private static STORAGE_KEY = 'gs_script_url';

  static getScriptUrl(): string {
    return localStorage.getItem(this.STORAGE_KEY) || '';
  }

  static setScriptUrl(url: string): void {
    localStorage.setItem(this.STORAGE_KEY, url);
  }

  /**
   * Fetches transactions from the Google Sheet via GET request.
   */
  static async fetchTransactions(): Promise<Transaction[]> {
    const url = this.getScriptUrl();
    if (!url) throw new Error('Google Script URL not configured.');

    try {
      const response = await fetch(url);
      if (!response.ok) throw new Error('Failed to fetch data from Google Sheets.');
      return await response.json();
    } catch (error) {
      console.error('Error fetching transactions:', error);
      throw error;
    }
  }

  /**
   * Sends a new transaction to the Google Sheet via POST request.
   * Note: GAS doPost handles JSON content if configured correctly.
   */
  static async addTransaction(transaction: Transaction): Promise<void> {
    const url = this.getScriptUrl();
    if (!url) throw new Error('Google Script URL not configured.');

    try {
      // GAS often requires redirects for POST requests. 
      // Most browsers handle this, but some GAS setups prefer 'no-cors' 
      // which prevents reading the response. We use 'cors' here.
      const response = await fetch(url, {
        method: 'POST',
        mode: 'no-cors', // Many GAS implementations work best with 'no-cors' for POST to avoid preflight issues
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(transaction),
      });

      // With no-cors, we can't check response.ok, so we assume success if no error thrown
    } catch (error) {
      console.error('Error adding transaction:', error);
      throw error;
    }
  }
}

import React from 'react';

interface StatCardProps {
  label: string;
  value: string | number;
  icon: React.ReactNode;
  trend?: string;
  color: string;
}

const StatCard: React.FC<StatCardProps> = ({ label, value, icon, trend, color }) => {
  return (
    <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex items-center gap-4">
      <div className={`p-3 rounded-xl ${color}`}>
        {icon}
      </div>
      <div>
        <p className="text-sm font-medium text-slate-500 uppercase tracking-wider">{label}</p>
        <h3 className="text-2xl font-bold text-slate-800">{value}</h3>
        {trend && (
          <p className="text-xs font-semibold text-emerald-600 mt-1">
            {trend}
          </p>
        )}
      </div>
    </div>
  );
};

export default StatCard;

import React, { useState } from 'react';
import { Transaction } from '../types';
import { PlusCircle, Loader2 } from 'lucide-react';

interface TransactionFormProps {
  onSuccess: (transaction: Transaction) => void;
  isLoading: boolean;
}

const TransactionForm: React.FC<TransactionFormProps> = ({ onSuccess, isLoading }) => {
  const [formData, setFormData] = useState<Transaction>({
    date: new Date().toISOString().split('T')[0],
    amount: 0,
    name: '',
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (formData.amount <= 0 || !formData.name) return;
    onSuccess(formData);
    setFormData({
      date: new Date().toISOString().split('T')[0],
      amount: 0,
      name: '',
    });
  };

  return (
    <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 h-full">
      <h3 className="text-lg font-semibold text-slate-800 mb-6 flex items-center gap-2">
        <PlusCircle className="w-5 h-5 text-indigo-500" />
        New Transaction
      </h3>
      <form onSubmit={handleSubmit} className="space-y-4">
        <div>
          <label className="block text-sm font-medium text-slate-600 mb-1">Date</label>
          <input
            type="date"
            required
            className="w-full px-4 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all"
            value={formData.date}
            onChange={(e) => setFormData({ ...formData, date: e.target.value })}
          />
        </div>
        <div>
          <label className="block text-sm font-medium text-slate-600 mb-1">Transaction Name</label>
          <input
            type="text"
            required
            placeholder="e.g. Grocery, Salary"
            className="w-full px-4 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all"
            value={formData.name}
            onChange={(e) => setFormData({ ...formData, name: e.target.value })}
          />
        </div>
        <div>
          <label className="block text-sm font-medium text-slate-600 mb-1">Amount ($)</label>
          <input
            type="number"
            step="0.01"
            required
            placeholder="0.00"
            className="w-full px-4 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all"
            value={formData.amount || ''}
            onChange={(e) => setFormData({ ...formData, amount: parseFloat(e.target.value) })}
          />
        </div>
        <button
          type="submit"
          disabled={isLoading}
          className="w-full bg-indigo-600 hover:bg-indigo-700 disabled:bg-indigo-300 text-white font-semibold py-3 rounded-lg shadow-md shadow-indigo-200 transition-all flex items-center justify-center gap-2"
        >
          {isLoading ? (
            <Loader2 className="w-5 h-5 animate-spin" />
          ) : (
            <>
              <PlusCircle className="w-5 h-5" />
              Add Transaction
            </>
          )}
        </button>
      </form>
    </div>
  );
};

export default TransactionForm;

import React, { useMemo } from 'react';
import { Transaction, DailyTotal } from '../types';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer,
  Cell,
  PieChart,
  Pie
} from 'recharts';
import { DollarSign, Calendar, TrendingUp, Wallet } from 'lucide-react';
import StatCard from './StatCard';

interface DashboardProps {
  transactions: Transaction[];
}

const Dashboard: React.FC<DashboardProps> = ({ transactions }) => {
  const stats = useMemo(() => {
    const total = transactions.reduce((acc, curr) => acc + curr.amount, 0);
    const avg = transactions.length > 0 ? total / transactions.length : 0;

    // Group by day for the last 7 days (or just sort all days)
    const dailyMap = transactions.reduce((acc: Record<string, number>, curr) => {
      acc[curr.date] = (acc[curr.date] || 0) + curr.amount;
      return acc;
    }, {});

    const dailyData: DailyTotal[] = Object.entries(dailyMap)
      .map(([date, total]) => ({ date, total }))
      .sort((a, b) => a.date.localeCompare(b.date))
      .slice(-14); // Last 14 days of data

    return { total, avg, dailyData };
  }, [transactions]);

  const COLORS = ['#6366f1', '#8b5cf6', '#ec4899', '#f43f5e', '#f97316'];

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard 
          label="Total Balance" 
          value={`$${stats.total.toLocaleString(undefined, { minimumFractionDigits: 2 })}`} 
          icon={<DollarSign className="w-6 h-6 text-emerald-600" />}
          color="bg-emerald-50"
        />
        <StatCard 
          label="Avg. Per Transaction" 
          value={`$${stats.avg.toLocaleString(undefined, { minimumFractionDigits: 2 })}`} 
          icon={<TrendingUp className="w-6 h-6 text-indigo-600" />}
          color="bg-indigo-50"
        />
        <StatCard 
          label="Transaction Count" 
          value={transactions.length} 
          icon={<Wallet className="w-6 h-6 text-violet-600" />}
          color="bg-violet-50"
        />
        <StatCard 
          label="Last Entry" 
          value={transactions.length > 0 ? transactions[transactions.length - 1].date : '--'} 
          icon={<Calendar className="w-6 h-6 text-slate-600" />}
          color="bg-slate-100"
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <h3 className="text-lg font-semibold text-slate-800 mb-6">Daily Spending (Last 14 Records)</h3>
          <div className="h-80 w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={stats.dailyData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis 
                  dataKey="date" 
                  axisLine={false} 
                  tickLine={false} 
                  tick={{ fontSize: 12, fill: '#64748b' }} 
                  dy={10}
                />
                <YAxis 
                  axisLine={false} 
                  tickLine={false} 
                  tick={{ fontSize: 12, fill: '#64748b' }}
                />
                <Tooltip 
                  cursor={{ fill: '#f8fafc' }}
                  contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)' }}
                />
                <Bar dataKey="total" radius={[4, 4, 0, 0]}>
                  {stats.dailyData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <h3 className="text-lg font-semibold text-slate-800 mb-6">Spending Distribution</h3>
          <div className="h-80 w-full flex flex-col items-center justify-center">
            {transactions.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie
                    data={transactions.slice(-5)} // Just demoing last 5 items
                    dataKey="amount"
                    nameKey="name"
                    cx="50%"
                    cy="50%"
                    innerRadius={60}
                    outerRadius={80}
                    paddingAngle={5}
                    fill="#8884d8"
                  >
                    {transactions.slice(-5).map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                    ))}
                  </Pie>
                  <Tooltip 
                    contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)' }}
                  />
                </PieChart>
              </ResponsiveContainer>
            ) : (
              <div className="text-slate-400 text-sm">No data to display</div>
            )}
            <div className="mt-4 space-y-2 w-full px-4">
              {transactions.slice(-3).reverse().map((t, idx) => (
                <div key={idx} className="flex items-center justify-between text-xs">
                  <span className="text-slate-500 font-medium truncate w-32">{t.name}</span>
                  <span className="text-slate-800 font-bold">${t.amount.toFixed(2)}</span>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { GoogleSheetsService } from '../services/googleSheets';
import { Settings as SettingsIcon, Save, ExternalLink, Info } from 'lucide-react';

interface SettingsProps {
  onSave: () => void;
}

const Settings: React.FC<SettingsProps> = ({ onSave }) => {
  const [url, setUrl] = useState(GoogleSheetsService.getScriptUrl());
  const [status, setStatus] = useState<'idle' | 'saved'>('idle');

  const handleSave = () => {
    GoogleSheetsService.setScriptUrl(url);
    setStatus('saved');
    setTimeout(() => {
      setStatus('idle');
      onSave();
    }, 1500);
  };

  return (
    <div className="max-w-2xl mx-auto space-y-6">
      <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-100">
        <h2 className="text-xl font-bold text-slate-800 mb-6 flex items-center gap-2">
          <SettingsIcon className="w-6 h-6 text-indigo-500" />
          Sync Configuration
        </h2>

        <div className="space-y-6">
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-2">Google Apps Script Web App URL</label>
            <input
              type="text"
              placeholder="https://script.google.com/macros/s/.../exec"
              className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all font-mono text-sm"
              value={url}
              onChange={(e) => setUrl(e.target.value)}
            />
            <p className="mt-2 text-xs text-slate-500 flex items-center gap-1">
              <Info className="w-3 h-3" />
              Ensure your script is deployed as a Web App with access set to "Anyone".
            </p>
          </div>

          <button
            onClick={handleSave}
            className="flex items-center justify-center gap-2 px-6 py-3 bg-indigo-600 hover:bg-indigo-700 text-white font-semibold rounded-xl transition-all w-full shadow-lg shadow-indigo-100"
          >
            {status === 'saved' ? 'Config Saved!' : (
              <>
                <Save className="w-5 h-5" />
                Save Connection URL
              </>
            )}
          </button>
        </div>
      </div>

      <div className="bg-indigo-50 p-6 rounded-2xl border border-indigo-100">
        <h3 className="font-semibold text-indigo-900 mb-3 flex items-center gap-2">
          <ExternalLink className="w-4 h-4" />
          Quick Instructions
        </h3>
        <ol className="text-sm text-indigo-800 space-y-2 list-decimal list-inside">
          <li>Create a Google Sheet and name a sheet <strong>"Transcations"</strong>.</li>
          <li>Go to Extensions &gt; Apps Script.</li>
          <li>Paste the provided script code.</li>
          <li>Click <strong>Deploy &gt; New Deployment</strong>.</li>
          <li>Select <strong>Web App</strong>, Execute as "Me", Access: "Anyone".</li>
          <li>Copy the Web App URL and paste it above.</li>
        </ol>
      </div>
    </div>
  );
};

export default Settings;

import React, { useState, useEffect, useCallback } from 'react';
import { Transaction, ViewType } from './types';
import { GoogleSheetsService } from './services/googleSheets';
import TransactionForm from './components/TransactionForm';
import Dashboard from './components/Dashboard';
import TransactionList from './components/TransactionList';
import Settings from './components/Settings';
import { 
  LayoutDashboard, 
  Receipt, 
  Settings as SettingsIcon, 
  RefreshCw,
  Search,
  AlertCircle,
  Menu,
  X
} from 'lucide-react';

const App: React.FC = () => {
  const [view, setView] = useState<ViewType>('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  const fetchData = useCallback(async () => {
    const url = GoogleSheetsService.getScriptUrl();
    if (!url) {
      setError('Google Script URL is not configured. Please go to Settings.');
      return;
    }

    setIsLoading(true);
    setError(null);
    try {
      const data = await GoogleSheetsService.fetchTransactions();
      setTransactions(data);
    } catch (err) {
      setError('Could not fetch data. Check your Script URL and CORS settings.');
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  const handleAddTransaction = async (newTransaction: Transaction) => {
    setIsSyncing(true);
    try {
      await GoogleSheetsService.addTransaction(newTransaction);
      // Optimistic update
      setTransactions([...transactions, newTransaction]);
      // Then re-fetch to ensure sync
      setTimeout(() => fetchData(), 2000); 
    } catch (err) {
      setError('Sync failed, but transaction added locally.');
    } finally {
      setIsSyncing(false);
    }
  };

  const navItems = [
    { id: 'dashboard', label: 'Dashboard', icon: LayoutDashboard },
    { id: 'transactions', label: 'All Entries', icon: Receipt },
    { id: 'settings', label: 'Settings', icon: SettingsIcon },
  ];

  return (
    <div className="min-h-screen bg-slate-50 flex">
      {/* Mobile Sidebar Overlay */}
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-40 lg:hidden"
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      {/* Sidebar */}
      <aside className={`
        fixed inset-y-0 left-0 z-50 w-64 bg-white border-r border-slate-100 transform transition-transform duration-300 ease-in-out lg:relative lg:translate-x-0
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}
      `}>
        <div className="h-full flex flex-col">
          <div className="p-6">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-indigo-100">
                <RefreshCw className="w-6 h-6" />
              </div>
              <h1 className="text-xl font-bold text-slate-800 tracking-tight">SheetSpend</h1>
            </div>
          </div>

          <nav className="flex-1 px-4 space-y-1">
            {navItems.map((item) => (
              <button
                key={item.id}
                onClick={() => {
                  setView(item.id as ViewType);
                  setIsSidebarOpen(false);
                }}
                className={`
                  w-full flex items-center gap-3 px-4 py-3 rounded-xl text-sm font-semibold transition-all
                  ${view === item.id 
                    ? 'bg-indigo-50 text-indigo-600 shadow-sm' 
                    : 'text-slate-500 hover:bg-slate-50 hover:text-slate-800'}
                `}
              >
                <item.icon className="w-5 h-5" />
                {item.label}
              </button>
            ))}
          </nav>

          <div className="p-6 border-t border-slate-100">
            <div className="bg-slate-50 rounded-2xl p-4">
              <p className="text-xs font-medium text-slate-400 mb-1 uppercase">Cloud Status</p>
              <div className="flex items-center gap-2">
                <div className={`w-2 h-2 rounded-full ${transactions.length > 0 ? 'bg-emerald-500' : 'bg-amber-500'}`} />
                <span className="text-sm font-bold text-slate-700">
                  {transactions.length > 0 ? 'Synced' : 'No Connection'}
                </span>
              </div>
            </div>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col min-w-0 h-screen overflow-y-auto">
        {/* Header */}
        <header className="sticky top-0 z-30 bg-white/80 backdrop-blur-md border-b border-slate-100 px-6 py-4 flex items-center justify-between">
          <div className="flex items-center gap-4">
            <button 
              className="lg:hidden p-2 text-slate-500 hover:bg-slate-50 rounded-lg"
              onClick={() => setIsSidebarOpen(true)}
            >
              <Menu className="w-6 h-6" />
            </button>
            <h2 className="text-lg font-bold text-slate-800 capitalize">
              {view === 'dashboard' ? 'Quick Overview' : view}
            </h2>
          </div>

          <div className="flex items-center gap-4">
            <div className="hidden md:flex items-center bg-slate-100 rounded-full px-4 py-2 gap-2 text-slate-400 focus-within:text-indigo-600 focus-within:bg-white focus-within:ring-2 focus-within:ring-indigo-100 transition-all">
              <Search className="w-4 h-4" />
              <input 
                type="text" 
                placeholder="Search..." 
                className="bg-transparent border-none text-sm focus:outline-none text-slate-800 w-32"
              />
            </div>
            <button 
              onClick={fetchData}
              disabled={isLoading}
              className="p-2 text-slate-500 hover:text-indigo-600 hover:bg-indigo-50 rounded-full transition-all disabled:opacity-50"
            >
              <RefreshCw className={`w-5 h-5 ${isLoading ? 'animate-spin text-indigo-600' : ''}`} />
            </button>
          </div>
        </header>

        <div className="flex-1 p-6 md:p-8 max-w-7xl mx-auto w-full space-y-8">
          {error && (
            <div className="bg-amber-50 border border-amber-200 p-4 rounded-xl flex items-center gap-3 text-amber-800 text-sm shadow-sm animate-in slide-in-from-top duration-300">
              <AlertCircle className="w-5 h-5 flex-shrink-0" />
              <span>{error}</span>
              {view !== 'settings' && (
                <button 
                  onClick={() => setView('settings')}
                  className="underline font-bold ml-auto"
                >
                  Configure Now
                </button>
              )}
            </div>
          )}

          {view === 'dashboard' && (
            <div className="grid grid-cols-1 xl:grid-cols-4 gap-8">
              <div className="xl:col-span-3">
                <Dashboard transactions={transactions} />
              </div>
              <div className="xl:col-span-1">
                <TransactionForm onSuccess={handleAddTransaction} isLoading={isSyncing} />
              </div>
            </div>
          )}

          {view === 'transactions' && (
            <div className="space-y-6">
              <TransactionList transactions={transactions} />
