export class GoogleSheetsService {
  private static STORAGE_KEY = 'gs_script_url';

  static getScriptUrl(): string {
    return localStorage.getItem(this.STORAGE_KEY) || '';
  }

  static setScriptUrl(url: string): void {
    localStorage.setItem(this.STORAGE_KEY, url.trim());
  }

  /**
   * Fetches transactions from the Google Sheet via GET request.
   */
  static async fetchTransactions(): Promise<Transaction[]> {
    const url = this.getScriptUrl();
    if (!url) throw new Error('Google Script URL not configured.');

    try {
      // GAS requires following redirects. 'follow' is default but we make it explicit.
      const response = await fetch(url, {
        method: 'GET',
        mode: 'cors',
        cache: 'no-cache',
        redirect: 'follow',
      });

      if (!response.ok) throw new Error(`Server responded with ${response.status}`);

      const data = await response.json();
      return data.map((item: any) => ({
        ...item,
        amount: typeof item.amount === 'string' ? parseFloat(item.amount.replace(/[^0-9.-]+/g,"")) : item.amount
      }));
    } catch (error) {
      console.error('Error fetching transactions:', error);
      // More helpful error for common GAS issues
      throw new Error('Failed to connect to Google Sheets. Ensure your Script is deployed as "Anyone" and the URL is correct.');
    }
  }

  /**
   * Sends a new transaction to the Google Sheet via POST request.
   */
  static async addTransaction(transaction: Transaction): Promise<void> {
    const url = this.getScriptUrl();
    if (!url) throw new Error('Google Script URL not configured.');

    try {
      // Ensure we only send the raw number to Google Sheets, no currency symbols
      const payload = {
        date: transaction.date,
        amount: Number(transaction.amount), 
        name: transaction.name
      };

      await fetch(url, {
        method: 'POST',
        mode: 'no-cors', // Standard workaround for GAS POST requests
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(payload),
      });
    } catch (error) {
      console.error('Error adding transaction:', error);
      throw error;
    }
  }
}

