  const [formData, setFormData] = useState<Transaction>({
    date: new Date().toISOString().split('T')[0],
    amount: 0,
    name: '',
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (formData.amount <= 0 || !formData.name) return;
    onSuccess(formData);
    setFormData({
      date: new Date().toISOString().split('T')[0],
      amount: 0,
      name: '',
