import React, { useMemo } from 'react';
import { Transaction, DailyTotal } from '../types';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer,
  Cell,
  PieChart,
  Pie
} from 'recharts';
import { Landmark, Calendar, TrendingUp, Wallet } from 'lucide-react';
import StatCard from './StatCard';

interface DashboardProps {
  transactions: Transaction[];
}

const Dashboard: React.FC<DashboardProps> = ({ transactions }) => {
  const stats = useMemo(() => {
    const total = transactions.reduce((acc, curr) => acc + curr.amount, 0);
    const avg = transactions.length > 0 ? total / transactions.length : 0;

    // Fix: Using explicit parameter types and type assertion for the initial value 
    // to avoid "Untyped function calls may not accept type arguments" and typing issues.
    const dailyMap = transactions.reduce((acc: Record<string, number>, curr) => {
      acc[curr.date] = (acc[curr.date] || 0) + curr.amount;
      return acc;
    }, {} as Record<string, number>);

    // Fix: Explicitly cast total to number to resolve 'unknown' type error in mapping
    const dailyData: DailyTotal[] = Object.entries(dailyMap)
      .map(([date, total]) => ({ date, total: total as number }))
      .sort((a, b) => a.date.localeCompare(b.date))
      .slice(-14);

    return { total, avg, dailyData };
  }, [transactions]);

  const COLORS = ['#6366f1', '#8b5cf6', '#ec4899', '#f43f5e', '#f97316'];

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard 
          label="Total (MVR)" 
          value={`${stats.total.toLocaleString(undefined, { minimumFractionDigits: 2 })}`} 
          icon={<Landmark className="w-6 h-6 text-emerald-600" />}
          color="bg-emerald-50"
        />
        <StatCard 
          label="Average Rf" 
          value={`${stats.avg.toLocaleString(undefined, { minimumFractionDigits: 2 })}`} 
          icon={<TrendingUp className="w-6 h-6 text-indigo-600" />}
          color="bg-indigo-50"
        />
        <StatCard 
          label="Transactions" 
          value={transactions.length} 
          icon={<Wallet className="w-6 h-6 text-violet-600" />}
          color="bg-violet-50"
        />
        <StatCard 
          label="Last Update" 
          value={transactions.length > 0 ? transactions[transactions.length - 1].date : '--'} 
          icon={<Calendar className="w-6 h-6 text-slate-600" />}
          color="bg-slate-100"
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 bg-white p-8 rounded-3xl shadow-sm border border-slate-100">
          <div className="flex items-center justify-between mb-8">
            <h3 className="text-xl font-bold text-slate-800">Spending Trends (MVR)</h3>
            <div className="text-xs font-medium text-slate-400">Past 14 entries</div>
          </div>
          <div className="h-80 w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={stats.dailyData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis 
                  dataKey="date" 
                  axisLine={false} 
                  tickLine={false} 
                  tick={{ fontSize: 11, fill: '#94a3b8' }} 
                  dy={10}
                />
                <YAxis 
                  axisLine={false} 
                  tickLine={false} 
                  tick={{ fontSize: 11, fill: '#94a3b8' }}
                />
                <Tooltip 
                  cursor={{ fill: '#f8fafc' }}
                  formatter={(value) => [`${value} MVR`, 'Total']}
                  contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 20px 25px -5px rgba(0,0,0,0.1)' }}
                />
                <Bar dataKey="total" radius={[6, 6, 0, 0]} barSize={32}>
                  {stats.dailyData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100 flex flex-col">
          <h3 className="text-xl font-bold text-slate-800 mb-8">Recent Allocation</h3>
          <div className="flex-1 flex flex-col items-center justify-center min-h-[300px]">
            {transactions.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie
                    data={transactions.slice(-5)}
                    dataKey="amount"
                    nameKey="name"
                    cx="50%"
                    cy="50%"
                    innerRadius={70}
                    outerRadius={95}
                    paddingAngle={8}
                    fill="#8884d8"
                  >
                    {transactions.slice(-5).map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} strokeWidth={0} />
                    ))}
                  </Pie>
                  <Tooltip 
                    formatter={(value) => [`${value} MVR`]}
                    contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 20px 25px -5px rgba(0,0,0,0.1)' }}
                  />
                </PieChart>
              </ResponsiveContainer>
            ) : (
              <div className="text-slate-400 text-sm">Waiting for data...</div>
            )}
            <div className="mt-8 space-y-3 w-full px-2">
              {transactions.slice(-3).reverse().map((t, idx) => (
                <div key={idx} className="flex items-center justify-between group">
                  <div className="flex items-center gap-2">
                    <div className="w-2 h-2 rounded-full" style={{ backgroundColor: COLORS[idx % COLORS.length] }} />
                    <span className="text-sm font-semibold text-slate-600 truncate w-32 group-hover:text-indigo-600 transition-colors">{t.name}</span>
                  </div>
                  <span className="text-sm font-black text-slate-800">Rf {t.amount.toFixed(2)}</span>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

