    const day = String(now.getDate()).padStart(2, '0');
    const todayStr = `${year}-${month}-${day}`;

    // Calculate Today's Total - more robust comparison (taking just the date part)
    const todayTotal = transactions
      .filter(t => {
        if (!t.date) return false;
        // Handle cases where the date might come back as a full ISO string from the API
        const transactionDate = t.date.includes('T') ? t.date.split('T')[0] : t.date;
        return transactionDate === todayStr;
      })
      .reduce((acc, curr) => acc + curr.amount, 0);

    const dailyMap = transactions.reduce((acc: Record<string, number>, curr) => {
      // Normalize date key to YYYY-MM-DD
      const dateKey = curr.date.includes('T') ? curr.date.split('T')[0] : curr.date;
      acc[dateKey] = (acc[dateKey] || 0) + curr.amount;
      return acc;
    }, {} as Record<string, number>);

