interface TransactionFormProps {
  onSuccess: (transaction: Transaction) => void;
  isLoading: boolean;
}

const TransactionForm: React.FC<TransactionFormProps> = ({ onSuccess, isLoading }) => {
  // Helper for local YYYY-MM-DD
  const getLocalDateString = () => {
    const now = new Date();
    const year = now.getFullYear();
    const month = String(now.getMonth() + 1).padStart(2, '0');
    const day = String(now.getDate()).padStart(2, '0');
    return `${year}-${month}-${day}`;
  };

  const [formData, setFormData] = useState<Transaction>({
    date: getLocalDateString(),
    amount: 0,
    name: '',
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (formData.amount <= 0 || !formData.name) return;
    onSuccess(formData);
    setFormData({
      date: getLocalDateString(),
      amount: 0,
      name: '',
    });
  };

  return (
    <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100 h-full relative overflow-hidden">
      <div className="absolute top-0 right-0 p-4 opacity-5">
        <Sparkles className="w-24 h-24 text-indigo-600" />
      </div>

      <h3 className="text-xl font-bold text-slate-800 mb-8 flex items-center gap-3">
        <div className="p-2 bg-indigo-50 rounded-xl">
          <PlusCircle className="w-5 h-5 text-indigo-600" />
        </div>
        Record Transaction
      </h3>

      <form onSubmit={handleSubmit} className="space-y-6">
        <div className="space-y-2">
          <label className="text-xs font-bold text-slate-400 uppercase tracking-widest px-1">Date</label>
          <input
            type="date"
            required
            className="w-full px-5 py-4 bg-slate-50 border border-slate-100 rounded-2xl focus:outline-none focus:ring-4 focus:ring-indigo-500/10 focus:bg-white focus:border-indigo-500 transition-all text-sm font-medium"
            value={formData.date}
            onChange={(e) => setFormData({ ...formData, date: e.target.value })}
          />
        </div>
        <div className="space-y-2">
          <label className="text-xs font-bold text-slate-400 uppercase tracking-widest px-1">Description</label>
          <input
            type="text"
            required
            placeholder="What was this for?"
            className="w-full px-5 py-4 bg-slate-50 border border-slate-100 rounded-2xl focus:outline-none focus:ring-4 focus:ring-indigo-500/10 focus:bg-white focus:border-indigo-500 transition-all text-sm font-medium"
            value={formData.name}
            onChange={(e) => setFormData({ ...formData, name: e.target.value })}
          />
        </div>
        <div className="space-y-2">
          <label className="text-xs font-bold text-slate-400 uppercase tracking-widest px-1">Amount (Rf)</label>
          <div className="relative">
            <span className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-400 font-bold text-sm">Rf</span>
            <input
              type="number"
              step="0.01"
              required
              placeholder="0.00"
              className="w-full pl-12 pr-5 py-4 bg-slate-50 border border-slate-100 rounded-2xl focus:outline-none focus:ring-4 focus:ring-indigo-500/10 focus:bg-white focus:border-indigo-500 transition-all text-sm font-black"
              value={formData.amount || ''}
              onChange={(e) => setFormData({ ...formData, amount: parseFloat(e.target.value) })}
            />
          </div>
        </div>

        <button
          type="submit"
          disabled={isLoading}
          className="w-full bg-slate-900 hover:bg-indigo-600 disabled:bg-slate-300 text-white font-bold py-4 rounded-2xl shadow-xl shadow-slate-200 hover:shadow-indigo-200 transition-all flex items-center justify-center gap-3 active:scale-[0.98] group"
        >
          {isLoading ? (
