          icon={<TrendingUp className="w-6 h-6 text-indigo-600" />}
          color="bg-indigo-50"
        />
        <StatCard 
          label="Transactions" 
          value={`${transactions.length} Entries`} 
          icon={<Wallet className="w-6 h-6 text-violet-600" />}
          color="bg-violet-50"
        />
        <StatCard 
          label="Last Entry" 
          value={transactions.length > 0 ? (transactions[transactions.length - 1].date.split('T')[0]) : '--'} 
          icon={<Calendar className="w-6 h-6 text-slate-600" />}
          color="bg-slate-100"
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
