              className="p-3 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-2xl transition-all disabled:opacity-50 border border-slate-100"
            >
              <RefreshCw className={`w-5 h-5 ${isLoading ? 'animate-spin text-indigo-600' : ''}`} />
            </button>
          </div>
        </header>

        <div className="flex-1 p-8 lg:p-12 overflow-y-auto custom-scrollbar">
          <div className="max-w-7xl mx-auto space-y-10 pb-12">
            {error && (
              <div className="bg-rose-50 border border-rose-100 p-5 rounded-3xl flex items-center gap-4 text-rose-800 text-sm shadow-sm animate-in slide-in-from-top-4 duration-500">
                <div className="p-2 bg-rose-100 rounded-xl">
                    <AlertCircle className="w-5 h-5 flex-shrink-0" />
                </div>
                <div className="flex-1">
                  <p className="font-bold">Sync Issue Detected</p>
                  <p className="text-rose-600/80 font-medium">{error}</p>
                </div>
                {view !== 'settings' && (
                  <button 
                    onClick={() => setView('settings')}
                    className="bg-white border border-rose-200 px-4 py-2 rounded-xl text-xs font-black shadow-sm hover:bg-rose-100 transition-colors"
                  >
                    Fix Connection
                  </button>
                )}
              </div>
            )}

            {view === 'dashboard' && (
              <div className="grid grid-cols-1 xl:grid-cols-12 gap-10">
                <div className="xl:col-span-4">
                  <TransactionForm onSuccess={handleAddTransaction} isLoading={isSyncing} />
                </div>
                <div className="xl:col-span-8">
                  <Dashboard transactions={transactions} />
                </div>
              </div>
            )}

            {view === 'transactions' && (
              <div className="space-y-6">
                <TransactionList transactions={transactions} />
