                  <span className="text-xs font-bold text-slate-600 truncate group-hover:text-indigo-600 transition-colors">{t.name}</span>
                </div>
                <span className="text-xs font-black text-slate-800 shrink-0 ml-2">Rf {t.amount.toFixed(2)}</span>
