import React, { useState, useEffect, useCallback } from 'react';
import { Transaction, ViewType } from './types';
import { GoogleSheetsService } from './services/googleSheets';
import TransactionForm from './components/TransactionForm';
import Dashboard from './components/Dashboard';
import TransactionList from './components/TransactionList';
import Settings from './components/Settings';
import { 
  LayoutDashboard, 
  Receipt, 
  Settings as SettingsIcon, 
  RefreshCw,
  Search,
  AlertCircle,
  Menu,
  Zap
} from 'lucide-react';

const App: React.FC = () => {
  const [view, setView] = useState<ViewType>('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  const fetchData = useCallback(async () => {
    const url = GoogleSheetsService.getScriptUrl();
    if (!url) {
      setError('Connection not established. Please configure the Script URL.');
      return;
    }

    setIsLoading(true);
    setError(null);
    try {
      const data = await GoogleSheetsService.fetchTransactions();
      setTransactions(data);
    } catch (err: any) {
      setError(err.message || 'Could not fetch data. Check your permissions.');
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  const handleAddTransaction = async (newTransaction: Transaction) => {
    setIsSyncing(true);
    try {
      await GoogleSheetsService.addTransaction(newTransaction);
      // Optimistic local update
      setTransactions(prev => [...prev, newTransaction]);
      // Gentle delayed re-fetch to ensure remote sync is complete
      setTimeout(() => fetchData(), 3000); 
    } catch (err) {
      setError('Cloud sync failed, entry saved locally.');
    } finally {
      setIsSyncing(false);
    }
  };

  const navItems = [
    { id: 'dashboard', label: 'Dashboard', icon: LayoutDashboard },
    { id: 'transactions', label: 'History', icon: Receipt },
    { id: 'settings', label: 'Connection', icon: SettingsIcon },
  ];

  return (
    <div className="min-h-screen bg-slate-50 flex text-slate-900 selection:bg-indigo-100 selection:text-indigo-900">
      {/* Mobile Sidebar Overlay */}
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-40 lg:hidden animate-in fade-in duration-300"
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      {/* Sidebar */}
      <aside className={`
        fixed inset-y-0 left-0 z-50 w-72 bg-white border-r border-slate-100 transform transition-all duration-500 ease-[cubic-bezier(0.2,0.8,0.2,1)] lg:relative lg:translate-x-0
        ${isSidebarOpen ? 'translate-x-0 shadow-2xl' : '-translate-x-full'}
      `}>
        <div className="h-full flex flex-col p-8">
          <div className="mb-12">
            <div className="flex items-center gap-4">
              <div className="w-12 h-12 bg-indigo-600 rounded-2xl flex items-center justify-center text-white shadow-xl shadow-indigo-200">
                <Zap className="w-6 h-6 fill-current" />
              </div>
              <div>
                <h1 className="text-xl font-black tracking-tighter text-slate-800">SheetSpend</h1>
                <p className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-500">MVR Tracker</p>
              </div>
            </div>
          </div>

          <nav className="flex-1 space-y-2">
            {navItems.map((item) => (
              <button
                key={item.id}
                onClick={() => {
                  setView(item.id as ViewType);
                  setIsSidebarOpen(false);
                }}
                className={`
                  w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-sm font-bold transition-all group
                  ${view === item.id 
                    ? 'bg-indigo-50 text-indigo-600 shadow-sm' 
                    : 'text-slate-400 hover:bg-slate-50 hover:text-slate-800'}
                `}
              >
                <item.icon className={`w-5 h-5 transition-transform duration-300 ${view === item.id ? 'scale-110' : 'group-hover:scale-110'}`} />
                {item.label}
              </button>
            ))}
          </nav>

          <div className="mt-auto pt-8">
            <div className="bg-slate-900 rounded-3xl p-6 shadow-2xl overflow-hidden relative group">
              <div className="absolute -top-4 -right-4 w-20 h-20 bg-indigo-500 rounded-full blur-2xl opacity-20 group-hover:opacity-40 transition-opacity"></div>
              <p className="text-[10px] font-black text-slate-500 mb-2 uppercase tracking-[0.1em]">Local Ledger</p>
              <div className="flex items-center justify-between">
                <span className="text-lg font-black text-white">{transactions.length}</span>
                <span className="text-[10px] font-bold text-slate-400">Entries</span>
              </div>
              <div className="mt-4 flex items-center gap-2">
                <div className={`w-2 h-2 rounded-full animate-pulse ${error ? 'bg-rose-500' : 'bg-emerald-500'}`} />
                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{error ? 'Sync Error' : 'Live Sync'}</span>
              </div>
            </div>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col min-w-0 h-screen overflow-hidden">
        {/* Header */}
        <header className="sticky top-0 z-30 bg-white/70 backdrop-blur-xl border-b border-slate-100 px-8 py-6 flex items-center justify-between">
          <div className="flex items-center gap-6">
            <button 
              className="lg:hidden p-2 text-slate-500 hover:bg-slate-100 rounded-xl transition-colors"
              onClick={() => setIsSidebarOpen(true)}
            >
              <Menu className="w-6 h-6" />
            </button>
            <div>
              <h2 className="text-xl font-black text-slate-800 tracking-tight">
                {view === 'dashboard' ? 'Dashboard' : view === 'transactions' ? 'History' : 'System Connection'}
              </h2>
              <p className="text-xs font-bold text-slate-400">Maldivian Rufiyaa Tracker</p>
            </div>
          </div>

          <div className="flex items-center gap-6">
            <div className="hidden md:flex items-center bg-slate-100 rounded-2xl px-5 py-3 gap-3 text-slate-400 focus-within:text-indigo-600 focus-within:bg-white focus-within:ring-4 focus-within:ring-indigo-100 transition-all">
