import React, { useMemo } from 'react';
import { Transaction, DailyTotal } from '../types';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer,
  Cell,
  PieChart,
  Pie
} from 'recharts';
import { Landmark, TrendingUp } from 'lucide-react';
import StatCard from './StatCard';

interface DashboardProps {
  transactions: Transaction[];
}

const Dashboard: React.FC<DashboardProps> = ({ transactions }) => {
  // Helper to get local date string YYYY-MM-DD from any date input
  const getLocalDatePart = (dateInput: string | Date) => {
    try {
      const d = new Date(dateInput);
      if (isNaN(d.getTime())) return typeof dateInput === 'string' ? dateInput.split('T')[0] : '';
      return d.toLocaleDateString('en-CA'); // en-CA gives YYYY-MM-DD
    } catch (e) {
      return '';
    }
  };

  const stats = useMemo(() => {
    const total = transactions.reduce((acc, curr) => acc + curr.amount, 0);

    // Current local calendar day
    const todayStr = new Date().toLocaleDateString('en-CA');

    // Calculate Today's Total using local timezone-aware date parsing
    const todayTotal = transactions
      .filter(t => {
        if (!t.date) return false;
        return getLocalDatePart(t.date) === todayStr;
      })
      .reduce((acc, curr) => acc + curr.amount, 0);

    const dailyMap = transactions.reduce((acc: Record<string, number>, curr) => {
      const dateKey = getLocalDatePart(curr.date);
      if (dateKey) {
        acc[dateKey] = (acc[dateKey] || 0) + curr.amount;
      }
      return acc;
    }, {} as Record<string, number>);

    const dailyData: DailyTotal[] = Object.entries(dailyMap)
      .map(([date, total]) => ({ date, total: total as number }))
      .sort((a, b) => a.date.localeCompare(b.date))
      .slice(-14);

    return { total, todayTotal, dailyData };
  }, [transactions]);

  const COLORS = ['#6366f1', '#8b5cf6', '#ec4899', '#f43f5e', '#f97316'];

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-2 gap-4 lg:gap-6">
        <StatCard 
          label="Grand Total" 
          value={`${stats.total.toLocaleString(undefined, { minimumFractionDigits: 2 })} MVR`} 
          icon={<Landmark className="w-5 h-5 lg:w-6 lg:h-6 text-emerald-600" />}
          color="bg-emerald-50"
        />
        <StatCard 
          label="Today's Total" 
          value={`${stats.todayTotal.toLocaleString(undefined, { minimumFractionDigits: 2 })} Rf`} 
          icon={<TrendingUp className="w-5 h-5 lg:w-6 lg:h-6 text-indigo-600" />}
          color="bg-indigo-50"
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 bg-white p-8 rounded-3xl shadow-sm border border-slate-100">
          <div className="flex items-center justify-between mb-8">
            <h3 className="text-xl font-bold text-slate-800">Spending Trends (MVR)</h3>
            <div className="text-xs font-medium text-slate-400">Past 14 entries</div>
          </div>
          <div className="h-80 w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={stats.dailyData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis 
                  dataKey="date" 
                  axisLine={false} 
                  tickLine={false} 
                  tick={{ fontSize: 11, fill: '#94a3b8' }} 
                  dy={10}
                />
                <YAxis 
                  axisLine={false} 
                  tickLine={false} 
                  tick={{ fontSize: 11, fill: '#94a3b8' }}
                />
                <Tooltip 
                  cursor={{ fill: '#f8fafc' }}
                  formatter={(value) => [`${value} MVR`, 'Total']}
                  contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 20px 25px -5px rgba(0,0,0,0.1)' }}
                />
                <Bar dataKey="total" radius={[6, 6, 0, 0]} barSize={32}>
                  {stats.dailyData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100 flex flex-col h-full min-h-[450px]">
          <h3 className="text-xl font-bold text-slate-800 mb-2">Recent Allocation</h3>
          <div className="flex-1 relative w-full flex items-center justify-center overflow-hidden">
            {transactions.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%" minHeight={200}>
                <PieChart>
                  <Pie
                    data={transactions.slice(-5)}
                    dataKey="amount"
                    nameKey="name"
                    cx="50%"
                    cy="50%"
                    innerRadius="55%"
                    outerRadius="80%"
                    paddingAngle={8}
                  >
                    {transactions.slice(-5).map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} strokeWidth={0} />
                    ))}
                  </Pie>
                  <Tooltip 
                    formatter={(value) => [`${value} MVR`]}
                    contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 20px 25px -5px rgba(0,0,0,0.1)' }}
                  />
                </PieChart>
              </ResponsiveContainer>
            ) : (
              <div className="text-slate-400 text-sm">Waiting for data...</div>
            )}
          </div>
          <div className="mt-4 space-y-2.5 w-full">
            <h4 className="text-[10px] font-black text-slate-300 uppercase tracking-widest mb-2 border-b border-slate-50 pb-2">Last 3 Activities</h4>
            {transactions.slice(-3).reverse().map((t, idx) => (
              <div key={idx} className="flex items-center justify-between group">
