import React, { useState, useEffect, useCallback } from 'react';
import { Transaction, ViewType } from './types';
import { GoogleSheetsService } from './services/googleSheets';
import TransactionForm from './components/TransactionForm';
import Dashboard from './components/Dashboard';
import TransactionList from './components/TransactionList';
import Settings from './components/Settings';
import { 
  LayoutDashboard, 
  Receipt, 
  Settings as SettingsIcon, 
  RefreshCw,
  AlertCircle,
  Menu,
  Zap
} from 'lucide-react';

const App: React.FC = () => {
  const [view, setView] = useState<ViewType>('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  const fetchData = useCallback(async () => {
    const url = GoogleSheetsService.getScriptUrl();
    if (!url) {
      setError('Connection not established. Please configure the Script URL.');
      return;
    }

    setIsLoading(true);
    setError(null);
    try {
      const data = await GoogleSheetsService.fetchTransactions();
      setTransactions(data);
    } catch (err: any) {
      setError(err.message || 'Could not fetch data. Check your permissions.');
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  const handleAddTransaction = async (newTransaction: Transaction) => {
    setIsSyncing(true);
    try {
      await GoogleSheetsService.addTransaction(newTransaction);
      // Optimistic local update
      setTransactions(prev => [...prev, newTransaction]);
      // Gentle delayed re-fetch to ensure remote sync is complete
      setTimeout(() => fetchData(), 3000); 
    } catch (err) {
      setError('Cloud sync failed, entry saved locally.');
    } finally {
      setIsSyncing(false);
    }
  };

  const navItems = [
    { id: 'dashboard', label: 'Dashboard', icon: LayoutDashboard },
    { id: 'transactions', label: 'History', icon: Receipt },
    { id: 'settings', label: 'Connection', icon: SettingsIcon },
  ];

  return (
    <div className="min-h-screen bg-slate-50 flex text-slate-900 selection:bg-indigo-100 selection:text-indigo-900">
      {/* Mobile Sidebar Overlay */}
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-40 lg:hidden animate-in fade-in duration-300"
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      {/* Sidebar */}
      <aside className={`
        fixed inset-y-0 left-0 z-50 w-72 bg-white border-r border-slate-100 transform transition-all duration-500 ease-[cubic-bezier(0.2,0.8,0.2,1)] lg:relative lg:translate-x-0
        ${isSidebarOpen ? 'translate-x-0 shadow-2xl' : '-translate-x-full'}
      `}>
        <div className="h-full flex flex-col p-8">
          <div className="mb-12">
            <div className="flex items-center gap-4">
              <div className="w-12 h-12 bg-indigo-600 rounded-2xl flex items-center justify-center text-white shadow-xl shadow-indigo-200">
                <Zap className="w-6 h-6 fill-current" />
              </div>
              <div>
                <h1 className="text-xl font-black tracking-tighter text-slate-800">SheetSpend</h1>
                <p className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-500">MVR Tracker</p>
              </div>
            </div>
          </div>

          <nav className="flex-1 space-y-2">
            {navItems.map((item) => (
              <button
                key={item.id}
                onClick={() => {
                  setView(item.id as ViewType);
                  setIsSidebarOpen(false);
                }}
                className={`
                  w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-sm font-bold transition-all group
                  ${view === item.id 
                    ? 'bg-indigo-50 text-indigo-600 shadow-sm' 
                    : 'text-slate-400 hover:bg-slate-50 hover:text-slate-800'}
                `}
              >
                <item.icon className={`w-5 h-5 transition-transform duration-300 ${view === item.id ? 'scale-110' : 'group-hover:scale-110'}`} />
                {item.label}
              </button>
            ))}
          </nav>

          {/* Simplified Sync Status at Sidebar Bottom */}
          <div className="mt-auto pt-8">
            <div className="flex items-center gap-3 px-5 py-4 bg-slate-50 rounded-2xl border border-slate-100">
              <div className={`w-2 h-2 rounded-full ${error ? 'bg-rose-500 shadow-[0_0_8px_rgba(244,63,94,0.4)]' : 'bg-emerald-500 shadow-[0_0_8px_rgba(16,185,129,0.4)]'} ${!error && (isLoading || isSyncing) ? 'animate-pulse' : ''}`} />
              <div className="flex flex-col">
                <span className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">
                  {error ? 'Disconnected' : (isLoading || isSyncing) ? 'Syncing...' : 'System Online'}
                </span>
              </div>
            </div>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col min-w-0 h-screen overflow-hidden">
        {/* Header */}
        <header className="sticky top-0 z-30 bg-white/70 backdrop-blur-xl border-b border-slate-100 px-8 py-6 flex items-center justify-between">
          <div className="flex items-center gap-6">
            <button 
              className="lg:hidden p-2 text-slate-500 hover:bg-slate-100 rounded-xl transition-colors"
              onClick={() => setIsSidebarOpen(true)}
            >
              <Menu className="w-6 h-6" />
            </button>
            <div>
              <h2 className="text-xl font-black text-slate-800 tracking-tight">
                {view === 'dashboard' ? 'Dashboard' : view === 'transactions' ? 'History' : 'System Connection'}
              </h2>
              <p className="text-xs font-bold text-slate-400">Maldivian Rufiyaa Tracker</p>
            </div>
          </div>

          <div className="flex items-center gap-4">
            <button 
              onClick={fetchData}
              disabled={isLoading}
              className="p-3 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-2xl transition-all disabled:opacity-50 border border-slate-100 flex items-center gap-2 group"
            >
              <RefreshCw className={`w-4 h-4 ${isLoading ? 'animate-spin text-indigo-600' : 'group-hover:rotate-180 transition-transform duration-500'}`} />
              <span className="text-xs font-bold hidden sm:inline px-1">Refresh</span>
            </button>
          </div>
        </header>

        <div className="flex-1 p-8 lg:p-12 overflow-y-auto custom-scrollbar">
          <div className="max-w-7xl mx-auto space-y-10 pb-12">
            {error && (
              <div className="bg-rose-50 border border-rose-100 p-5 rounded-3xl flex items-center gap-4 text-rose-800 text-sm shadow-sm animate-in slide-in-from-top-4 duration-500">
                <div className="p-2 bg-rose-100 rounded-xl">
                    <AlertCircle className="w-5 h-5 flex-shrink-0" />
                </div>
                <div className="flex-1">
                  <p className="font-bold">Sync Issue Detected</p>
                  <p className="text-rose-600/80 font-medium">{error}</p>
                </div>
                {view !== 'settings' && (
                  <button 
                    onClick={() => setView('settings')}
                    className="bg-white border border-rose-200 px-4 py-2 rounded-xl text-xs font-black shadow-sm hover:bg-rose-100 transition-colors"
                  >
                    Fix Connection
                  </button>
                )}
              </div>
            )}

            {view === 'dashboard' && (
              <div className="grid grid-cols-1 xl:grid-cols-12 gap-10">
                <div className="xl:col-span-4">
                  <TransactionForm onSuccess={handleAddTransaction} isLoading={isSyncing} />
                </div>
                <div className="xl:col-span-8">
                  <Dashboard transactions={transactions} />
                </div>
              </div>
            )}

            {view === 'transactions' && (
              <div className="space-y-6">
                <TransactionList transactions={transactions} />
              </div>
            )}

            {view === 'settings' && (
              <Settings onSave={fetchData} />
            )}
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

import React from 'react';
import { Transaction } from '../types';
import { Table, Calendar, Tag, ChevronRight, Landmark, Download, FileText } from 'lucide-react';

interface TransactionListProps {
  transactions: Transaction[];
}

const TransactionList: React.FC<TransactionListProps> = ({ transactions }) => {
  // Helper to get local date string YYYY-MM-DD from any date input
  const getLocalDatePart = (dateInput: string) => {
    try {
      const d = new Date(dateInput);
      if (isNaN(d.getTime())) return dateInput.split('T')[0];
      return d.toLocaleDateString('en-CA'); // en-CA gives YYYY-MM-DD
    } catch (e) {
      return dateInput;
    }
  };

  const handleExportCSV = () => {
    if (transactions.length === 0) return;

    // CSV Headers
    const headers = ['Date', 'Description', 'Amount (MVR)'];

    // Format data rows
    const rows = transactions.slice().reverse().map(t => [
      getLocalDatePart(t.date),
      `"${t.name.replace(/"/g, '""')}"`, // Escape quotes in description
      t.amount.toFixed(2)
    ]);

    // Combine into CSV string
    const csvContent = [
      headers.join(','),
      ...rows.map(row => row.join(','))
    ].join('\n');

    // Create download link
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');

    const timestamp = new Date().toISOString().split('T')[0];
    link.setAttribute('href', url);
    link.setAttribute('download', `Transaction_Report_${timestamp}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden animate-in fade-in slide-in-from-bottom-8 duration-700">
      <div className="p-8 border-b border-slate-50 flex flex-col sm:flex-row sm:items-center justify-between gap-6 bg-white">
        <div>
          <h3 className="text-xl font-extrabold text-slate-800 flex items-center gap-3">
            <div className="p-2 bg-violet-50 rounded-xl">
              <Table className="w-5 h-5 text-violet-600" />
            </div>
            History
          </h3>
          <p className="text-sm text-slate-400 mt-1">Detailed log of your Maldivian Rufiyaa transactions</p>
        </div>

        <div className="flex items-center gap-3">
          <button
            onClick={handleExportCSV}
            disabled={transactions.length === 0}
            className="flex items-center gap-2 px-5 py-3 bg-slate-900 hover:bg-indigo-600 disabled:bg-slate-200 text-white rounded-2xl text-xs font-black transition-all shadow-lg shadow-slate-200 hover:shadow-indigo-100 active:scale-95"
          >
            <Download className="w-4 h-4" />
            Export CSV
          </button>
          <span className="text-xs font-black text-indigo-600 bg-indigo-50 px-4 py-3 rounded-2xl border border-indigo-100 uppercase tracking-tighter hidden sm:block">
            {transactions.length} Entries
          </span>
        </div>
      </div>

      <div className="overflow-x-auto">
        <table className="w-full text-left">
