import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { Transaction, ViewType } from './types';
import { GoogleSheetsService } from './services/googleSheets';
import TransactionForm from './components/TransactionForm';
import Dashboard from './components/Dashboard';
import TransactionList from './components/TransactionList';
import Settings from './components/Settings';
import StatCard from './components/StatCard';
import { 
  LayoutDashboard, 
  Receipt, 
  Settings as SettingsIcon, 
  RefreshCw,
  AlertCircle,
  Menu,
  Zap,
  Wallet,
  ArrowRightCircle
} from 'lucide-react';

const App: React.FC = () => {
  const [view, setView] = useState<ViewType>('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [expenses, setExpenses] = useState<Transaction[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  const fetchData = useCallback(async () => {
    setIsLoading(true);
    setError(null);
    try {
      // Fetch both sheets in parallel
      const [transData, expData] = await Promise.all([
        GoogleSheetsService.fetchTransactions('Transcations'),
        GoogleSheetsService.fetchTransactions('Expenses')
      ]);
      setTransactions(transData);
      setExpenses(expData);
    } catch (err: any) {
      setError(err.message || 'Could not fetch data. Check your permissions.');
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  const handleAddData = async (newRecord: Transaction, sheet: 'Transcations' | 'Expenses') => {
    setIsSyncing(true);
    try {
      await GoogleSheetsService.addTransaction(newRecord, sheet);
      // Optimistic local update
      if (sheet === 'Transcations') {
        setTransactions(prev => [...prev, newRecord]);
      } else {
        setExpenses(prev => [...prev, newRecord]);
      }
      // Gentle delayed re-fetch
      setTimeout(() => fetchData(), 2000); 
    } catch (err) {
      setError('Cloud sync failed.');
    } finally {
      setIsSyncing(false);
    }
  };

  const navItems = [
    { id: 'dashboard', label: 'Dashboard', icon: LayoutDashboard },
    { id: 'transactions', label: 'History', icon: Receipt },
    { id: 'expenses', label: 'Expenses', icon: Wallet },
    { id: 'settings', label: 'Connection', icon: SettingsIcon },
  ];

  const expenseStats = useMemo(() => {
    const total = expenses.reduce((acc, curr) => acc + curr.amount, 0);
    const todayStr = new Date().toLocaleDateString('en-CA');
    const todayTotal = expenses
      .filter(t => t.date && t.date === todayStr)
      .reduce((acc, curr) => acc + curr.amount, 0);
    return { total, todayTotal };
  }, [expenses]);

  return (
    <div className="min-h-screen bg-slate-50 flex text-slate-900 selection:bg-indigo-100 selection:text-indigo-900">
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-40 lg:hidden animate-in fade-in duration-300"
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      <aside className={`
        fixed inset-y-0 left-0 z-50 w-72 bg-white border-r border-slate-100 transform transition-all duration-500 ease-[cubic-bezier(0.2,0.8,0.2,1)] lg:relative lg:translate-x-0
        ${isSidebarOpen ? 'translate-x-0 shadow-2xl' : '-translate-x-full'}
      `}>
        <div className="h-full flex flex-col p-8">
          <div className="mb-12">
            <div className="flex items-center gap-4">
              <div className="w-12 h-12 bg-indigo-600 rounded-2xl flex items-center justify-center text-white shadow-xl shadow-indigo-200">
                <Zap className="w-6 h-6 fill-current" />
              </div>
              <div>
                <h1 className="text-xl font-black tracking-tighter text-slate-800">Load Badhige</h1>
                <p className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-500">System</p>
              </div>
            </div>
          </div>

          <nav className="flex-1 space-y-2">
            {navItems.map((item) => (
              <button
                key={item.id}
                onClick={() => {
                  setView(item.id as ViewType);
                  setIsSidebarOpen(false);
                }}
                className={`
                  w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-sm font-bold transition-all group
                  ${view === item.id 
                    ? 'bg-indigo-50 text-indigo-600 shadow-sm' 
                    : 'text-slate-400 hover:bg-slate-50 hover:text-slate-800'}
                `}
              >
                <item.icon className={`w-5 h-5 transition-transform duration-300 ${view === item.id ? 'scale-110' : 'group-hover:scale-110'}`} />
                {item.label}
              </button>
            ))}
          </nav>

          <div className="mt-auto pt-8">
            <div className="flex items-center gap-3 px-5 py-4 bg-slate-50 rounded-2xl border border-slate-100">
              <div className={`w-2 h-2 rounded-full ${error ? 'bg-rose-500 shadow-[0_0_8px_rgba(244,63,94,0.4)]' : 'bg-emerald-500 shadow-[0_0_8px_rgba(16,185,129,0.4)]'} ${!error && (isLoading || isSyncing) ? 'animate-pulse' : ''}`} />
              <div className="flex flex-col">
                <span className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">
                  {error ? 'Sync Error' : (isLoading || isSyncing) ? 'Syncing...' : 'Cloud Active'}
                </span>
              </div>
            </div>
          </div>
        </div>
      </aside>

      <main className="flex-1 flex flex-col min-w-0 h-screen overflow-hidden">
        <header className="sticky top-0 z-30 bg-white/70 backdrop-blur-xl border-b border-slate-100 px-8 py-6 flex items-center justify-between">
          <div className="flex items-center gap-6">
            <button className="lg:hidden p-2 text-slate-500 hover:bg-slate-100 rounded-xl transition-colors" onClick={() => setIsSidebarOpen(true)}>
              <Menu className="w-6 h-6" />
            </button>
            <div>
              <h2 className="text-xl font-black text-slate-800 tracking-tight capitalize">{view}</h2>
              <p className="text-xs font-bold text-slate-400">Load Badhige Tracker</p>
            </div>
          </div>
          <button onClick={fetchData} disabled={isLoading} className="p-3 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-2xl transition-all border border-slate-100 flex items-center gap-2 group">
            <RefreshCw className={`w-4 h-4 ${isLoading ? 'animate-spin text-indigo-600' : 'group-hover:rotate-180 transition-transform duration-500'}`} />
            <span className="text-xs font-bold hidden sm:inline px-1">Sync</span>
          </button>
        </header>

        <div className="flex-1 p-8 lg:p-12 overflow-y-auto custom-scrollbar">
          <div className="max-w-7xl mx-auto space-y-10 pb-12">
            {error && (
              <div className="bg-rose-50 border border-rose-100 p-5 rounded-3xl flex items-center gap-4 text-rose-800 text-sm shadow-sm animate-in slide-in-from-top-4">
                <AlertCircle className="w-5 h-5 flex-shrink-0 text-rose-500" />
                <div className="flex-1 font-bold">{error}</div>
              </div>
            )}

            {view === 'dashboard' && (
              <div className="grid grid-cols-1 xl:grid-cols-12 gap-10">
                <div className="xl:col-span-4">
                  <TransactionForm 
                    onSuccess={(t) => handleAddData(t, 'Transcations')} 
                    isLoading={isSyncing} 
                    title="Quick Log"
                    placeholder="Transfer Details..."
                  />
                </div>
                <div className="xl:col-span-8">
                  <Dashboard transactions={transactions} />
                </div>
              </div>
            )}

            {view === 'transactions' && (
              <TransactionList transactions={transactions} title="Transaction History" />
            )}

            {view === 'expenses' && (
              <div className="space-y-10">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <StatCard 
                    label="Total Expenses" 
                    value={`${expenseStats.total.toLocaleString(undefined, { minimumFractionDigits: 2 })} MVR`} 
                    icon={<Wallet className="w-6 h-6 text-rose-600" />}
                    color="bg-rose-50"
                  />
                  <StatCard 
                    label="Today's Spend" 
                    value={`${expenseStats.todayTotal.toLocaleString(undefined, { minimumFractionDigits: 2 })} MVR`} 
                    icon={<ArrowRightCircle className="w-6 h-6 text-orange-600" />}
                    color="bg-orange-50"
                  />
                </div>
                <div className="grid grid-cols-1 xl:grid-cols-12 gap-10">
                  <div className="xl:col-span-4">
                    <TransactionForm 
                      onSuccess={(t) => handleAddData(t, 'Expenses')} 
                      isLoading={isSyncing} 
                      title="Add Expense"
                      placeholder="Expense details..."
                      icon={<Wallet className="w-5 h-5 text-rose-600" />}
                    />
                  </div>
                  <div className="xl:col-span-8">
                    <TransactionList 
                      transactions={expenses} 
                      title="Expense Log" 
                      description="Records stored in the Expenses sheet"
                    />
                  </div>
                </div>
              </div>
            )}

            {view === 'settings' && <Settings onSave={fetchData} />}
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

