### Important: Update your Google Apps Script
To make the "Expenses" tab work, you must replace your existing Google Script code with the one below. This version automatically creates the "Expenses" sheet if it doesn't exist and handles the data switching:

```javascript
function doGet(e) {
  const sheetName = (e && e.parameter && e.parameter.sheet) ? e.parameter.sheet : "Transcations";
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  let ws = ss.getSheetByName(sheetName);

  // Create sheet if it doesn't exist
  if (!ws) {
    ws = ss.insertSheet(sheetName);
    ws.appendRow(["Date", "Amount", "Name"]); // Default headers
  }

  const data = ws.getDataRange().getValues();
  const headers = data.shift(); // Remove header row

  const json = data.map(row => ({
    date: row[0] instanceof Date ? row[0].toISOString().split('T')[0] : row[0],
    amount: row[1],
    name: row[2]
  }));

  return ContentService.createTextOutput(JSON.stringify(json))
    .setMimeType(ContentService.MimeType.JSON);
}

function doPost(e) {
  const params = JSON.parse(e.postData.contents);
  const sheetName = params.sheet || "Transcations";
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  let ws = ss.getSheetByName(sheetName);

  if (!ws) {
    ws = ss.insertSheet(sheetName);
    ws.appendRow(["Date", "Amount", "Name"]);
  }

  ws.appendRow([
    params.date,
    params.amount,
    params.name
  ]);

  return ContentService.createTextOutput("Success")
    .setMimeType(ContentService.MimeType.TEXT);
}

