} from 'lucide-react';

const App: React.FC = () => {
  const [view, setView] = useState<ViewType>('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]); // This is Sales
  const [expenses, setExpenses] = useState<Transaction[]>([]);         // This is Expenses
  const [isLoading, setIsLoading] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  const fetchData = useCallback(async () => {
    setIsLoading(true);
    setError(null);
    try {
      // Parallel fetch from different sheets
      const [salesData, expenseData] = await Promise.all([
        GoogleSheetsService.fetchTransactions('Transcations'),
        GoogleSheetsService.fetchTransactions('Expenses')
      ]);
      setTransactions(salesData);
      setExpenses(expenseData);
    } catch (err: any) {
      setError(err.message || 'Could not fetch data. Check your permissions.');
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  const handleAddData = async (newRecord: Transaction, sheet: 'Transcations' | 'Expenses') => {
    setIsSyncing(true);
    try {
      await GoogleSheetsService.addTransaction(newRecord, sheet);
      // Optimistic local update to the correct list
      if (sheet === 'Transcations') {
        setTransactions(prev => [...prev, newRecord]);
      } else {
        setExpenses(prev => [...prev, newRecord]);
      }
      // Re-fetch to ensure sync after a short delay
      setTimeout(() => fetchData(), 2000); 
    } catch (err) {
      setError('Cloud sync failed.');
    } finally {
      setIsSyncing(false);
    }
