                  <TransactionForm 
                    onSuccess={(t) => handleAddData(t, 'Transcations')} 
                    isLoading={isSyncing} 
                    title="Record Sale"
                    placeholder="Sale Description..."
                    icon={<TrendingUp className="w-5 h-5 text-indigo-600" />}
                  />
                </div>
                <div className="xl:col-span-8">
                  <Dashboard transactions={transactions} />
                </div>
