            )}

            {view === 'transactions' && (
              <TransactionList 
                transactions={transactions} 
                title="Sales History" 
                description="All records from the primary sales sheet"
              />
            )}

            {view === 'expenses' && (
              <div className="space-y-10">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <StatCard 
