### ⚠️ IMPORTANT: Update Your Google Apps Script
To prevent the Expense Log from showing Sales data, **you must replace your current Apps Script code** with this one. This version listens for the `sheet` parameter we are sending from the app.

```javascript
function doGet(e) {
  // Use the 'sheet' parameter from the URL, otherwise default to "Transcations"
  const sheetName = (e && e.parameter && e.parameter.sheet) ? e.parameter.sheet : "Transcations";
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  let ws = ss.getSheetByName(sheetName);

  // Auto-create the sheet with headers if it doesn't exist
  if (!ws) {
    ws = ss.insertSheet(sheetName);
    ws.appendRow(["Date", "Amount", "Name"]);
  }

  const data = ws.getDataRange().getValues();
  const headers = data.shift(); // Remove headers

  const json = data.map(row => ({
    date: row[0] instanceof Date ? row[0].toISOString().split('T')[0] : row[0],
    amount: row[1],
    name: row[2]
  }));

  return ContentService.createTextOutput(JSON.stringify(json))
    .setMimeType(ContentService.MimeType.JSON);
}

function doPost(e) {
  const params = JSON.parse(e.postData.contents);
  // Use the 'sheet' property from the JSON body
  const sheetName = params.sheet || "Transcations";
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  let ws = ss.getSheetByName(sheetName);

  if (!ws) {
    ws = ss.insertSheet(sheetName);
    ws.appendRow(["Date", "Amount", "Name"]);
  }

  ws.appendRow([
    params.date,
    params.amount,
    params.name
  ]);

  return ContentService.createTextOutput("Success")
    .setMimeType(ContentService.MimeType.TEXT);
}

