import React, { useMemo } from 'react';
import { Transaction, DailyTotal } from '../types';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer,
  Cell
} from 'recharts';
import { Landmark, TrendingUp } from 'lucide-react';
import StatCard from './StatCard';

interface DashboardProps {
  transactions: Transaction[];
}

const Dashboard: React.FC<DashboardProps> = ({ transactions }) => {
  /**
   * Extract only the YYYY-MM-DD part. 
   * If it's already a string, we split it. If it's a Date, we convert carefully.
   */
  const getLocalDatePart = (dateInput: string | Date) => {
    if (!dateInput) return '';
    if (typeof dateInput === 'string') {
      return dateInput.split('T')[0];
    }
    // For actual Date objects, use a method that returns local YYYY-MM-DD
    const d = new Date(dateInput);
    const year = d.getFullYear();
    const month = String(d.getMonth() + 1).padStart(2, '0');
    const day = String(d.getDate()).padStart(2, '0');
    return `${year}-${month}-${day}`;
  };

  const stats = useMemo(() => {
    const total = transactions.reduce((acc, curr) => acc + curr.amount, 0);

    // Get today's date in local YYYY-MM-DD format
    const now = new Date();
    const todayStr = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}`;

    const todayTotal = transactions
      .filter(t => t.date && getLocalDatePart(t.date) === todayStr)
      .reduce((acc, curr) => acc + curr.amount, 0);

    const dailyMap = transactions.reduce((acc: Record<string, number>, curr) => {
      const dateKey = getLocalDatePart(curr.date);
      if (dateKey) {
        acc[dateKey] = (acc[dateKey] || 0) + curr.amount;
      }
      return acc;
    }, {} as Record<string, number>);

    const dailyData: DailyTotal[] = Object.entries(dailyMap)
      .map(([date, total]) => ({ date, total: total as number }))
      .sort((a, b) => a.date.localeCompare(b.date))
      .slice(-14);

    return { total, todayTotal, dailyData };
  }, [transactions]);

  const COLORS = ['#6366f1', '#8b5cf6', '#ec4899', '#f43f5e', '#f97316'];

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <StatCard 
          label="Total Sales" 
          value={`${stats.total.toLocaleString(undefined, { minimumFractionDigits: 2 })} MVR`} 
          icon={<Landmark className="w-5 h-5 lg:w-6 lg:h-6 text-emerald-600" />}
          color="bg-emerald-50"
        />
        <StatCard 
          label="Today's Sales" 
          value={`${stats.todayTotal.toLocaleString(undefined, { minimumFractionDigits: 2 })} MVR`} 
          icon={<TrendingUp className="w-5 h-5 lg:w-6 lg:h-6 text-indigo-600" />}
          color="bg-indigo-50"
        />
      </div>

      <div className="w-full">
        <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100">
          <div className="flex items-center justify-between mb-8">
            <h3 className="text-xl font-bold text-slate-800 tracking-tight">Daily Sales Performance</h3>
            <div className="text-[10px] font-black uppercase tracking-widest text-slate-300">Last 14 days</div>
          </div>
          <div className="h-96 w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={stats.dailyData} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis 
                  dataKey="date" 
                  axisLine={false} 
                  tickLine={false} 
                  tick={{ fontSize: 10, fill: '#94a3b8', fontWeight: 600 }} 
                  dy={10}
                />
                <YAxis 
                  axisLine={false} 
                  tickLine={false} 
                  tick={{ fontSize: 10, fill: '#94a3b8', fontWeight: 600 }}
                />
                <Tooltip 
                  cursor={{ fill: '#f8fafc' }}
                  formatter={(value) => [`${Number(value).toFixed(2)} MVR`, 'Total Sales']}
                  contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 20px 25px -5px rgba(0,0,0,0.1)', padding: '12px' }}
                />
                <Bar dataKey="total" radius={[6, 6, 0, 0]} barSize={32}>
                  {stats.dailyData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { Transaction, ViewType } from './types';
import { GoogleSheetsService } from './services/googleSheets';
import TransactionForm from './components/TransactionForm';
import Dashboard from './components/Dashboard';
import TransactionList from './components/TransactionList';
import Settings from './components/Settings';
import StatCard from './components/StatCard';
import { 
  LayoutDashboard, 
  Receipt, 
  Settings as SettingsIcon, 
  RefreshCw,
  AlertCircle,
  Menu,
  Zap,
  Wallet,
  ArrowRightCircle,
  TrendingUp
} from 'lucide-react';

const App: React.FC = () => {
  const [view, setView] = useState<ViewType>('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]); 
  const [expenses, setExpenses] = useState<Transaction[]>([]);         
  const [isLoading, setIsLoading] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  const fetchData = useCallback(async () => {
    setIsLoading(true);
    setError(null);
    try {
      const [salesData, expenseData] = await Promise.all([
        GoogleSheetsService.fetchTransactions('Transcations'),
        GoogleSheetsService.fetchTransactions('Expenses')
      ]);
      setTransactions(salesData);
      setExpenses(expenseData);
    } catch (err: any) {
      setError(err.message || 'Could not fetch data. Check your permissions.');
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  const handleAddData = async (newRecord: Transaction, sheet: 'Transcations' | 'Expenses') => {
    setIsSyncing(true);
    try {
      await GoogleSheetsService.addTransaction(newRecord, sheet);
      if (sheet === 'Transcations') {
        setTransactions(prev => [...prev, newRecord]);
      } else {
        setExpenses(prev => [...prev, newRecord]);
      }
      setTimeout(() => fetchData(), 2500); 
    } catch (err) {
      setError('Sync failed. Please check connection.');
    } finally {
      setIsSyncing(false);
    }
  };

  const navItems = [
    { id: 'dashboard', label: 'Sales Dashboard', icon: LayoutDashboard },
    { id: 'transactions', label: 'Sales Log', icon: Receipt },
    { id: 'expenses', label: 'Expense Log', icon: Wallet },
    { id: 'settings', label: 'Connection', icon: SettingsIcon },
  ];

  const expenseStats = useMemo(() => {
    // Generate today's local string without using toLocaleDateString('en-CA')
    // which can sometimes behave differently across browsers.
    const now = new Date();
    const todayStr = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}`;

    const total = expenses.reduce((acc, curr) => acc + (Number(curr.amount) || 0), 0);

    const todayTotal = expenses
      .filter(t => {
        // Compare the stored date string (YYYY-MM-DD) with our local todayStr
        const transactionDate = t.date ? t.date.split('T')[0] : '';
        return transactionDate === todayStr;
      })
      .reduce((acc, curr) => acc + (Number(curr.amount) || 0), 0);

    return { total, todayTotal };
  }, [expenses]);

  return (
    <div className="min-h-screen bg-slate-50 flex text-slate-900 selection:bg-indigo-100 selection:text-indigo-900">
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-40 lg:hidden animate-in fade-in duration-300"
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      <aside className={`
        fixed inset-y-0 left-0 z-50 w-72 bg-white border-r border-slate-100 transform transition-all duration-500 ease-[cubic-bezier(0.2,0.8,0.2,1)] lg:relative lg:translate-x-0
        ${isSidebarOpen ? 'translate-x-0 shadow-2xl' : '-translate-x-full'}
      `}>
        <div className="h-full flex flex-col p-8">
          <div className="mb-12">
            <div className="flex items-center gap-4">
              <div className="w-12 h-12 bg-indigo-600 rounded-2xl flex items-center justify-center text-white shadow-xl shadow-indigo-200">
                <Zap className="w-6 h-6 fill-current" />
              </div>
              <div>
                <h1 className="text-xl font-black tracking-tighter text-slate-800">Load Badhige</h1>
                <p className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-500">Business Manager</p>
              </div>
            </div>
          </div>

          <nav className="flex-1 space-y-2">
            {navItems.map((item) => (
              <button
                key={item.id}
                onClick={() => {
                  setView(item.id as ViewType);
                  setIsSidebarOpen(false);
                }}
                className={`
                  w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-sm font-bold transition-all group
                  ${view === item.id 
                    ? 'bg-indigo-50 text-indigo-600 shadow-sm' 
                    : 'text-slate-400 hover:bg-slate-50 hover:text-slate-800'}
                `}
