import React, { useState } from 'react';
import { Transaction } from '../types';
import { PlusCircle, Loader2, Sparkles, Calendar as CalendarIcon, Tag } from 'lucide-react';

interface TransactionFormProps {
  onSuccess: (transaction: Transaction) => void;
  isLoading: boolean;
  title?: string;
  placeholder?: string;
  icon?: React.ReactNode;
}

const TransactionForm: React.FC<TransactionFormProps> = ({ 
  onSuccess, 
  isLoading, 
  title = "New Entry", 
  placeholder = "Details...",
  icon = <PlusCircle className="w-5 h-5 text-indigo-600" />
}) => {
  // Reliable local YYYY-MM-DD builder
  const getLocalDateString = () => {
    const now = new Date();
    const year = now.getFullYear();
    const month = String(now.getMonth() + 1).padStart(2, '0');
    const day = String(now.getDate()).padStart(2, '0');
    return `${year}-${month}-${day}`;
  };

  const [formData, setFormData] = useState<Transaction>({
    date: getLocalDateString(),
    amount: 0,
    name: '',
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (formData.amount <= 0 || !formData.name) return;
    onSuccess(formData);
    setFormData({
      date: getLocalDateString(),
      amount: 0,
      name: '',
    });
  };

  return (
    <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100 h-full relative overflow-hidden group">
      <div className="absolute top-0 right-0 p-4 opacity-5 group-hover:opacity-10 transition-opacity">
        <Sparkles className="w-24 h-24 text-indigo-600" />
      </div>

      <h3 className="text-xl font-extrabold text-slate-800 mb-8 flex items-center gap-3">
        <div className="p-2.5 bg-indigo-50 rounded-xl">
          {icon}
        </div>
        {title}
      </h3>

      <form onSubmit={handleSubmit} className="space-y-6">
        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1 flex items-center gap-2">
            <CalendarIcon className="w-3 h-3" />
            Date
          </label>
          <input
            type="date"
            required
            className="w-full px-5 py-4 bg-slate-50 border border-slate-100 rounded-2xl focus:outline-none focus:ring-4 focus:ring-indigo-500/10 focus:bg-white focus:border-indigo-500 transition-all text-sm font-bold cursor-pointer"
            value={formData.date}
            onChange={(e) => setFormData({ ...formData, date: e.target.value })}
          />
        </div>

        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1 flex items-center gap-2">
            <Tag className="w-3 h-3" />
            Description
          </label>
          <input
            type="text"
            required
            placeholder={placeholder}
            className="w-full px-5 py-4 bg-slate-50 border border-slate-100 rounded-2xl focus:outline-none focus:ring-4 focus:ring-indigo-500/10 focus:bg-white focus:border-indigo-500 transition-all text-sm font-bold"
            value={formData.name}
            onChange={(e) => setFormData({ ...formData, name: e.target.value })}
          />
        </div>

        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Amount (MVR)</label>
          <div className="relative">
            <span className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-400 font-black text-xs">MVR</span>
            <input
              type="number"
              step="0.01"
              required
              placeholder="0.00"
              className="w-full pl-16 pr-5 py-4 bg-slate-50 border border-slate-100 rounded-2xl focus:outline-none focus:ring-4 focus:ring-indigo-500/10 focus:bg-white focus:border-indigo-500 transition-all text-base font-black"
              value={formData.amount || ''}
              onChange={(e) => setFormData({ ...formData, amount: parseFloat(e.target.value) || 0 })}
            />
          </div>
        </div>

        <button
          type="submit"
          disabled={isLoading}
          className="w-full bg-slate-900 hover:bg-indigo-600 disabled:bg-slate-200 text-white font-black py-4 rounded-2xl shadow-xl shadow-slate-100 hover:shadow-indigo-100 transition-all flex items-center justify-center gap-3 active:scale-[0.98]"
        >
          {isLoading ? (
            <Loader2 className="w-5 h-5 animate-spin" />
          ) : (
            <>
              <PlusCircle className="w-5 h-5" />
              Sync Record
            </>
          )}
