import React, { useMemo } from 'react';
import { Transaction, DailyTotal } from '../types';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer,
  Cell
} from 'recharts';
import { Landmark, TrendingUp } from 'lucide-react';
import StatCard from './StatCard';

interface DashboardProps {
  transactions: Transaction[];
}

const Dashboard: React.FC<DashboardProps> = ({ transactions }) => {
  /**
   * Direct string extraction for YYYY-MM-DD.
   * Does NOT use new Date() to avoid timezone offsets.
   */
  const getLocalDatePart = (dateInput: string) => {
    if (!dateInput) return '';
    return dateInput.split('T')[0];
  };

  const stats = useMemo(() => {
    const total = transactions.reduce((acc, curr) => acc + curr.amount, 0);

    // Get local today in YYYY-MM-DD
    const now = new Date();
    const todayStr = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}`;

    const todayTotal = transactions
      .filter(t => t.date && getLocalDatePart(t.date) === todayStr)
      .reduce((acc, curr) => acc + curr.amount, 0);

    const dailyMap = transactions.reduce((acc: Record<string, number>, curr) => {
      const dateKey = getLocalDatePart(curr.date);
      if (dateKey) {
        acc[dateKey] = (acc[dateKey] || 0) + curr.amount;
      }
      return acc;
    }, {} as Record<string, number>);

    const dailyData: DailyTotal[] = Object.entries(dailyMap)
      .map(([date, total]) => ({ date, total: total as number }))
      .sort((a, b) => a.date.localeCompare(b.date))
      .slice(-14);

    return { total, todayTotal, dailyData };
  }, [transactions]);

  const COLORS = ['#6366f1', '#8b5cf6', '#ec4899', '#f43f5e', '#f97316'];

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <StatCard 
          label="Total Sales" 
          value={`${stats.total.toLocaleString(undefined, { minimumFractionDigits: 2 })} MVR`} 
          icon={<Landmark className="w-5 h-5 lg:w-6 lg:h-6 text-emerald-600" />}
          color="bg-emerald-50"
        />
        <StatCard 
          label="Today's Sales" 
          value={`${stats.todayTotal.toLocaleString(undefined, { minimumFractionDigits: 2 })} MVR`} 
          icon={<TrendingUp className="w-5 h-5 lg:w-6 lg:h-6 text-indigo-600" />}
          color="bg-indigo-50"
        />
      </div>

      <div className="w-full">
        <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100">
          <div className="flex items-center justify-between mb-8">
            <h3 className="text-xl font-bold text-slate-800 tracking-tight">Daily Sales Performance</h3>
            <div className="text-[10px] font-black uppercase tracking-widest text-slate-300">Last 14 days</div>
          </div>
          <div className="h-96 w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={stats.dailyData} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis 
                  dataKey="date" 
                  axisLine={false} 
                  tickLine={false} 
                  tick={{ fontSize: 10, fill: '#94a3b8', fontWeight: 600 }} 
                  dy={10}
                />
                <YAxis 
                  axisLine={false} 
                  tickLine={false} 
                  tick={{ fontSize: 10, fill: '#94a3b8', fontWeight: 600 }}
                />
                <Tooltip 
                  cursor={{ fill: '#f8fafc' }}
                  formatter={(value) => [`${Number(value).toFixed(2)} MVR`, 'Total Sales']}
                  contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 20px 25px -5px rgba(0,0,0,0.1)', padding: '12px' }}
                />
                <Bar dataKey="total" radius={[6, 6, 0, 0]} barSize={32}>
                  {stats.dailyData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

