interface TransactionListProps {
  transactions: Transaction[];
  title?: string;
  description?: string;
  nameLabel?: string;
  showCategory?: boolean;
}

const MONTHS = ['JAN', 'FEB', 'MAR', 'APR', 'MAY', 'JUN', 'JUL', 'AUG', 'SEP', 'OCT', 'NOV', 'DEC'];

const TransactionList: React.FC<TransactionListProps> = ({ 
  transactions, 
  title = "History", 
  description = "Detailed log of your records",
  nameLabel = "Description",
  showCategory = false
}) => {
  /**
   * Robust date display in DD-MMM-YY format (e.g., 05-JAN-26).
   */
  const formatDisplayDate = (dateInput: string) => {
    if (!dateInput) return 'N/A';

    // Remove the ' quote if it exists
    const cleanStr = dateInput.startsWith("'") ? dateInput.slice(1) : dateInput;

    let year: number, monthIdx: number, day: string;

    if (cleanStr.includes('T')) {
      const d = new Date(cleanStr);
      if (!isNaN(d.getTime())) {
        year = d.getFullYear();
        monthIdx = d.getMonth();
        day = String(d.getDate()).padStart(2, '0');
      } else {
        return cleanStr;
      }
    } else {
      const parts = cleanStr.split('-');
      if (parts.length === 3) {
        year = parseInt(parts[0]);
        monthIdx = parseInt(parts[1]) - 1;
        day = parts[2].padStart(2, '0');
      } else {
        return cleanStr;
      }
    }

    // Format as DD-MMM-YY
    const monthName = MONTHS[monthIdx] || '???';
    const shortYear = year.toString().slice(-2);
    return `${day}-${monthName}-${shortYear}`;
  };

  const handleExportCSV = () => {
    if (transactions.length === 0) return;
    const headers = ['Date', ...(showCategory ? ['Category'] : []), nameLabel, 'Amount (MVR)'];
    const rows = transactions.slice().reverse().map(t => [
      formatDisplayDate(t.date),
      ...(showCategory ? [t.category || 'N/A'] : []),
      `"${t.name.replace(/"/g, '""')}"`,
      t.amount.toFixed(2)
    ]);
    const csvContent = [headers.join(','), ...rows.map(row => row.join(','))].join('\n');
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');

    const now = new Date();
    const todayFormatted = `${String(now.getDate()).padStart(2, '0')}-${MONTHS[now.getMonth()]}-${now.getFullYear().toString().slice(-2)}`;

    link.setAttribute('href', url);
    link.setAttribute('download', `${title.replace(/\s+/g, '_')}_${todayFormatted}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden animate-in fade-in slide-in-from-bottom-8 duration-700">
      <div className="p-8 border-b border-slate-50 flex flex-col sm:flex-row sm:items-center justify-between gap-6 bg-white">
        <div>
          <h3 className="text-xl font-extrabold text-slate-800 flex items-center gap-3">
            <div className="p-2 bg-violet-50 rounded-xl">
              <Table className="w-5 h-5 text-violet-600" />
            </div>
            {title}
          </h3>
          <p className="text-sm text-slate-400 mt-1">{description}</p>
        </div>

        <div className="flex items-center gap-3">
          <button
            onClick={handleExportCSV}
            disabled={transactions.length === 0}
            className="flex items-center gap-2 px-5 py-3 bg-slate-900 hover:bg-indigo-600 disabled:bg-slate-200 text-white rounded-2xl text-xs font-black transition-all shadow-lg shadow-slate-200 hover:shadow-indigo-100 active:scale-95"
          >
            <Download className="w-4 h-4" />
            Export CSV
          </button>
          <span className="text-xs font-black text-indigo-600 bg-indigo-50 px-4 py-3 rounded-2xl border border-indigo-100 uppercase tracking-tighter hidden sm:block">
            {transactions.length} Entries
          </span>
        </div>
      </div>

      <div className="overflow-x-auto">
        <table className="w-full text-left">
          <thead className="bg-slate-50/30">
            <tr>
              <th className="px-8 py-5 text-xs font-bold text-slate-400 uppercase tracking-widest">Date</th>
              {showCategory && <th className="px-8 py-5 text-xs font-bold text-slate-400 uppercase tracking-widest">Category</th>}
              <th className="px-8 py-5 text-xs font-bold text-slate-400 uppercase tracking-widest">{nameLabel}</th>
              <th className="px-8 py-5 text-xs font-bold text-slate-400 uppercase tracking-widest text-right">Amount</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {transactions.slice().reverse().map((t, i) => (
              <tr key={i} className="group hover:bg-slate-50/50 transition-all cursor-default">
                <td className="px-8 py-5 whitespace-nowrap">
                  <div className="flex items-center gap-3 text-sm font-medium text-slate-500">
                    <Calendar className="w-4 h-4 text-slate-300 group-hover:text-indigo-400 transition-colors" />
                    {formatDisplayDate(t.date)}
                  </div>
                </td>
                {showCategory && (
                  <td className="px-8 py-5 whitespace-nowrap">
                    <span className="inline-flex items-center gap-1.5 px-3 py-1.5 rounded-xl bg-slate-100 text-slate-600 text-[10px] font-black uppercase tracking-tighter">
                      <Layers className="w-3 h-3" />
                      {t.category || 'Uncategorized'}
                    </span>
                  </td>
                )}
                <td className="px-8 py-5">
                  <div className="flex items-center gap-3">
                    <div className="p-2 bg-slate-50 rounded-lg group-hover:bg-white transition-colors">
                      <Tag className="w-4 h-4 text-slate-400" />
                    </div>
                    <span className="text-sm font-bold text-slate-700">{t.name}</span>
                  </div>
                </td>
                <td className="px-8 py-5 text-right">
                  <div className="flex items-center justify-end gap-2">
                    <span className="text-xs font-bold text-slate-300">MVR</span>
                    <span className="text-base font-black text-slate-900">
                      {t.amount.toLocaleString(undefined, { minimumFractionDigits: 2 })}
                    </span>
                    <ChevronRight className="w-4 h-4 text-slate-200 opacity-0 group-hover:opacity-100 transition-all -translate-x-2 group-hover:translate-x-0" />
                  </div>
                </td>
              </tr>
            ))}
            {transactions.length === 0 && (
              <tr>
                <td colSpan={showCategory ? 4 : 3} className="px-8 py-20 text-center">
                  <div className="flex flex-col items-center gap-2">
                    <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mb-2">
                      <Landmark className="w-8 h-8 text-slate-200" />
                    </div>
                    <p className="text-slate-400 font-bold">No records found.</p>
                  </div>
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

