                    icon={<ArrowRightCircle className="w-6 h-6 text-orange-600" />}
                    color="bg-orange-50"
                  />
                </div>
                <div className="grid grid-cols-1 xl:grid-cols-12 gap-10">
                  <div className="xl:col-span-4">
                    <TransactionForm 
                      onSuccess={(t) => handleAddData(t, 'Expenses')} 
                      isLoading={isSyncing} 
                      title="Log New Expense"
                      placeholder="Expense description..."
                      icon={<Wallet className="w-5 h-5 text-rose-600" />}
                      options={dynamicExpenseCategories}
                    />
                  </div>
                  <div className="xl:col-span-8">
                    <TransactionList 
                      transactions={expenses} 
                      title="Full Expense History" 
                      description="Dedicated list of spending recorded in the Expenses sheet"
                      showCategory={true}
                    />
                  </div>
                </div>
              </div>
            )}

            {view === 'settings' && <Settings onSave={fetchData} />}
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

payload.text:
To implement the deletion feature, we need to update the application to track row identifiers and communicate deletion requests to your Google Apps Script. 

### Specification

1.  **Row Identification**: Modified the data fetching logic to assign a `rowId` to every transaction based on its position in the Google Sheet. This allows us to target specific rows for deletion.
2.  **Deletion Logic**:
    *   Added a `deleteTransaction` method to the `GoogleSheetsService`.
    *   Updated the `App` component with a `handleDeleteData` function that optimistically removes the record from the UI and then syncs with the cloud.
3.  **UI Enhancements**:
    *   Updated `TransactionList` to include a "Trash" icon button for each row.
    *   Added a confirmation state to prevent accidental deletions.
    *   The delete button is styled to be subtle but accessible, appearing more prominently on row hover.

### Action Required: Update your Google Apps Script
For the delete button to work, you must update your Google Apps Script with this version which supports the `delete` action:

```javascript
function doGet(e) {
  const sheetName = e.parameter.sheet || "Transcations";
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const ws = ss.getSheetByName(sheetName);
  if (!ws) return ContentService.createTextOutput("[]").setMimeType(ContentService.MimeType.JSON);
  const data = ws.getDataRange().getValues();
  const headers = data.shift();

  const json = data.map((row, index) => ({
    rowId: index + 2, // Row 1 is header, so data starts at Row 2
    date: row[0] instanceof Date ? row[0].toISOString().split('T')[0] : row[0],
    amount: row[1],
    name: row[2],
    category: row[3] || ""
  }));

  return ContentService.createTextOutput(JSON.stringify(json))
    .setMimeType(ContentService.MimeType.JSON);
}

function doPost(e) {
  const params = JSON.parse(e.postData.contents);
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const ws = ss.getSheetByName(params.sheet || "Transcations");

  if (params.action === 'delete') {
    ws.deleteRow(params.rowId);
    return ContentService.createTextOutput("Deleted").setMimeType(ContentService.MimeType.TEXT);
  }

  ws.appendRow([
    params.date,
    params.amount,
    params.name,
    params.category || "" 
  ]);

  return ContentService.createTextOutput("Success").setMimeType(ContentService.MimeType.TEXT);
}
```

