export type ViewType = 'dashboard' | 'transactions' | 'expenses' | 'settings';

import { Transaction } from '../types';

export class GoogleSheetsService {
  private static FIXED_URL = 'https://script.google.com/macros/s/AKfycbxlXpwPcjoxl7RadfoY7ZSa_duPA3b3atJK5-JsWApsP-fhy2VirXWKCWO9FyPXIEUNCw/exec';

  static getScriptUrl(): string {
    return this.FIXED_URL;
  }

  static setScriptUrl(url: string): void {}

  /**
   * Fetches data from a specific sheet via GET request.
   */
  static async fetchTransactions(sheetName: string = 'Transcations'): Promise<Transaction[]> {
    const url = `${this.getScriptUrl()}?sheet=${encodeURIComponent(sheetName)}`;

    try {
      const response = await fetch(url, {
        method: 'GET',
        mode: 'cors',
        cache: 'no-cache',
        redirect: 'follow',
      });

      if (!response.ok) throw new Error(`Server responded with ${response.status}`);

      const data = await response.json();
      return data.map((item: any) => ({
        ...item,
        amount: typeof item.amount === 'string' ? parseFloat(item.amount.replace(/[^0-9.-]+/g,"")) : item.amount,
        // Exclusively use the category from the sheet, no fallback to 'name' (description)
        category: item.category || (sheetName === 'Category' ? (item.date || item.name) : undefined)
      }));
    } catch (error) {
      console.error(`Error fetching from ${sheetName}:`, error);
      throw new Error(`Failed to connect to ${sheetName}. Ensure your Script is updated.`);
    }
  }

  /**
   * Sends a new record to a specific sheet via POST request.
   */
  static async addTransaction(transaction: Transaction, sheetName: string = 'Transcations'): Promise<void> {
    const url = this.getScriptUrl();

    try {
      const payload = {
        sheet: sheetName,
        date: `'${transaction.date}`, 
        amount: Number(transaction.amount), 
        name: transaction.name,
        category: transaction.category || ''
      };

      await fetch(url, {
        method: 'POST',
        mode: 'no-cors',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(payload),
      });
    } catch (error) {
      console.error(`Error adding to ${sheetName}:`, error);
      throw error;
    }
  }

  /**
   * Deletes a record from a specific sheet by rowId.
   */
  static async deleteTransaction(rowId: number, sheetName: string): Promise<void> {
    const url = this.getScriptUrl();

    try {
      const payload = {
        sheet: sheetName,
        action: 'delete',
        rowId: rowId
      };

      await fetch(url, {
        method: 'POST',
        mode: 'no-cors',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(payload),
      });
    } catch (error) {
      console.error(`Error deleting from ${sheetName}:`, error);
      throw error;
    }
  }
}

import React, { useState } from 'react';
import { Transaction } from '../types';
import { Table, Calendar, Tag, ChevronRight, Landmark, Download, Layers, Trash2, AlertTriangle, Loader2 } from 'lucide-react';

interface TransactionListProps {
  transactions: Transaction[];
  title?: string;
  description?: string;
  nameLabel?: string;
  showCategory?: boolean;
  onDelete?: (transaction: Transaction) => Promise<void>;
}

const MONTHS = ['JAN', 'FEB', 'MAR', 'APR', 'MAY', 'JUN', 'JUL', 'AUG', 'SEP', 'OCT', 'NOV', 'DEC'];

const TransactionList: React.FC<TransactionListProps> = ({ 
  transactions, 
  title = "History", 
  description = "Detailed log of your records",
  nameLabel = "Description",
  showCategory = false,
  onDelete
}) => {
  const [deletingId, setDeletingId] = useState<number | null>(null);
  const [confirmDeleteId, setConfirmDeleteId] = useState<number | null>(null);

  const formatDisplayDate = (dateInput: string) => {
    if (!dateInput) return 'N/A';
    const cleanStr = dateInput.startsWith("'") ? dateInput.slice(1) : dateInput;
    let year: number, monthIdx: number, day: string;

    if (cleanStr.includes('T')) {
      const d = new Date(cleanStr);
      if (!isNaN(d.getTime())) {
        year = d.getFullYear();
        monthIdx = d.getMonth();
        day = String(d.getDate()).padStart(2, '0');
      } else {
        return cleanStr;
      }
    } else {
      const parts = cleanStr.split('-');
      if (parts.length === 3) {
        year = parseInt(parts[0]);
        monthIdx = parseInt(parts[1]) - 1;
        day = parts[2].padStart(2, '0');
      } else {
        return cleanStr;
      }
    }
    const monthName = MONTHS[monthIdx] || '???';
    const shortYear = year.toString().slice(-2);
    return `${day}-${monthName}-${shortYear}`;
  };

  const handleDeleteClick = async (t: Transaction) => {
    if (!t.rowId || !onDelete) return;

    if (confirmDeleteId !== t.rowId) {
      setConfirmDeleteId(t.rowId);
      return;
    }

    try {
      setDeletingId(t.rowId);
      await onDelete(t);
    } finally {
      setDeletingId(null);
      setConfirmDeleteId(null);
    }
  };

  const handleExportCSV = () => {
    if (transactions.length === 0) return;
    const headers = ['Date', ...(showCategory ? ['Category'] : []), nameLabel, 'Amount (MVR)'];
    const rows = transactions.slice().reverse().map(t => [
      formatDisplayDate(t.date),
      ...(showCategory ? [t.category || 'N/A'] : []),
      `"${t.name.replace(/"/g, '""')}"`,
      t.amount.toFixed(2)
    ]);
    const csvContent = [headers.join(','), ...rows.map(row => row.join(','))].join('\n');
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    const now = new Date();
    const todayFormatted = `${String(now.getDate()).padStart(2, '0')}-${MONTHS[now.getMonth()]}-${now.getFullYear().toString().slice(-2)}`;
    link.setAttribute('href', url);
    link.setAttribute('download', `${title.replace(/\s+/g, '_')}_${todayFormatted}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden animate-in fade-in slide-in-from-bottom-8 duration-700">
      <div className="p-8 border-b border-slate-50 flex flex-col sm:flex-row sm:items-center justify-between gap-6 bg-white">
        <div>
          <h3 className="text-xl font-extrabold text-slate-800 flex items-center gap-3">
            <div className="p-2 bg-violet-50 rounded-xl">
              <Table className="w-5 h-5 text-violet-600" />
            </div>
            {title}
          </h3>
          <p className="text-sm text-slate-400 mt-1">{description}</p>
        </div>

        <div className="flex items-center gap-3">
          <button
            onClick={handleExportCSV}
            disabled={transactions.length === 0}
            className="flex items-center gap-2 px-5 py-3 bg-slate-900 hover:bg-indigo-600 disabled:bg-slate-200 text-white rounded-2xl text-xs font-black transition-all shadow-lg shadow-slate-200 hover:shadow-indigo-100 active:scale-95"
          >
            <Download className="w-4 h-4" />
            Export CSV
          </button>
          <span className="text-xs font-black text-indigo-600 bg-indigo-50 px-4 py-3 rounded-2xl border border-indigo-100 uppercase tracking-tighter hidden sm:block">
            {transactions.length} Entries
          </span>
        </div>
      </div>

      <div className="overflow-x-auto">
        <table className="w-full text-left">
          <thead className="bg-slate-50/30">
            <tr>
              <th className="px-8 py-5 text-xs font-bold text-slate-400 uppercase tracking-widest">Date</th>
              {showCategory && <th className="px-8 py-5 text-xs font-bold text-slate-400 uppercase tracking-widest">Category</th>}
              <th className="px-8 py-5 text-xs font-bold text-slate-400 uppercase tracking-widest">{nameLabel}</th>
              <th className="px-8 py-5 text-xs font-bold text-slate-400 uppercase tracking-widest text-right">Amount</th>
              {onDelete && <th className="px-8 py-5 text-xs font-bold text-slate-400 uppercase tracking-widest text-right w-10">Actions</th>}
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {transactions.slice().reverse().map((t, i) => (
              <tr key={t.rowId || i} className="group hover:bg-slate-50/50 transition-all cursor-default">
                <td className="px-8 py-5 whitespace-nowrap">
                  <div className="flex items-center gap-3 text-sm font-medium text-slate-500">
                    <Calendar className="w-4 h-4 text-slate-300 group-hover:text-indigo-400 transition-colors" />
                    {formatDisplayDate(t.date)}
                  </div>
                </td>
                {showCategory && (
                  <td className="px-8 py-5 whitespace-nowrap">
                    <span className="inline-flex items-center gap-1.5 px-3 py-1.5 rounded-xl bg-slate-100 text-slate-600 text-[10px] font-black uppercase tracking-tighter">
                      <Layers className="w-3 h-3" />
                      {t.category || 'Uncategorized'}
                    </span>
                  </td>
                )}
                <td className="px-8 py-5">
                  <div className="flex items-center gap-3">
                    <div className="p-2 bg-slate-50 rounded-lg group-hover:bg-white transition-colors">
                      <Tag className="w-4 h-4 text-slate-400" />
                    </div>
                    <span className="text-sm font-bold text-slate-700">{t.name}</span>
                  </div>
                </td>
                <td className="px-8 py-5 text-right">
                  <div className="flex items-center justify-end gap-2">
                    <span className="text-xs font-bold text-slate-300">MVR</span>
                    <span className="text-base font-black text-slate-900">
                      {t.amount.toLocaleString(undefined, { minimumFractionDigits: 2 })}
                    </span>
                    {!onDelete && <ChevronRight className="w-4 h-4 text-slate-200 opacity-0 group-hover:opacity-100 transition-all -translate-x-2 group-hover:translate-x-0" />}
                  </div>
                </td>
                {onDelete && (
                  <td className="px-8 py-5 text-right">
                    <div className="flex items-center justify-end">
                      <button
                        onClick={() => handleDeleteClick(t)}
                        disabled={deletingId === t.rowId}
                        className={`
                          p-2 rounded-xl transition-all flex items-center gap-2 group/btn
                          ${confirmDeleteId === t.rowId 
                            ? 'bg-rose-100 text-rose-600 px-3' 
                            : 'hover:bg-rose-50 text-slate-300 hover:text-rose-500'}
                        `}
                        title={confirmDeleteId === t.rowId ? "Click again to confirm" : "Delete transaction"}
                      >
                        {deletingId === t.rowId ? (
                          <Loader2 className="w-4 h-4 animate-spin" />
                        ) : confirmDeleteId === t.rowId ? (
                          <>
                            <AlertTriangle className="w-4 h-4" />
                            <span className="text-[10px] font-black uppercase">Confirm?</span>
                          </>
                        ) : (
                          <Trash2 className="w-4 h-4" />
                        )}
                      </button>
                    </div>
                  </td>
                )}
              </tr>
            ))}
            {transactions.length === 0 && (
              <tr>
                <td colSpan={showCategory ? 5 : 4} className="px-8 py-20 text-center">
                  <div className="flex flex-col items-center gap-2">
                    <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mb-2">
                      <Landmark className="w-8 h-8 text-slate-200" />
                    </div>
                    <p className="text-slate-400 font-bold">No records found.</p>
                  </div>
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default TransactionList;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { Transaction, ViewType } from './types';
import { GoogleSheetsService } from './services/googleSheets';
import TransactionForm from './components/TransactionForm';
import Dashboard from './components/Dashboard';
import TransactionList from './components/TransactionList';
import Settings from './components/Settings';
import StatCard from './components/StatCard';
import { 
  LayoutDashboard, 
  Receipt, 
  Settings as SettingsIcon, 
  RefreshCw,
  AlertCircle,
  Menu,
  Zap,
  Wallet,
  ArrowRightCircle,
  TrendingUp
} from 'lucide-react';

const App: React.FC = () => {
  const [view, setView] = useState<ViewType>('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]); 
  const [expenses, setExpenses] = useState<Transaction[]>([]);         
  const [fetchedCategories, setFetchedCategories] = useState<string[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  const fetchData = useCallback(async () => {
    setIsLoading(true);
    setError(null);
    try {
      // Fetch from Sales, Expenses, and the dedicated Category sheet
      const [salesData, expenseData, categoryData] = await Promise.all([
        GoogleSheetsService.fetchTransactions('Transcations'),
        GoogleSheetsService.fetchTransactions('Expenses'),
        GoogleSheetsService.fetchTransactions('Category').catch(() => []) 
      ]);

      setTransactions(salesData);
      setExpenses(expenseData);

      // Extract categories exclusively from the Category sheet data
      const categoriesFromSheet = categoryData
        .map(c => (c.category || c.date || c.name || '').toString().trim()) 
        .filter(c => 
          c !== '' && 
          !['DATE', 'NAME', 'CATEGORY', 'AMOUNT'].includes(c.toUpperCase())
        );

      setFetchedCategories(categoriesFromSheet);
    } catch (err: any) {
      setError(err.message || 'Could not fetch data. Check your permissions.');
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  const handleAddData = async (newRecord: Transaction, sheet: 'Transcations' | 'Expenses') => {
    setIsSyncing(true);
    try {
      await GoogleSheetsService.addTransaction(newRecord, sheet);
      if (sheet === 'Transcations') {
        setTransactions(prev => [...prev, newRecord]);
      } else {
        setExpenses(prev => [...prev, newRecord]);
      }
      setTimeout(() => fetchData(), 2500); 
    } catch (err) {
      setError('Sync failed. Please check connection and Script version.');
    } finally {
      setIsSyncing(false);
    }
  };

  const handleDeleteData = async (transaction: Transaction, sheet: 'Transcations' | 'Expenses') => {
    if (!transaction.rowId) return;

    try {
      await GoogleSheetsService.deleteTransaction(transaction.rowId, sheet);
      // Optimistically update local state
      if (sheet === 'Transcations') {
        setTransactions(prev => prev.filter(t => t.rowId !== transaction.rowId));
      } else {
        setExpenses(prev => prev.filter(e => e.rowId !== transaction.rowId));
      }
      // Re-fetch to ensure row IDs are recalculated correctly for future operations
      fetchData();
    } catch (err) {
      setError('Delete failed. Please ensure your Script supports deletions.');
    }
  };

  const navItems = [
    { id: 'dashboard', label: 'Sales Dashboard', icon: LayoutDashboard },
    { id: 'transactions', label: 'Sales Log', icon: Receipt },
    { id: 'expenses', label: 'Expense Log', icon: Wallet },
    { id: 'settings', label: 'Connection', icon: SettingsIcon },
  ];

  const expenseStats = useMemo(() => {
    const now = new Date();
    const todayStr = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}`;

    const total = expenses.reduce((acc, curr) => acc + (Number(curr.amount) || 0), 0);

    const todayTotal = expenses
      .filter(t => {
        if (!t.date) return false;
        const cleanStr = t.date.startsWith("'") ? t.date.slice(1) : t.date;
        let transDate = cleanStr.split('T')[0];
        if (cleanStr.includes('T')) {
          const d = new Date(cleanStr);
          if (!isNaN(d.getTime())) {
            transDate = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
          }
        }
        return transDate === todayStr;
      })
      .reduce((acc, curr) => acc + (Number(curr.amount) || 0), 0);

    return { total, todayTotal };
  }, [expenses]);

  const dynamicExpenseCategories = useMemo(() => {
    const uniqueCategories = Array.from(new Set(fetchedCategories));
    return uniqueCategories.length > 0 
      ? uniqueCategories.sort((a, b) => a.localeCompare(b))
      : ['General']; 
  }, [fetchedCategories]);

  return (
    <div className="min-h-screen bg-slate-50 flex text-slate-900 selection:bg-indigo-100 selection:text-indigo-900">
      {isSidebarOpen && (
        <div 
