The reason your deletions are not reflecting in the Google Sheet is most likely a mismatch between the app's request and the Google Apps Script's `doPost` function. In Google Apps Script, when you use `no-cors` mode, the request is sent but the response is "opaque" (hidden), and the server-side code must be specifically written to parse the raw body regardless of headers.

**Crucially, you must re-deploy your Google Apps Script as a "New Version" for changes to take effect.**

### Step 1: Update your Google Apps Script
Copy and replace your entire script in the Google Sheet Script Editor with this version. It includes robust error handling, row number conversion, and logging.

```javascript
/**
 * GOOGLE APPS SCRIPT
 * Replace your current script with this code.
 * Then click: Deploy -> Manage Deploys -> Edit (pencil) -> Version: "New Version" -> Deploy.
 */

function doGet(e) {
  const sheetName = e.parameter.sheet || "Transcations";
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const ws = ss.getSheetByName(sheetName);

  if (!ws) {
    return ContentService.createTextOutput(JSON.stringify([])).setMimeType(ContentService.MimeType.JSON);
  }

  const data = ws.getDataRange().getValues();
  if (data.length <= 1) {
    return ContentService.createTextOutput(JSON.stringify([])).setMimeType(ContentService.MimeType.JSON);
  }

  const headers = data.shift(); // Remove header row

  const json = data.map((row, index) => ({
    rowId: index + 2, // Header is Row 1, so first data row is 2
    date: row[0] instanceof Date ? row[0].toISOString().split('T')[0] : (row[0] ? row[0].toString() : ""),
    amount: row[1] || 0,
    name: row[2] || "",
    category: row[3] || ""
  }));

  return ContentService.createTextOutput(JSON.stringify(json))
    .setMimeType(ContentService.MimeType.JSON);
}

function doPost(e) {
  const lock = LockService.getScriptLock();
  lock.waitLock(30000); // Prevent concurrent write errors

  try {
    const params = JSON.parse(e.postData.contents);
    const ss = SpreadsheetApp.getActiveSpreadsheet();
    const ws = ss.getSheetByName(params.sheet || "Transcations");

    if (!ws) throw new Error("Sheet not found: " + params.sheet);

    // HANDLE DELETION
    if (params.action === 'delete') {
      const rowNum = parseInt(params.rowId);
      if (!isNaN(rowNum) && rowNum > 1) {
        ws.deleteRow(rowNum);
        return ContentService.createTextOutput("Deleted Row " + rowNum).setMimeType(ContentService.MimeType.TEXT);
      } else {
        throw new Error("Invalid Row ID for deletion: " + params.rowId);
      }
    }

    // HANDLE ADDITION (Default)
    ws.appendRow([
      params.date,
      params.amount,
      params.name,
      params.category || "" 
    ]);

    return ContentService.createTextOutput("Success").setMimeType(ContentService.MimeType.TEXT);

  } catch (err) {
    return ContentService.createTextOutput("Error: " + err.message).setMimeType(ContentService.MimeType.TEXT);
  } finally {
    lock.releaseLock();
  }
}
```

### Step 2: Update App Files
I've updated the `GoogleSheetsService` to be more explicit about what it sends and added a console log so you can verify the `rowId` in your browser's inspect tool (F12).

