        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1 flex items-center gap-2">
            <AlignLeft className="w-3 h-3" />
            Description
          </label>
          <input
            type="text"
            required
            placeholder={placeholder}
            className="w-full px-5 py-4 bg-slate-50 border border-slate-100 rounded-2xl focus:outline-none focus:ring-4 focus:ring-indigo-500/10 focus:bg-white focus:border-indigo-500 transition-all text-sm font-bold"
            value={formData.name}
            onChange={(e) => setFormData({ ...formData, name: e.target.value })}
          />
        </div>

        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Amount (MVR)</label>
          <div className="relative">
            <span className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-400 font-black text-xs">MVR</span>
            <input
              type="number"
              step="0.01"
              required
              placeholder="0.00"
              className="w-full pl-16 pr-5 py-4 bg-slate-50 border border-slate-100 rounded-2xl focus:outline-none focus:ring-4 focus:ring-indigo-500/10 focus:bg-white focus:border-indigo-500 transition-all text-base font-black"
              value={formData.amount || ''}
              onChange={(e) => setFormData({ ...formData, amount: parseFloat(e.target.value) || 0 })}
            />
          </div>
        </div>

        <button
          type="submit"
          disabled={isLoading}
          className="w-full bg-slate-900 hover:bg-indigo-600 disabled:bg-slate-200 text-white font-black py-4 rounded-2xl shadow-xl shadow-slate-100 hover:shadow-indigo-100 transition-all flex items-center justify-center gap-3 active:scale-[0.98]"
        >
          {isLoading ? (
            <Loader2 className="w-5 h-5 animate-spin" />
          ) : (
            <>
              <PlusCircle className="w-5 h-5" />
              Sync Record
            </>
          )}
        </button>
      </form>
    </div>
  );
};

export default TransactionForm;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { Transaction, ViewType } from './types';
import { GoogleSheetsService } from './services/googleSheets';
import TransactionForm from './components/TransactionForm';
import Dashboard from './components/Dashboard';
import TransactionList from './components/TransactionList';
import Settings from './components/Settings';
import StatCard from './components/StatCard';
import { 
  LayoutDashboard, 
  Receipt, 
  Settings as SettingsIcon, 
  RefreshCw,
  AlertCircle,
  Menu,
  Zap,
  Wallet,
  ArrowRightCircle,
  TrendingUp
} from 'lucide-react';

const App: React.FC = () => {
  const [view, setView] = useState<ViewType>('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]); 
  const [expenses, setExpenses] = useState<Transaction[]>([]);         
  const [fetchedCategories, setFetchedCategories] = useState<string[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  const fetchData = useCallback(async () => {
    setIsLoading(true);
    setError(null);
    try {
      const [salesData, expenseData, categoryData] = await Promise.all([
        GoogleSheetsService.fetchTransactions('Transcations'),
        GoogleSheetsService.fetchTransactions('Expenses'),
        GoogleSheetsService.fetchTransactions('Category').catch(() => []) 
      ]);

      setTransactions(salesData);
      setExpenses(expenseData);

      const categoriesFromSheet = categoryData
        .map(c => (c.category || c.date || c.name || '').toString().trim()) 
        .filter(c => 
          c !== '' && 
          !['DATE', 'NAME', 'CATEGORY', 'AMOUNT'].includes(c.toUpperCase())
        );

      setFetchedCategories(categoriesFromSheet);
    } catch (err: any) {
      setError(err.message || 'Could not fetch data. Check your permissions.');
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  const handleAddData = async (newRecord: Transaction, sheet: 'Transcations' | 'Expenses') => {
    setIsSyncing(true);
    try {
      await GoogleSheetsService.addTransaction(newRecord, sheet);
      if (sheet === 'Transcations') {
        setTransactions(prev => [...prev, newRecord]);
      } else {
        setExpenses(prev => [...prev, newRecord]);
      }
      setTimeout(() => fetchData(), 2500); 
    } catch (err) {
      setError('Sync failed. Please check connection and Script version.');
    } finally {
      setIsSyncing(false);
    }
  };

  const handleDeleteData = async (transaction: Transaction, sheet: 'Transcations' | 'Expenses') => {
    if (transaction.rowId === undefined || transaction.rowId === null) {
      setError('Cannot delete: This record is missing a cloud identifier.');
      return;
    }

    try {
      if (sheet === 'Transcations') {
        setTransactions(prev => prev.filter(t => t.rowId !== transaction.rowId));
      } else {
        setExpenses(prev => prev.filter(e => e.rowId !== transaction.rowId));
      }
      await GoogleSheetsService.deleteTransaction(transaction.rowId, sheet);
      setTimeout(() => { fetchData(); }, 3000);
    } catch (err) {
      console.error('Delete operation error:', err);
      setError('Delete request failed. Check your internet or Script version.');
      fetchData();
    }
  };

  const navItems = [
    { id: 'dashboard', label: 'Sales Dashboard', icon: LayoutDashboard },
    { id: 'transactions', label: 'Sales Log', icon: Receipt },
    { id: 'expenses', label: 'Expense Log', icon: Wallet },
    { id: 'settings', label: 'Connection', icon: SettingsIcon },
  ];

  const expenseStats = useMemo(() => {
    const now = new Date();
    const todayStr = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}`;
    const total = expenses.reduce((acc, curr) => acc + (Number(curr.amount) || 0), 0);
    const todayTotal = expenses
      .filter(t => {
        if (!t.date) return false;
        const cleanStr = t.date.startsWith("'") ? t.date.slice(1) : t.date;
        let transDate = cleanStr.split('T')[0];
        if (cleanStr.includes('T')) {
          const d = new Date(cleanStr);
          if (!isNaN(d.getTime())) {
            transDate = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
          }
        }
        return transDate === todayStr;
      })
      .reduce((acc, curr) => acc + (Number(curr.amount) || 0), 0);
    return { total, todayTotal };
  }, [expenses]);

  const dynamicExpenseCategories = useMemo(() => {
    const uniqueCategories = Array.from(new Set(fetchedCategories)) as string[];
    return uniqueCategories.length > 0 
      ? uniqueCategories.sort((a, b) => a.localeCompare(b))
      : ['General']; 
  }, [fetchedCategories]);

  return (
    <div className="min-h-screen bg-slate-950 flex text-slate-100 selection:bg-indigo-500/30 selection:text-indigo-200">
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black/60 backdrop-blur-md z-40 lg:hidden animate-in fade-in duration-300"
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      <aside className={`
        fixed inset-y-0 left-0 z-50 w-72 bg-slate-900 border-r border-slate-800 transform transition-all duration-500 ease-[cubic-bezier(0.2,0.8,0.2,1)] lg:relative lg:translate-x-0
        ${isSidebarOpen ? 'translate-x-0 shadow-2xl' : '-translate-x-full'}
      `}>
        <div className="h-full flex flex-col p-8">
          <div className="mb-12">
            <div className="flex items-center gap-4">
              <div className="w-12 h-12 bg-indigo-600 rounded-2xl flex items-center justify-center text-white shadow-xl shadow-indigo-900/20">
                <Zap className="w-6 h-6 fill-current" />
              </div>
              <div>
                <h1 className="text-xl font-black tracking-tighter text-slate-100">Load Badhige</h1>
                <p className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-400">Business Manager</p>
              </div>
            </div>
          </div>

          <nav className="flex-1 space-y-2">
            {navItems.map((item) => (
              <button
                key={item.id}
                onClick={() => {
                  setView(item.id as ViewType);
                  setIsSidebarOpen(false);
                }}
                className={`
                  w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-sm font-bold transition-all group
                  ${view === item.id 
                    ? 'bg-indigo-600/10 text-indigo-400 shadow-sm' 
                    : 'text-slate-500 hover:bg-slate-800 hover:text-slate-200'}
                `}
              >
                <item.icon className={`w-5 h-5 transition-transform duration-300 ${view === item.id ? 'scale-110' : 'group-hover:scale-110'}`} />
                {item.label}
              </button>
            ))}
          </nav>

          <div className="mt-auto pt-8">
            <div className="flex items-center gap-3 px-5 py-4 bg-slate-800/50 rounded-2xl border border-slate-800">
              <div className={`w-2 h-2 rounded-full ${error ? 'bg-rose-500 shadow-[0_0_8px_rgba(244,63,94,0.6)]' : 'bg-emerald-500 shadow-[0_0_8px_rgba(16,185,129,0.6)]'} ${!error && (isLoading || isSyncing) ? 'animate-pulse' : ''}`} />
              <div className="flex flex-col">
                <span className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em]">
                  {error ? 'Sync Error' : (isLoading || isSyncing) ? 'Syncing...' : 'Cloud Active'}
                </span>
              </div>
            </div>
          </div>
        </div>
      </aside>

      <main className="flex-1 flex flex-col min-w-0 h-screen overflow-hidden">
        <header className="sticky top-0 z-30 bg-slate-950/70 backdrop-blur-xl border-b border-slate-800 px-8 py-6 flex items-center justify-between">
          <div className="flex items-center gap-6">
            <button className="lg:hidden p-2 text-slate-400 hover:bg-slate-800 rounded-xl transition-colors" onClick={() => setIsSidebarOpen(true)}>
              <Menu className="w-6 h-6" />
            </button>
            <div>
              <h2 className="text-xl font-black text-slate-100 tracking-tight capitalize">
                {view === 'transactions' ? 'Sales Log' : view === 'dashboard' ? 'Sales Dashboard' : view === 'expenses' ? 'Expense Log' : view}
              </h2>
              <p className="text-xs font-bold text-slate-500">Finance & Analytics</p>
            </div>
          </div>
          <button onClick={fetchData} disabled={isLoading} className="p-3 text-slate-400 hover:text-indigo-400 hover:bg-indigo-600/10 rounded-2xl transition-all border border-slate-800 flex items-center gap-2 group">
            <RefreshCw className={`w-4 h-4 ${isLoading ? 'animate-spin text-indigo-400' : 'group-hover:rotate-180 transition-transform duration-500'}`} />
            <span className="text-xs font-bold hidden sm:inline px-1">Refresh Data</span>
          </button>
        </header>

        <div className="flex-1 p-8 lg:p-12 overflow-y-auto custom-scrollbar">
          <div className="max-w-7xl mx-auto space-y-10 pb-12">
            {error && (
              <div className="bg-rose-950/20 border border-rose-900/30 p-5 rounded-3xl flex items-center gap-4 text-rose-200 text-sm shadow-sm animate-in slide-in-from-top-4">
                <AlertCircle className="w-5 h-5 flex-shrink-0 text-rose-500" />
                <div className="flex-1 font-bold">{error}</div>
              </div>
            )}

            {view === 'dashboard' && (
              <div className="grid grid-cols-1 xl:grid-cols-12 gap-10">
                <div className="xl:col-span-4">
                  <TransactionForm 
                    onSuccess={(t) => handleAddData(t, 'Transcations')} 
                    isLoading={isSyncing} 
                    title="Quick Sales Entry"
                    placeholder="Transferred By..."
                    icon={<TrendingUp className="w-5 h-5 text-indigo-400" />}
                  />
                </div>
                <div className="xl:col-span-8">
                  <Dashboard transactions={transactions} expenses={expenses} />
                </div>
              </div>
            )}

            {view === 'transactions' && (
              <TransactionList 
                transactions={transactions} 
                title="Full Sales Log" 
                description="List of all sales recorded in the main transactions sheet"
                nameLabel="Transferred By"
                onDelete={(t) => handleDeleteData(t, 'Transcations')}
              />
            )}

            {view === 'expenses' && (
              <div className="space-y-10">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <StatCard 
                    label="Total Expenses" 
                    value={`${expenseStats.total.toLocaleString(undefined, { minimumFractionDigits: 2 })} MVR`} 
                    icon={<Wallet className="w-6 h-6 text-rose-500" />}
                    color="bg-rose-500/10"
                  />
                  <StatCard 
                    label="Today's Total Spend" 
                    value={`${expenseStats.todayTotal.toLocaleString(undefined, { minimumFractionDigits: 2 })} MVR`} 
                    icon={<ArrowRightCircle className="w-6 h-6 text-orange-500" />}
                    color="bg-orange-500/10"
                  />
                </div>
                <div className="grid grid-cols-1 xl:grid-cols-12 gap-10">
                  <div className="xl:col-span-4">
                    <TransactionForm 
                      onSuccess={(t) => handleAddData(t, 'Expenses')} 
                      isLoading={isSyncing} 
                      title="Log New Expense"
                      placeholder="Expense description..."
                      icon={<Wallet className="w-5 h-5 text-rose-500" />}
                      options={dynamicExpenseCategories}
                    />
                  </div>
                  <div className="xl:col-span-8">
                    <TransactionList 
                      transactions={expenses} 
                      title="Full Expense History" 
                      description="Dedicated list of spending recorded in the Expenses sheet"
                      showCategory={true}
                      onDelete={(t) => handleDeleteData(t, 'Expenses')}
                    />
                  </div>
                </div>
              </div>
            )}

            {view === 'settings' && <Settings onSave={fetchData} />}
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Transaction } from '../types';
import { PlusCircle, Loader2, Sparkles, Calendar as CalendarIcon, Tag, ChevronDown, Edit3, AlignLeft } from 'lucide-react';

interface TransactionFormProps {
  onSuccess: (transaction: Transaction) => void;
  isLoading: boolean;
  title?: string;
  placeholder?: string;
  icon?: React.ReactNode;
  options?: string[]; 
}

const MONTHS = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];

const TransactionForm: React.FC<TransactionFormProps> = ({ 
  onSuccess, 
  isLoading, 
  title = "New Entry", 
  placeholder = "Details...",
  icon = <PlusCircle className="w-5 h-5 text-indigo-400" />,
  options = []
}) => {
  const getLocalDateString = () => {
    const now = new Date();
    const year = now.getFullYear();
    const month = String(now.getMonth() + 1).padStart(2, '0');
    const day = String(now.getDate()).padStart(2, '0');
    return `${year}-${month}-${day}`;
  };

  const [formData, setFormData] = useState<Transaction>({
    date: getLocalDateString(),
    amount: 0,
    name: '',
    category: options.length > 1 ? options[0] : (options[0] || '')
  });

  const [isCustomCategory, setIsCustomCategory] = useState(false);
  const dateInputRef = useRef<HTMLInputElement>(null);

  const formatDisplayDate = (isoDate: string) => {
    if (!isoDate) return 'Select Date';
    const parts = isoDate.split('-');
    if (parts.length !== 3) return isoDate;
    const [y, m, d] = parts;
    const mmm = MONTHS[parseInt(m) - 1] || '???';
    return `${d.padStart(2, '0')}-${mmm}-${y.slice(-2)}`;
  };

  useEffect(() => {
    if (options.length > 0 && !isCustomCategory) {
      if (!formData.category || !options.includes(formData.category)) {
        setFormData(prev => ({ ...prev, category: options[0] }));
      }
    }
  }, [options, isCustomCategory]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (formData.amount <= 0 || !formData.name) return;
    const finalCategory = formData.category || (options.length > 0 ? options[0] : '');
    onSuccess({ ...formData, category: finalCategory });
    setFormData({
      date: getLocalDateString(),
      amount: 0,
      name: '',
      category: options.length > 0 ? options[0] : ''
    });
    setIsCustomCategory(false);
  };

  return (
    <div className="bg-slate-900 p-8 rounded-3xl shadow-sm border border-slate-800 h-full relative overflow-hidden group">
      <div className="absolute top-0 right-0 p-4 opacity-5 group-hover:opacity-10 transition-opacity">
        <Sparkles className="w-24 h-24 text-indigo-400" />
      </div>

      <h3 className="text-xl font-extrabold text-slate-100 mb-8 flex items-center gap-3">
        <div className="p-2.5 bg-indigo-500/10 rounded-xl">
          {icon}
        </div>
        {title}
      </h3>

      <form onSubmit={handleSubmit} className="space-y-6">
        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest px-1 flex items-center gap-2">
            <CalendarIcon className="w-3 h-3" />
            Date
          </label>
          <div className="relative group/date">
            <input
              type="date"
              ref={dateInputRef}
              required
              className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"
              value={formData.date}
              onChange={(e) => setFormData({ ...formData, date: e.target.value })}
            />
            <div className="w-full px-5 py-4 bg-slate-800 border border-slate-700 rounded-2xl group-hover/date:border-indigo-500/50 transition-all flex items-center justify-between">
              <span className="text-sm font-bold text-slate-200">
                {formatDisplayDate(formData.date)}
              </span>
              <CalendarIcon className="w-4 h-4 text-slate-600 group-hover/date:text-indigo-400 transition-colors" />
            </div>
          </div>
        </div>

        {options.length > 0 && (
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest px-1 flex items-center gap-2">
              <Tag className="w-3 h-3" />
              Category
            </label>

            {!isCustomCategory ? (
              <div className="relative">
                <select
                  required
                  className="w-full px-5 py-4 bg-slate-800 border border-slate-700 rounded-2xl focus:outline-none focus:ring-4 focus:ring-indigo-500/10 focus:bg-slate-800 focus:border-indigo-500 transition-all text-sm font-bold appearance-none cursor-pointer text-slate-200"
                  value={formData.category}
                  onChange={(e) => {
                    if (e.target.value === 'CUSTOM_NEW') {
                      setIsCustomCategory(true);
                      setFormData({ ...formData, category: '' });
                    } else {
                      setFormData({ ...formData, category: e.target.value });
                    }
                  }}
                >
                  {options.map((opt) => (
                    <option key={opt} value={opt} className="bg-slate-900">{opt}</option>
                  ))}
                  <option value="CUSTOM_NEW" className="text-indigo-400 font-bold bg-slate-900">+ Add New...</option>
                </select>
                <ChevronDown className="absolute right-5 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500 pointer-events-none" />
              </div>
            ) : (
              <div className="relative">
                <input
                  type="text"
                  required
                  placeholder="New category name..."
                  className="w-full px-5 py-4 bg-slate-800 border border-slate-700 rounded-2xl focus:outline-none focus:ring-4 focus:ring-indigo-500/10 focus:bg-slate-800 focus:border-indigo-500 transition-all text-sm font-bold text-slate-200"
                  value={formData.category || ''}
                  onChange={(e) => setFormData({ ...formData, category: e.target.value })}
                  autoFocus
                />
                <button 
                  type="button"
                  onClick={() => setIsCustomCategory(false)}
                  className="absolute right-4 top-1/2 -translate-y-1/2 p-2 hover:bg-slate-700 rounded-lg text-slate-500 transition-colors"
                  title="Back to list"
                >
                  <Edit3 className="w-3.5 h-3.5" />
                </button>
              </div>
            )}
          </div>
        )}

        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest px-1 flex items-center gap-2">
            <AlignLeft className="w-3 h-3" />
            Description
          </label>
          <input
            type="text"
            required
            placeholder={placeholder}
            className="w-full px-5 py-4 bg-slate-800 border border-slate-700 rounded-2xl focus:outline-none focus:ring-4 focus:ring-indigo-500/10 focus:bg-slate-800 focus:border-indigo-500 transition-all text-sm font-bold text-slate-200"
            value={formData.name}
            onChange={(e) => setFormData({ ...formData, name: e.target.value })}
          />
        </div>

        <div className="space-y-2">
          <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest px-1">Amount (MVR)</label>
          <div className="relative">
            <span className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-500 font-black text-xs">MVR</span>
            <input
              type="number"
              step="0.01"
              required
              placeholder="0.00"
              className="w-full pl-16 pr-5 py-4 bg-slate-800 border border-slate-700 rounded-2xl focus:outline-none focus:ring-4 focus:ring-indigo-500/10 focus:bg-slate-800 focus:border-indigo-500 transition-all text-base font-black text-slate-100"
              value={formData.amount || ''}
              onChange={(e) => setFormData({ ...formData, amount: parseFloat(e.target.value) || 0 })}
            />
          </div>
        </div>

        <button
          type="submit"
          disabled={isLoading}
          className="w-full bg-slate-100 hover:bg-indigo-500 disabled:bg-slate-800 text-slate-900 hover:text-white font-black py-4 rounded-2xl shadow-xl shadow-black/20 hover:shadow-indigo-900/40 transition-all flex items-center justify-center gap-3 active:scale-[0.98]"
        >
          {isLoading ? (
            <Loader2 className="w-5 h-5 animate-spin" />
          ) : (
            <>
              <PlusCircle className="w-5 h-5" />
              Sync Record
            </>
          )}
        </button>
      </form>
    </div>
  );
};

