import React, { useMemo } from 'react';
import { Transaction, DailyTotal } from '../types';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer,
  Cell
} from 'recharts';
import { Landmark, TrendingUp, Banknote, AlertCircle } from 'lucide-react';
import StatCard from './StatCard';

interface DashboardProps {
  transactions: Transaction[];
  expenses: Transaction[];
}

const MONTHS = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];

const Dashboard: React.FC<DashboardProps> = ({ transactions, expenses }) => {
  const getLocalDatePart = (dateInput: string) => {
    if (!dateInput) return '';
    const cleanStr = dateInput.startsWith("'") ? dateInput.slice(1) : dateInput;
    if (cleanStr.includes('T')) {
      const d = new Date(cleanStr);
      if (!isNaN(d.getTime())) {
        const year = d.getFullYear();
        const month = String(d.getMonth() + 1).padStart(2, '0');
        const day = String(d.getDate()).padStart(2, '0');
        return `${year}-${month}-${day}`;
      }
    }
    return cleanStr.split('T')[0];
  };

  const formatForDisplay = (isoDate: string) => {
    if (!isoDate) return '';
    const parts = isoDate.split('-');
    if (parts.length !== 3) return isoDate;
    const [y, m, d] = parts;
    const mmm = MONTHS[parseInt(m) - 1] || '???';
    return `${d.padStart(2, '0')}-${mmm}-${y.slice(-2)}`;
  };

  const stats = useMemo(() => {
    const totalSales = transactions.reduce((acc, curr) => acc + curr.amount, 0);
    const totalExpenses = expenses.reduce((acc, curr) => acc + curr.amount, 0);
    const profit = totalSales - totalExpenses;
    const now = new Date();
    const todayStr = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}`;
    const todayTotal = transactions
      .filter(t => t.date && getLocalDatePart(t.date) === todayStr)
      .reduce((acc, curr) => acc + curr.amount, 0);
    const dailyMap = transactions.reduce((acc: Record<string, number>, curr) => {
      const dateKey = getLocalDatePart(curr.date);
      if (dateKey) {
        acc[dateKey] = (acc[dateKey] || 0) + curr.amount;
      }
      return acc;
    }, {} as Record<string, number>);
    const dailyData: DailyTotal[] = Object.entries(dailyMap)
      .map(([date, total]) => ({ date, total: total as number }))
      .sort((a, b) => a.date.localeCompare(b.date))
      .slice(-14);
    return { totalSales, todayTotal, dailyData, totalExpenses, profit };
  }, [transactions, expenses]);

  const COLORS = ['#6366f1', '#8b5cf6', '#ec4899', '#f43f5e', '#f97316'];

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        <StatCard 
          label="Total Sales" 
          value={`${stats.totalSales.toLocaleString(undefined, { minimumFractionDigits: 2 })} MVR`} 
          icon={<Landmark className="w-5 h-5 lg:w-6 lg:h-6 text-emerald-500" />}
          color="bg-emerald-500/10"
        />
        <StatCard 
          label="Today's Sales" 
          value={`${stats.todayTotal.toLocaleString(undefined, { minimumFractionDigits: 2 })} MVR`} 
          icon={<TrendingUp className="w-5 h-5 lg:w-6 lg:h-6 text-indigo-500" />}
          color="bg-indigo-500/10"
        />
        <StatCard 
          label="Profit / Loss" 
          value={`${stats.profit.toLocaleString(undefined, { minimumFractionDigits: 2 })} MVR`} 
          icon={stats.profit >= 0 ? <Banknote className="w-5 h-5 lg:w-6 lg:h-6 text-violet-500" /> : <AlertCircle className="w-5 h-5 lg:w-6 lg:h-6 text-rose-500" />}
          color={stats.profit >= 0 ? "bg-violet-500/10" : "bg-rose-500/10"}
          trend={stats.profit >= 0 ? "Positive Net" : "Negative Net"}
        />
      </div>

      <div className="w-full">
        <div className="bg-zinc-950 p-8 rounded-3xl shadow-2xl border border-zinc-900">
          <div className="flex items-center justify-between mb-8">
            <h3 className="text-xl font-bold text-zinc-100 tracking-tight">Daily Sales Performance</h3>
            <div className="text-[10px] font-black uppercase tracking-widest text-zinc-600">Last 14 days</div>
          </div>
          <div className="h-96 w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={stats.dailyData} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#18181b" />
                <XAxis 
                  dataKey="date" 
                  axisLine={false} 
                  tickLine={false} 
                  tick={{ fontSize: 10, fill: '#52525b', fontWeight: 600 }} 
                  dy={10}
                  tickFormatter={formatForDisplay}
                />
                <YAxis 
                  axisLine={false} 
                  tickLine={false} 
                  tick={{ fontSize: 10, fill: '#52525b', fontWeight: 600 }}
                />
                <Tooltip 
                  cursor={{ fill: '#09090b' }}
                  labelFormatter={formatForDisplay}
                  formatter={(value) => [`${Number(value).toFixed(2)} MVR`, 'Total Sales']}
                  contentStyle={{ 
                    backgroundColor: '#000000', 
                    borderRadius: '16px', 
                    border: '1px solid #27272a', 
                    boxShadow: '0 25px 50px -12px rgba(0,0,0,0.5)', 
                    padding: '12px',
                    color: '#fafafa'
                  }}
                  itemStyle={{ color: '#fafafa' }}
                />
                <Bar dataKey="total" radius={[6, 6, 0, 0]} barSize={32}>
                  {stats.dailyData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} opacity={0.9} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { Transaction } from '../types';
import { Table, Calendar, Tag, ChevronRight, Landmark, Download, Layers, Trash2, AlertTriangle, Loader2 } from 'lucide-react';

interface TransactionListProps {
  transactions: Transaction[];
  title?: string;
  description?: string;
  nameLabel?: string;
  showCategory?: boolean;
  onDelete?: (transaction: Transaction) => Promise<void>;
}

const MONTHS = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];

const TransactionList: React.FC<TransactionListProps> = ({ 
  transactions, 
  title = "History", 
  description = "Detailed log of your records",
  nameLabel = "Description",
  showCategory = false,
  onDelete
}) => {
  const [deletingId, setDeletingId] = useState<number | null>(null);
  const [confirmDeleteId, setConfirmDeleteId] = useState<number | null>(null);

  const formatDisplayDate = (dateInput: string) => {
    if (!dateInput) return 'N/A';
    const cleanStr = dateInput.startsWith("'") ? dateInput.slice(1) : dateInput;
    let dateObj: Date;
    if (cleanStr.includes('T')) {
      dateObj = new Date(cleanStr);
    } else {
      const parts = cleanStr.split(/[-/]/);
      if (parts.length === 3) {
        if (parts[0].length === 4) {
          dateObj = new Date(parseInt(parts[0]), parseInt(parts[1]) - 1, parseInt(parts[2]));
        } else if (parts[2].length === 4 || parts[2].length === 2) {
          const year = parts[2].length === 2 ? 2000 + parseInt(parts[2]) : parseInt(parts[2]);
          dateObj = new Date(year, parseInt(parts[1]) - 1, parseInt(parts[0]));
        } else { dateObj = new Date(cleanStr); }
      } else { dateObj = new Date(cleanStr); }
    }
    if (isNaN(dateObj.getTime())) return cleanStr;
    const dd = String(dateObj.getDate()).padStart(2, '0');
    const mmm = MONTHS[dateObj.getMonth()];
    const yy = String(dateObj.getFullYear()).slice(-2);
    return `${dd}-${mmm}-${yy}`;
  };

  const handleDeleteClick = async (t: Transaction) => {
    if (t.rowId === undefined || t.rowId === null || !onDelete) return;
    if (confirmDeleteId !== t.rowId) {
      setConfirmDeleteId(t.rowId);
      return;
    }
    try {
      setDeletingId(t.rowId);
      await onDelete(t);
    } finally {
      setDeletingId(null);
      setConfirmDeleteId(null);
    }
  };

  const handleExportCSV = () => {
    if (transactions.length === 0) return;
    const headers = ['Date', ...(showCategory ? ['Category'] : []), nameLabel, 'Amount (MVR)'];
    const rows = transactions.slice().reverse().map(t => [
      formatDisplayDate(t.date),
      ...(showCategory ? [t.category || 'N/A'] : []),
      `"${t.name.replace(/"/g, '""')}"`,
      t.amount.toFixed(2)
    ]);
    const csvContent = [headers.join(','), ...rows.map(row => row.join(','))].join('\n');
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const now = new Date();
    const stamp = `${String(now.getDate()).padStart(2, '0')}-${MONTHS[now.getMonth()]}-${String(now.getFullYear()).slice(-2)}`;
    const link = document.createElement('a');
    link.setAttribute('href', url);
    link.setAttribute('download', `${title.replace(/\s+/g, '_')}_${stamp}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="bg-zinc-950 rounded-3xl shadow-2xl border border-zinc-900 overflow-hidden animate-in fade-in slide-in-from-bottom-8 duration-700">
      <div className="p-8 border-b border-zinc-900 flex flex-col sm:flex-row sm:items-center justify-between gap-6 bg-zinc-950">
        <div>
          <h3 className="text-xl font-extrabold text-zinc-100 flex items-center gap-3">
            <div className="p-2 bg-violet-500/10 rounded-xl">
              <Table className="w-5 h-5 text-violet-500" />
            </div>
            {title}
          </h3>
          <p className="text-sm text-zinc-500 mt-1">{description}</p>
        </div>

        <div className="flex items-center gap-3">
          <button
            onClick={handleExportCSV}
            disabled={transactions.length === 0}
            className="flex items-center gap-2 px-5 py-3 bg-zinc-100 hover:bg-white disabled:bg-zinc-900 disabled:text-zinc-700 text-zinc-950 rounded-2xl text-xs font-black transition-all shadow-lg active:scale-95"
          >
            <Download className="w-4 h-4" />
            Export CSV
          </button>
          <span className="text-xs font-black text-indigo-500 bg-indigo-500/10 px-4 py-3 rounded-2xl border border-indigo-500/20 uppercase tracking-tighter hidden sm:block">
            {transactions.length} Entries
          </span>
        </div>
      </div>

      <div className="overflow-x-auto">
        <table className="w-full text-left">
          <thead className="bg-black">
            <tr>
              <th className="px-8 py-5 text-xs font-bold text-zinc-600 uppercase tracking-widest">Date</th>
              {showCategory && <th className="px-8 py-5 text-xs font-bold text-zinc-600 uppercase tracking-widest">Category</th>}
              <th className="px-8 py-5 text-xs font-bold text-zinc-600 uppercase tracking-widest">{nameLabel}</th>
              <th className="px-8 py-5 text-xs font-bold text-zinc-600 uppercase tracking-widest text-right">Amount</th>
              {onDelete && <th className="px-8 py-5 text-xs font-bold text-zinc-600 uppercase tracking-widest text-right w-10">Actions</th>}
            </tr>
          </thead>
          <tbody className="divide-y divide-zinc-900">
            {transactions.slice().reverse().map((t, i) => (
              <tr key={t.rowId || i} className="group hover:bg-zinc-900/30 transition-all cursor-default">
                <td className="px-8 py-5 whitespace-nowrap">
                  <div className="flex items-center gap-3 text-sm font-medium text-zinc-500">
                    <Calendar className="w-4 h-4 text-zinc-700 group-hover:text-indigo-500 transition-colors" />
                    {formatDisplayDate(t.date)}
                  </div>
                </td>
                {showCategory && (
                  <td className="px-8 py-5 whitespace-nowrap">
                    <span className="inline-flex items-center gap-1.5 px-3 py-1.5 rounded-xl bg-zinc-900 text-zinc-400 text-[10px] font-black uppercase tracking-tighter border border-zinc-800">
                      <Layers className="w-3 h-3" />
                      {t.category || 'Uncategorized'}
                    </span>
                  </td>
                )}
                <td className="px-8 py-5">
                  <div className="flex items-center gap-3">
                    <div className="p-2 bg-zinc-900 rounded-lg group-hover:bg-zinc-800 transition-colors">
                      <Tag className="w-4 h-4 text-zinc-600" />
                    </div>
                    <span className="text-sm font-bold text-zinc-200">{t.name}</span>
                  </div>
                </td>
                <td className="px-8 py-5 text-right">
                  <div className="flex items-center justify-end gap-2">
                    <span className="text-xs font-bold text-zinc-700">MVR</span>
                    <span className="text-base font-black text-zinc-100">
                      {t.amount.toLocaleString(undefined, { minimumFractionDigits: 2 })}
                    </span>
                  </div>
                </td>
                {onDelete && (
                  <td className="px-8 py-5 text-right">
                    <div className="flex items-center justify-end">
                      <button
                        onClick={() => handleDeleteClick(t)}
                        disabled={deletingId === t.rowId}
                        className={`
                          p-2 rounded-xl transition-all flex items-center gap-2 group/btn
                          ${confirmDeleteId === t.rowId 
                            ? 'bg-rose-950 text-rose-500 px-3 border border-rose-900' 
                            : 'hover:bg-rose-950 text-zinc-700 hover:text-rose-500'}
                        `}
                      >
                        {deletingId === t.rowId ? (
                          <Loader2 className="w-4 h-4 animate-spin text-rose-500" />
                        ) : confirmDeleteId === t.rowId ? (
                          <>
                            <AlertTriangle className="w-4 h-4" />
                            <span className="text-[10px] font-black uppercase">Confirm?</span>
                          </>
                        ) : (
                          <Trash2 className="w-4 h-4" />
                        )}
                      </button>
                    </div>
                  </td>
                )}
              </tr>
            ))}
            {transactions.length === 0 && (
              <tr>
                <td colSpan={showCategory ? 5 : 4} className="px-8 py-20 text-center">
                  <div className="flex flex-col items-center gap-2">
                    <div className="w-16 h-16 bg-zinc-900 rounded-full flex items-center justify-center mb-2">
                      <Landmark className="w-8 h-8 text-zinc-800" />
                    </div>
                    <p className="text-zinc-700 font-bold">No records found.</p>
                  </div>
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default TransactionList;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { Transaction, ViewType } from './types';
import { GoogleSheetsService } from './services/googleSheets';
import TransactionForm from './components/TransactionForm';
import Dashboard from './components/Dashboard';
import TransactionList from './components/TransactionList';
import Settings from './components/Settings';
import StatCard from './components/StatCard';
import { 
  LayoutDashboard, 
  Receipt, 
  Settings as SettingsIcon, 
  RefreshCw,
  AlertCircle,
  Menu,
  Zap,
  Wallet,
  ArrowRightCircle,
  TrendingUp
} from 'lucide-react';

const App: React.FC = () => {
  const [view, setView] = useState<ViewType>('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]); 
  const [expenses, setExpenses] = useState<Transaction[]>([]);         
  const [fetchedCategories, setFetchedCategories] = useState<string[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  const fetchData = useCallback(async () => {
    setIsLoading(true);
    setError(null);
    try {
      const [salesData, expenseData, categoryData] = await Promise.all([
        GoogleSheetsService.fetchTransactions('Transcations'),
        GoogleSheetsService.fetchTransactions('Expenses'),
        GoogleSheetsService.fetchTransactions('Category').catch(() => []) 
      ]);

      setTransactions(salesData);
      setExpenses(expenseData);

      const categoriesFromSheet = categoryData
        .map(c => (c.category || c.date || c.name || '').toString().trim()) 
        .filter(c => 
          c !== '' && 
          !['DATE', 'NAME', 'CATEGORY', 'AMOUNT'].includes(c.toUpperCase())
        );

      setFetchedCategories(categoriesFromSheet);
    } catch (err: any) {
      setError(err.message || 'Could not fetch data. Check your permissions.');
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  const handleAddData = async (newRecord: Transaction, sheet: 'Transcations' | 'Expenses') => {
    setIsSyncing(true);
    try {
      await GoogleSheetsService.addTransaction(newRecord, sheet);
      if (sheet === 'Transcations') {
        setTransactions(prev => [...prev, newRecord]);
      } else {
        setExpenses(prev => [...prev, newRecord]);
      }
      setTimeout(() => fetchData(), 2500); 
    } catch (err) {
      setError('Sync failed. Please check connection and Script version.');
    } finally {
      setIsSyncing(false);
    }
  };

  const handleDeleteData = async (transaction: Transaction, sheet: 'Transcations' | 'Expenses') => {
    if (transaction.rowId === undefined || transaction.rowId === null) {
      setError('Cannot delete: This record is missing a cloud identifier.');
      return;
    }

    try {
      if (sheet === 'Transcations') {
        setTransactions(prev => prev.filter(t => t.rowId !== transaction.rowId));
      } else {
        setExpenses(prev => prev.filter(e => e.rowId !== transaction.rowId));
      }
      await GoogleSheetsService.deleteTransaction(transaction.rowId, sheet);
      setTimeout(() => { fetchData(); }, 3000);
    } catch (err) {
      console.error('Delete operation error:', err);
      setError('Delete request failed. Check your internet or Script version.');
      fetchData();
    }
  };

  const navItems = [
    { id: 'dashboard', label: 'Sales Dashboard', icon: LayoutDashboard },
    { id: 'transactions', label: 'Sales Log', icon: Receipt },
    { id: 'expenses', label: 'Expense Log', icon: Wallet },
    { id: 'settings', label: 'Cloud', icon: SettingsIcon },
  ];

  const expenseStats = useMemo(() => {
    const now = new Date();
    const todayStr = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}`;
    const total = expenses.reduce((acc, curr) => acc + (Number(curr.amount) || 0), 0);
    const todayTotal = expenses
      .filter(t => {
        if (!t.date) return false;
        const cleanStr = t.date.startsWith("'") ? t.date.slice(1) : t.date;
        let transDate = cleanStr.split('T')[0];
        if (cleanStr.includes('T')) {
          const d = new Date(cleanStr);
          if (!isNaN(d.getTime())) {
            transDate = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
          }
        }
        return transDate === todayStr;
      })
      .reduce((acc, curr) => acc + (Number(curr.amount) || 0), 0);
    return { total, todayTotal };
  }, [expenses]);

  const dynamicExpenseCategories = useMemo(() => {
    const uniqueCategories = Array.from(new Set(fetchedCategories)) as string[];
    return uniqueCategories.length > 0 
      ? uniqueCategories.sort((a, b) => a.localeCompare(b))
      : ['General']; 
  }, [fetchedCategories]);

  return (
    <div className="min-h-screen bg-black flex text-zinc-100 selection:bg-indigo-500/30 selection:text-indigo-200">
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black/80 backdrop-blur-md z-40 lg:hidden animate-in fade-in duration-300"
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      <aside className={`
        fixed inset-y-0 left-0 z-50 w-72 bg-zinc-950 border-r border-zinc-900 transform transition-all duration-500 lg:relative lg:translate-x-0
        ${isSidebarOpen ? 'translate-x-0 shadow-2xl' : '-translate-x-full'}
      `}>
        <div className="h-full flex flex-col p-8">
          <div className="mb-12">
            <div className="flex items-center gap-4">
              <div className="w-12 h-12 bg-indigo-600 rounded-2xl flex items-center justify-center text-white shadow-xl shadow-indigo-900/40">
                <Zap className="w-6 h-6 fill-current" />
              </div>
              <div>
                <h1 className="text-xl font-black tracking-tighter text-zinc-100">Load Badhige</h1>
                <p className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-500">Business Manager</p>
              </div>
            </div>
          </div>

          <nav className="flex-1 space-y-2">
            {navItems.map((item) => (
              <button
                key={item.id}
                onClick={() => {
                  setView(item.id as ViewType);
                  setIsSidebarOpen(false);
                }}
                className={`
                  w-full flex items-center gap-4 px-5 py-4 rounded-2xl text-sm font-bold transition-all group
                  ${view === item.id 
                    ? 'bg-indigo-600/10 text-indigo-500' 
                    : 'text-zinc-500 hover:bg-zinc-900 hover:text-zinc-200'}
                `}
              >
                <item.icon className={`w-5 h-5 transition-transform duration-300 ${view === item.id ? 'scale-110' : 'group-hover:scale-110'}`} />
                {item.label}
              </button>
            ))}
          </nav>

          <div className="mt-auto pt-8">
            <div className="flex items-center gap-3 px-5 py-4 bg-zinc-900/50 rounded-2xl border border-zinc-900">
              <div className={`w-2 h-2 rounded-full ${error ? 'bg-rose-500 shadow-[0_0_8px_rgba(244,63,94,0.6)]' : 'bg-emerald-500 shadow-[0_0_8px_rgba(16,185,129,0.6)]'} ${!error && (isLoading || isSyncing) ? 'animate-pulse' : ''}`} />
              <div className="flex flex-col">
                <span className="text-[10px] font-black text-zinc-500 uppercase tracking-[0.2em]">
                  {error ? 'Sync Error' : (isLoading || isSyncing) ? 'Syncing...' : 'Cloud Active'}
                </span>
              </div>
            </div>
          </div>
        </div>
      </aside>

      <main className="flex-1 flex flex-col min-w-0 h-screen overflow-hidden">
        <header className="sticky top-0 z-30 bg-black/80 backdrop-blur-xl border-b border-zinc-900 px-8 py-6 flex items-center justify-between">
          <div className="flex items-center gap-6">
            <button className="lg:hidden p-2 text-zinc-400 hover:bg-zinc-900 rounded-xl transition-colors" onClick={() => setIsSidebarOpen(true)}>
              <Menu className="w-6 h-6" />
            </button>
            <div>
              <h2 className="text-xl font-black text-zinc-100 tracking-tight capitalize">
                {view === 'transactions' ? 'Sales Log' : view === 'dashboard' ? 'Sales Dashboard' : view === 'expenses' ? 'Expense Log' : view === 'settings' ? 'Cloud Settings' : view}
              </h2>
              <p className="text-xs font-bold text-zinc-500">Finance & Analytics</p>
            </div>
          </div>
          <button onClick={fetchData} disabled={isLoading} className="p-3 text-zinc-400 hover:text-indigo-500 hover:bg-indigo-600/10 rounded-2xl transition-all border border-zinc-900 flex items-center gap-2 group">
            <RefreshCw className={`w-4 h-4 ${isLoading ? 'animate-spin text-indigo-500' : 'group-hover:rotate-180 transition-transform duration-500'}`} />
            <span className="text-xs font-bold hidden sm:inline px-1">Refresh Data</span>
          </button>
        </header>

        <div className="flex-1 p-8 lg:p-12 overflow-y-auto custom-scrollbar">
          <div className="max-w-7xl mx-auto space-y-10 pb-12">
            {error && (
              <div className="bg-rose-950/30 border border-rose-900/50 p-5 rounded-3xl flex items-center gap-4 text-rose-200 text-sm shadow-sm animate-in slide-in-from-top-4">
                <AlertCircle className="w-5 h-5 flex-shrink-0 text-rose-500" />
                <div className="flex-1 font-bold">{error}</div>
              </div>
            )}

            {view === 'dashboard' && (
              <div className="grid grid-cols-1 xl:grid-cols-12 gap-10">
                <div className="xl:col-span-4">
                  <TransactionForm 
                    onSuccess={(t) => handleAddData(t, 'Transcations')} 
                    isLoading={isSyncing} 
                    title="Quick Sales Entry"
                    placeholder="Transferred By..."
                    icon={<TrendingUp className="w-5 h-5 text-indigo-500" />}
                  />
                </div>
                <div className="xl:col-span-8">
                  <Dashboard transactions={transactions} expenses={expenses} />
                </div>
              </div>
            )}

            {view === 'transactions' && (
              <TransactionList 
                transactions={transactions} 
                title="Full Sales Log" 
                description="List of all sales recorded in the main transactions sheet"
                nameLabel="Transferred By"
                onDelete={(t) => handleDeleteData(t, 'Transcations')}
              />
            )}

            {view === 'expenses' && (
              <div className="space-y-10">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <StatCard 
                    label="Total Expenses" 
                    value={`${expenseStats.total.toLocaleString(undefined, { minimumFractionDigits: 2 })} MVR`} 
                    icon={<Wallet className="w-6 h-6 text-rose-500" />}
                    color="bg-rose-500/10"
                  />
                  <StatCard 
                    label="Today's Total Spend" 
                    value={`${expenseStats.todayTotal.toLocaleString(undefined, { minimumFractionDigits: 2 })} MVR`} 
                    icon={<ArrowRightCircle className="w-6 h-6 text-orange-500" />}
                    color="bg-orange-500/10"
                  />
                </div>
                <div className="grid grid-cols-1 xl:grid-cols-12 gap-10">
                  <div className="xl:col-span-4">
                    <TransactionForm 
                      onSuccess={(t) => handleAddData(t, 'Expenses')} 
                      isLoading={isSyncing} 
                      title="Log New Expense"
                      placeholder="Expense description..."
                      icon={<Wallet className="w-5 h-5 text-rose-500" />}
                      options={dynamicExpenseCategories}
                    />
                  </div>
                  <div className="xl:col-span-8">
                    <TransactionList 
                      transactions={expenses} 
                      title="Full Expense History" 
                      description="Dedicated list of spending recorded in the Expenses sheet"
                      showCategory={true}
                      onDelete={(t) => handleDeleteData(t, 'Expenses')}
                    />
                  </div>
                </div>
              </div>
            )}

            {view === 'settings' && <Settings onSave={fetchData} />}
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Transaction } from '../types';
import { 
  Table, 
  Calendar, 
  Tag, 
  Landmark, 
  Download, 
  Layers, 
  Trash2, 
  AlertTriangle, 
  Loader2, 
  Search, 
  X 
} from 'lucide-react';

interface TransactionListProps {
  transactions: Transaction[];
  title?: string;
  description?: string;
  nameLabel?: string;
  showCategory?: boolean;
  onDelete?: (transaction: Transaction) => Promise<void>;
}

const MONTHS = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];

const TransactionList: React.FC<TransactionListProps> = ({ 
  transactions, 
  title = "History", 
  description = "Detailed log of your records",
  nameLabel = "Description",
  showCategory = false,
  onDelete
}) => {
  const [deletingId, setDeletingId] = useState<number | null>(null);
  const [confirmDeleteId, setConfirmDeleteId] = useState<number | null>(null);
  const [searchTerm, setSearchTerm] = useState('');

  const formatDisplayDate = (dateInput: string) => {
    if (!dateInput) return 'N/A';
    const cleanStr = dateInput.startsWith("'") ? dateInput.slice(1) : dateInput;
    let dateObj: Date;
    if (cleanStr.includes('T')) {
      dateObj = new Date(cleanStr);
    } else {
      const parts = cleanStr.split(/[-/]/);
      if (parts.length === 3) {
        if (parts[0].length === 4) {
          dateObj = new Date(parseInt(parts[0]), parseInt(parts[1]) - 1, parseInt(parts[2]));
        } else if (parts[2].length === 4 || parts[2].length === 2) {
          const year = parts[2].length === 2 ? 2000 + parseInt(parts[2]) : parseInt(parts[2]);
          dateObj = new Date(year, parseInt(parts[1]) - 1, parseInt(parts[0]));
        } else { dateObj = new Date(cleanStr); }
      } else { dateObj = new Date(cleanStr); }
    }
    if (isNaN(dateObj.getTime())) return cleanStr;
    const dd = String(dateObj.getDate()).padStart(2, '0');
    const mmm = MONTHS[dateObj.getMonth()];
    const yy = String(dateObj.getFullYear()).slice(-2);
    return `${dd}-${mmm}-${yy}`;
  };

  const filteredTransactions = useMemo(() => {
    if (!searchTerm.trim()) return transactions;
    const lowerSearch = searchTerm.toLowerCase();
    return transactions.filter(t => {
      const formattedDate = formatDisplayDate(t.date).toLowerCase();
      const nameMatch = t.name.toLowerCase().includes(lowerSearch);
      const categoryMatch = showCategory && t.category?.toLowerCase().includes(lowerSearch);
      const dateMatch = formattedDate.includes(lowerSearch);
      return nameMatch || categoryMatch || dateMatch;
    });
  }, [transactions, searchTerm, showCategory]);

  const handleDeleteClick = async (t: Transaction) => {
    if (t.rowId === undefined || t.rowId === null || !onDelete) return;
    if (confirmDeleteId !== t.rowId) {
      setConfirmDeleteId(t.rowId);
      return;
    }
    try {
      setDeletingId(t.rowId);
      await onDelete(t);
    } finally {
      setDeletingId(null);
      setConfirmDeleteId(null);
    }
  };

  const handleExportCSV = () => {
    const dataToExport = filteredTransactions.length > 0 ? filteredTransactions : transactions;
    if (dataToExport.length === 0) return;

    const headers = ['Date', ...(showCategory ? ['Category'] : []), nameLabel, 'Amount (MVR)'];
    const rows = dataToExport.slice().reverse().map(t => [
      formatDisplayDate(t.date),
      ...(showCategory ? [t.category || 'N/A'] : []),
      `"${t.name.replace(/"/g, '""')}"`,
      t.amount.toFixed(2)
    ]);
    const csvContent = [headers.join(','), ...rows.map(row => row.join(','))].join('\n');
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const now = new Date();
    const stamp = `${String(now.getDate()).padStart(2, '0')}-${MONTHS[now.getMonth()]}-${String(now.getFullYear()).slice(-2)}`;
    const link = document.createElement('a');
    link.setAttribute('href', url);
    link.setAttribute('download', `${title.replace(/\s+/g, '_')}_${stamp}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="bg-zinc-950 rounded-3xl shadow-2xl border border-zinc-900 overflow-hidden animate-in fade-in slide-in-from-bottom-8 duration-700">
      <div className="p-8 border-b border-zinc-900 flex flex-col xl:flex-row xl:items-center justify-between gap-6 bg-zinc-950">
        <div>
          <h3 className="text-xl font-extrabold text-zinc-100 flex items-center gap-3">
            <div className="p-2 bg-violet-500/10 rounded-xl">
              <Table className="w-5 h-5 text-violet-500" />
            </div>
            {title}
          </h3>
          <p className="text-sm text-zinc-500 mt-1">{description}</p>
        </div>

        <div className="flex flex-col sm:flex-row items-stretch sm:items-center gap-4 flex-1 xl:max-w-2xl xl:justify-end">
          <div className="relative flex-1">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-zinc-600" />
            <input
              type="text"
              placeholder={`Filter by ${nameLabel.toLowerCase()}${showCategory ? ', category' : ''} or date...`}
              className="w-full pl-11 pr-11 py-3 bg-black border border-zinc-800 rounded-2xl text-sm font-bold text-zinc-200 placeholder:text-zinc-700 focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 transition-all"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
            {searchTerm && (
              <button 
                onClick={() => setSearchTerm('')}
                className="absolute right-4 top-1/2 -translate-y-1/2 p-1 hover:bg-zinc-800 rounded-lg text-zinc-500 transition-colors"
              >
                <X className="w-3.5 h-3.5" />
              </button>
            )}
          </div>

          <div className="flex items-center gap-3">
            <button
              onClick={handleExportCSV}
              disabled={transactions.length === 0}
              className="flex items-center gap-2 px-5 py-3 bg-zinc-100 hover:bg-white disabled:bg-zinc-900 disabled:text-zinc-700 text-zinc-950 rounded-2xl text-xs font-black transition-all shadow-lg active:scale-95 whitespace-nowrap"
            >
              <Download className="w-4 h-4" />
              Export {searchTerm ? 'Filtered' : 'CSV'}
            </button>
