import React, { useState, useMemo } from 'react';
import { Transaction } from '../types';
import { 
  Table, 
  Calendar, 
  Tag, 
  Landmark, 
  Download, 
  Layers, 
  Trash2, 
  AlertTriangle, 
  Loader2, 
  Search, 
  X 
} from 'lucide-react';

interface TransactionListProps {
  transactions: Transaction[];
  title?: string;
  description?: string;
  nameLabel?: string;
  showCategory?: boolean;
  onDelete?: (transaction: Transaction) => Promise<void>;
}

const MONTHS = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];

const TransactionList: React.FC<TransactionListProps> = ({ 
  transactions, 
  title = "History", 
  description = "Detailed log of your records",
  nameLabel = "Description",
  showCategory = false,
  onDelete
}) => {
  const [deletingId, setDeletingId] = useState<number | null>(null);
  const [confirmDeleteId, setConfirmDeleteId] = useState<number | null>(null);
  const [searchTerm, setSearchTerm] = useState('');

  const formatDisplayDate = (dateInput: string) => {
    if (!dateInput) return 'N/A';
    const cleanStr = dateInput.startsWith("'") ? dateInput.slice(1) : dateInput;
    let dateObj: Date;
    if (cleanStr.includes('T')) {
      dateObj = new Date(cleanStr);
    } else {
      const parts = cleanStr.split(/[-/]/);
      if (parts.length === 3) {
        if (parts[0].length === 4) {
          dateObj = new Date(parseInt(parts[0]), parseInt(parts[1]) - 1, parseInt(parts[2]));
        } else if (parts[2].length === 4 || parts[2].length === 2) {
          const year = parts[2].length === 2 ? 2000 + parseInt(parts[2]) : parseInt(parts[2]);
          dateObj = new Date(year, parseInt(parts[1]) - 1, parseInt(parts[0]));
        } else { dateObj = new Date(cleanStr); }
      } else { dateObj = new Date(cleanStr); }
    }
    if (isNaN(dateObj.getTime())) return cleanStr;
    const dd = String(dateObj.getDate()).padStart(2, '0');
    const mmm = MONTHS[dateObj.getMonth()];
    const yy = String(dateObj.getFullYear()).slice(-2);
    return `${dd}/${mmm}/${yy}`;
  };

  const filteredTransactions = useMemo(() => {
    if (!searchTerm.trim()) return transactions;
    const lowerSearch = searchTerm.toLowerCase();
    return transactions.filter(t => {
      const formattedDate = formatDisplayDate(t.date).toLowerCase();
      const nameMatch = t.name.toLowerCase().includes(lowerSearch);
      const categoryMatch = showCategory && t.category?.toLowerCase().includes(lowerSearch);
      const dateMatch = formattedDate.includes(lowerSearch);
      return nameMatch || categoryMatch || dateMatch;
    });
  }, [transactions, searchTerm, showCategory]);

  const handleDeleteClick = async (t: Transaction) => {
    if (t.rowId === undefined || t.rowId === null || !onDelete) return;
    if (confirmDeleteId !== t.rowId) {
      setConfirmDeleteId(t.rowId);
      return;
    }
    try {
      setDeletingId(t.rowId);
      await onDelete(t);
    } finally {
      setDeletingId(null);
      setConfirmDeleteId(null);
    }
  };

  const handleExportCSV = () => {
    const dataToExport = filteredTransactions.length > 0 ? filteredTransactions : transactions;
    if (dataToExport.length === 0) return;

    const headers = ['Date', ...(showCategory ? ['Category'] : []), nameLabel, 'Amount (MVR)'];
    const rows = dataToExport.slice().reverse().map(t => [
      formatDisplayDate(t.date),
      ...(showCategory ? [t.category || 'N/A'] : []),
      `"${t.name.replace(/"/g, '""')}"`,
      t.amount.toFixed(2)
    ]);
    const csvContent = [headers.join(','), ...rows.map(row => row.join(','))].join('\n');
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const now = new Date();
    const stamp = `${String(now.getDate()).padStart(2, '0')}-${MONTHS[now.getMonth()]}-${String(now.getFullYear()).slice(-2)}`;
    const link = document.createElement('a');
    link.setAttribute('href', url);
    link.setAttribute('download', `${title.replace(/\s+/g, '_')}_${stamp}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="bg-zinc-950 rounded-3xl shadow-2xl border border-zinc-900 overflow-hidden animate-in fade-in slide-in-from-bottom-8 duration-700">
      <div className="p-8 border-b border-zinc-900 flex flex-col xl:flex-row xl:items-center justify-between gap-6 bg-zinc-950">
        <div>
          <h3 className="text-xl font-extrabold text-zinc-100 flex items-center gap-3">
            <div className="p-2 bg-violet-500/10 rounded-xl">
              <Table className="w-5 h-5 text-violet-500" />
            </div>
            {title}
          </h3>
          <p className="text-sm text-zinc-500 mt-1">{description}</p>
        </div>

        <div className="flex flex-col sm:flex-row items-stretch sm:items-center gap-4 flex-1 xl:max-w-2xl xl:justify-end">
          <div className="relative flex-1">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-zinc-600" />
            <input
              type="text"
              placeholder={`Filter by ${nameLabel.toLowerCase()}${showCategory ? ', category' : ''} or date...`}
              className="w-full pl-11 pr-11 py-3 bg-black border border-zinc-800 rounded-2xl text-sm font-bold text-zinc-200 placeholder:text-zinc-700 focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 transition-all"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
            {searchTerm && (
              <button 
                onClick={() => setSearchTerm('')}
                className="absolute right-4 top-1/2 -translate-y-1/2 p-1 hover:bg-zinc-800 rounded-lg text-zinc-500 transition-colors"
              >
                <X className="w-3.5 h-3.5" />
              </button>
            )}
          </div>

          <div className="flex items-center gap-3">
            <button
              onClick={handleExportCSV}
              disabled={transactions.length === 0}
              className="flex items-center gap-2 px-5 py-3 bg-zinc-100 hover:bg-white disabled:bg-zinc-900 disabled:text-zinc-700 text-zinc-950 rounded-2xl text-xs font-black transition-all shadow-lg active:scale-95 whitespace-nowrap"
            >
              <Download className="w-4 h-4" />
              Export {searchTerm ? 'Filtered' : 'CSV'}
            </button>
            <span className="text-xs font-black text-indigo-500 bg-indigo-500/10 px-4 py-3 rounded-2xl border border-indigo-500/20 uppercase tracking-tighter hidden sm:block whitespace-nowrap">
              {searchTerm ? `${filteredTransactions.length} Matches` : `${transactions.length} Entries`}
            </span>
          </div>
        </div>
      </div>

      <div className="overflow-x-auto">
        <table className="w-full text-left">
          <thead className="bg-black">
            <tr>
              <th className="px-8 py-5 text-xs font-bold text-zinc-600 uppercase tracking-widest">Date</th>
              {showCategory && <th className="px-8 py-5 text-xs font-bold text-zinc-600 uppercase tracking-widest">Category</th>}
              <th className="px-8 py-5 text-xs font-bold text-zinc-600 uppercase tracking-widest">{nameLabel}</th>
              <th className="px-8 py-5 text-xs font-bold text-zinc-600 uppercase tracking-widest text-right">Amount</th>
              {onDelete && <th className="px-8 py-5 text-xs font-bold text-zinc-600 uppercase tracking-widest text-right w-10">Actions</th>}
            </tr>
          </thead>
          <tbody className="divide-y divide-zinc-900">
            {filteredTransactions.slice().reverse().map((t, i) => (
              <tr key={t.rowId || i} className="group hover:bg-zinc-900/30 transition-all cursor-default">
                <td className="px-8 py-5 whitespace-nowrap">
                  <div className="flex items-center gap-3 text-sm font-medium text-zinc-500">
                    <Calendar className="w-4 h-4 text-zinc-700 group-hover:text-indigo-500 transition-colors" />
                    {formatDisplayDate(t.date)}
                  </div>
                </td>
                {showCategory && (
                  <td className="px-8 py-5 whitespace-nowrap">
                    <span className="inline-flex items-center gap-1.5 px-3 py-1.5 rounded-xl bg-zinc-900 text-zinc-400 text-[10px] font-black uppercase tracking-tighter border border-zinc-800">
                      <Layers className="w-3 h-3" />
                      {t.category || 'Uncategorized'}
                    </span>
                  </td>
                )}
                <td className="px-8 py-5">
                  <div className="flex items-center gap-3">
                    <div className="p-2 bg-zinc-900 rounded-lg group-hover:bg-zinc-800 transition-colors">
                      <Tag className="w-4 h-4 text-zinc-600" />
                    </div>
                    <span className="text-sm font-bold text-zinc-200">{t.name}</span>
                  </div>
                </td>
                <td className="px-8 py-5 text-right">
                  <div className="flex items-center justify-end gap-2">
                    <span className="text-xs font-bold text-zinc-700">MVR</span>
                    <span className="text-base font-black text-zinc-100">
                      {t.amount.toLocaleString(undefined, { minimumFractionDigits: 2 })}
                    </span>
                  </div>
                </td>
                {onDelete && (
                  <td className="px-8 py-5 text-right">
                    <div className="flex items-center justify-end">
                      <button
                        onClick={() => handleDeleteClick(t)}
                        disabled={deletingId === t.rowId}
                        className={`
                          p-2 rounded-xl transition-all flex items-center gap-2 group/btn
                          ${confirmDeleteId === t.rowId 
                            ? 'bg-rose-950 text-rose-500 px-3 border border-rose-900' 
                            : 'hover:bg-rose-950 text-zinc-700 hover:text-rose-500'}
                        `}
                      >
                        {deletingId === t.rowId ? (
                          <Loader2 className="w-4 h-4 animate-spin text-rose-500" />
                        ) : confirmDeleteId === t.rowId ? (
                          <>
                            <AlertTriangle className="w-4 h-4" />
                            <span className="text-[10px] font-black uppercase">Confirm?</span>
                          </>
                        ) : (
                          <Trash2 className="w-4 h-4" />
                        )}
                      </button>
                    </div>
                  </td>
                )}
              </tr>
            ))}
            {filteredTransactions.length === 0 && (
              <tr>
                <td colSpan={showCategory ? 5 : 4} className="px-8 py-20 text-center">
                  <div className="flex flex-col items-center gap-2">
                    <div className="w-16 h-16 bg-zinc-900 rounded-full flex items-center justify-center mb-2">
                      {searchTerm ? (
                        <Search className="w-8 h-8 text-zinc-800" />
                      ) : (
                        <Landmark className="w-8 h-8 text-zinc-800" />
                      )}
                    </div>
                    <p className="text-zinc-700 font-bold">
                      {searchTerm ? `No results for "${searchTerm}"` : 'No records found.'}
                    </p>
                    {searchTerm && (
                      <button 
                        onClick={() => setSearchTerm('')}
                        className="text-xs font-black text-indigo-500 hover:text-indigo-400 mt-2 uppercase tracking-widest"
                      >
                        Clear All Filters
                      </button>
                    )}
                  </div>
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default TransactionList;

import React, { useState, useEffect, useRef } from 'react';
import { Transaction } from '../types';
import { PlusCircle, Loader2, Sparkles, Calendar as CalendarIcon, Tag, ChevronDown, Edit3, AlignLeft } from 'lucide-react';

interface TransactionFormProps {
  onSuccess: (transaction: Transaction) => void;
  isLoading: boolean;
  title?: string;
  placeholder?: string;
  icon?: React.ReactNode;
  options?: string[]; 
}

const MONTHS = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];

const TransactionForm: React.FC<TransactionFormProps> = ({ 
  onSuccess, 
  isLoading, 
  title = "New Entry", 
  placeholder = "Details...",
  icon = <PlusCircle className="w-5 h-5 text-indigo-500" />,
  options = []
}) => {
  const pickerId = React.useId();

  const getLocalDateString = () => {
    const now = new Date();
    const year = now.getFullYear();
    const month = String(now.getMonth() + 1).padStart(2, '0');
    const day = String(now.getDate()).padStart(2, '0');
    return `${year}-${month}-${day}`;
  };

  const formatDateToDisplay = (isoDate: string) => {
    if (!isoDate) return '';
    const [y, m, d] = isoDate.split('-');
    if (!y || !m || !d) return isoDate;
    const mmm = MONTHS[parseInt(m) - 1];
    const yy = y.slice(-2);
    return `${d.padStart(2, '0')}/${mmm}/${yy}`;
  };

  const parseDisplayToDate = (displayStr: string): string | null => {
    const parts = displayStr.split(/[-/ ]/);
    if (parts.length !== 3) return null;

    let [d, m, y] = parts;

    // Parse Day
    const day = parseInt(d);
    if (isNaN(day) || day < 1 || day > 31) return null;

    // Parse Month
    let monthIndex = -1;
    if (isNaN(parseInt(m))) {
      monthIndex = MONTHS.findIndex(name => name.toLowerCase() === m.toLowerCase());
    } else {
      monthIndex = parseInt(m) - 1;
    }
    if (monthIndex < 0 || monthIndex > 11) return null;

    // Parse Year
    let year = parseInt(y);
    if (isNaN(year)) return null;
    if (year < 100) year += 2000;

    const pad = (n: number) => String(n).padStart(2, '0');
    return `${year}-${pad(monthIndex + 1)}-${pad(day)}`;
  };

  const [formData, setFormData] = useState<Transaction>({
    date: getLocalDateString(),
    amount: 0,
    name: '',
    category: options.length > 1 ? options[0] : (options[0] || '')
  });

  const [displayDate, setDisplayDate] = useState(formatDateToDisplay(getLocalDateString()));
  const [isCustomCategory, setIsCustomCategory] = useState(false);
  const datePickerRef = useRef<HTMLInputElement>(null);
  const textInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (options.length > 0 && !isCustomCategory) {
      if (!formData.category || !options.includes(formData.category)) {
        setFormData(prev => ({ ...prev, category: options[0] }));
      }
    }
  }, [options, isCustomCategory]);

  const handleManualDateChange = (val: string) => {
    setDisplayDate(val);
    const parsed = parseDisplayToDate(val);
    if (parsed) {
      setFormData(prev => ({ ...prev, date: parsed }));
    }
  };

  const handlePickerChange = (isoDate: string) => {
    if (!isoDate) return;
    setFormData(prev => ({ ...prev, date: isoDate }));
    setDisplayDate(formatDateToDisplay(isoDate));
  };

  const triggerPicker = (e?: React.MouseEvent | React.TouchEvent | React.PointerEvent) => {
    if (e) {
      e.preventDefault();
      e.stopPropagation();
    }

    if (datePickerRef.current) {
      try {
        // Modern browsers standard
        if (typeof (datePickerRef.current as any).showPicker === 'function') {
          (datePickerRef.current as any).showPicker();
        } else {
          // Fallback
          datePickerRef.current.click();
        }
      } catch (err) {
        // Safe fallback for restricted contexts
        datePickerRef.current.click();
      }
    }
  };

  const handleMouseEnter = () => {
    if (textInputRef.current) {
      textInputRef.current.focus();
      textInputRef.current.select();
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (formData.amount <= 0 || !formData.name || !formData.date) return;
    const finalCategory = formData.category || (options.length > 0 ? options[0] : '');
    onSuccess({ ...formData, category: finalCategory });

    const defaultDate = getLocalDateString();
    setFormData({
      date: defaultDate,
      amount: 0,
      name: '',
      category: options.length > 0 ? options[0] : ''
    });
    setDisplayDate(formatDateToDisplay(defaultDate));
    setIsCustomCategory(false);
  };

  return (
    <div className="bg-zinc-950 p-8 rounded-3xl shadow-2xl border border-zinc-900 h-full relative overflow-hidden group">
      <div className="absolute top-0 right-0 p-4 opacity-5 group-hover:opacity-10 transition-opacity pointer-events-none">
        <Sparkles className="w-24 h-24 text-indigo-500" />
      </div>

      <h3 className="text-xl font-extrabold text-zinc-100 mb-8 flex items-center gap-3">
        <div className="p-2.5 bg-indigo-500/10 rounded-xl">
          {icon}
        </div>
        {title}
      </h3>

      <form onSubmit={handleSubmit} className="space-y-6">
        <div className="space-y-2">
          <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest px-1 flex items-center gap-2">
            <CalendarIcon className="w-3 h-3" />
            Date (DD/MMM/YY)
          </label>
          <div 
            className="relative cursor-pointer group/date"
            onMouseEnter={handleMouseEnter}
          >
            <input
              type="text"
              ref={textInputRef}
              placeholder="DD/MMM/YY"
              className="w-full px-5 py-4 bg-zinc-900 border border-zinc-800 rounded-2xl focus:outline-none focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 transition-all text-sm font-bold text-zinc-200"
              value={displayDate}
              onChange={(e) => handleManualDateChange(e.target.value)}
              onBlur={() => setDisplayDate(formatDateToDisplay(formData.date))}
              onClick={(e) => triggerPicker()}
            />

            <button 
              type="button"
              className="absolute right-4 top-1/2 -translate-y-1/2 p-2 hover:bg-zinc-800 rounded-xl text-zinc-600 hover:text-indigo-500 transition-all z-20"
              onClick={triggerPicker}
              title="Open Calendar"
            >
              <CalendarIcon className="w-4 h-4 pointer-events-none" />
            </button>

            {/* Hidden native picker - positioned correctly to avoid browser block */}
            <input
              id={pickerId}
              type="date"
              ref={datePickerRef}
              className="absolute inset-0 opacity-0 w-full h-full cursor-pointer pointer-events-none -z-10"
              value={formData.date}
              onChange={(e) => handlePickerChange(e.target.value)}
              tabIndex={-1}
            />
          </div>
        </div>

        {options.length > 0 && (
          <div className="space-y-2">
            <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest px-1 flex items-center gap-2">
              <Tag className="w-3 h-3" />
              Category
            </label>

            {!isCustomCategory ? (
              <div className="relative">
                <select
                  required
                  className="w-full px-5 py-4 bg-zinc-900 border border-zinc-800 rounded-2xl focus:outline-none focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 transition-all text-sm font-bold appearance-none cursor-pointer text-zinc-200"
                  value={formData.category}
                  onChange={(e) => {
                    if (e.target.value === 'CUSTOM_NEW') {
                      setIsCustomCategory(true);
                      setFormData({ ...formData, category: '' });
                    } else {
                      setFormData({ ...formData, category: e.target.value });
                    }
                  }}
                >
                  {options.map((opt) => (
                    <option key={opt} value={opt} className="bg-zinc-950">{opt}</option>
                  ))}
                  <option value="CUSTOM_NEW" className="text-indigo-500 font-bold bg-zinc-950">+ Add New...</option>
                </select>
                <ChevronDown className="absolute right-5 top-1/2 -translate-y-1/2 w-4 h-4 text-zinc-600 pointer-events-none" />
              </div>
            ) : (
              <div className="relative">
                <input
                  type="text"
                  required
                  placeholder="New category name..."
                  className="w-full px-5 py-4 bg-zinc-900 border border-zinc-800 rounded-2xl focus:outline-none focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 transition-all text-sm font-bold text-zinc-200"
                  value={formData.category || ''}
                  onChange={(e) => setFormData({ ...formData, category: e.target.value })}
                  autoFocus
                />
                <button 
                  type="button"
                  onClick={() => setIsCustomCategory(false)}
                  className="absolute right-4 top-1/2 -translate-y-1/2 p-2 hover:bg-zinc-800 rounded-lg text-zinc-500 transition-colors"
                  title="Back to list"
                >
                  <Edit3 className="w-3.5 h-3.5" />
                </button>
              </div>
            )}
          </div>
        )}

        <div className="space-y-2">
          <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest px-1 flex items-center gap-2">
            <AlignLeft className="w-3 h-3" />
            Description
          </label>
          <input
            type="text"
            required
            placeholder={placeholder}
            className="w-full px-5 py-4 bg-zinc-900 border border-zinc-800 rounded-2xl focus:outline-none focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 transition-all text-sm font-bold text-zinc-200"
            value={formData.name}
            onChange={(e) => setFormData({ ...formData, name: e.target.value })}
          />
        </div>

        <div className="space-y-2">
          <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest px-1">Amount (MVR)</label>
          <div className="relative">
            <span className="absolute left-5 top-1/2 -translate-y-1/2 text-zinc-600 font-black text-xs">MVR</span>
            <input
              type="number"
              step="0.01"
              required
              placeholder="0.00"
              className="w-full pl-16 pr-5 py-4 bg-zinc-900 border border-zinc-800 rounded-2xl focus:outline-none focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 transition-all text-base font-black text-zinc-100"
              value={formData.amount || ''}
              onChange={(e) => setFormData({ ...formData, amount: parseFloat(e.target.value) || 0 })}
            />
          </div>
        </div>

        <button
          type="submit"
          disabled={isLoading}
          className="w-full bg-zinc-100 hover:bg-indigo-600 disabled:bg-zinc-800 text-zinc-950 hover:text-white font-black py-4 rounded-2xl shadow-xl shadow-black transition-all flex items-center justify-center gap-3 active:scale-[0.98]"
        >
          {isLoading ? (
            <Loader2 className="w-5 h-5 animate-spin" />
          ) : (
            <>
              <PlusCircle className="w-5 h-5" />
              Sync Record
            </>
          )}
        </button>
      </form>
    </div>
  );
};

export default TransactionForm;

import React, { useState, useEffect, useRef } from 'react';
import { Transaction } from '../types';
import { PlusCircle, Loader2, Sparkles, Calendar as CalendarIcon, Tag, ChevronDown, Edit3, AlignLeft } from 'lucide-react';

interface TransactionFormProps {
  onSuccess: (transaction: Transaction) => void;
  isLoading: boolean;
  title?: string;
  placeholder?: string;
  icon?: React.ReactNode;
  options?: string[]; 
}

const MONTHS = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];

const TransactionForm: React.FC<TransactionFormProps> = ({ 
  onSuccess, 
  isLoading, 
  title = "New Entry", 
  placeholder = "Details...",
  icon = <PlusCircle className="w-5 h-5 text-indigo-500" />,
  options = []
}) => {
  const pickerId = React.useId();

  const getLocalDateString = () => {
    const now = new Date();
    const year = now.getFullYear();
    const month = String(now.getMonth() + 1).padStart(2, '0');
    const day = String(now.getDate()).padStart(2, '0');
    return `${year}-${month}-${day}`;
  };

  const formatDateToDisplay = (isoDate: string) => {
    if (!isoDate) return '';
    const [y, m, d] = isoDate.split('-');
    if (!y || !m || !d) return isoDate;
    const yy = y.slice(-2);
    return `${d.padStart(2, '0')}/${m.padStart(2, '0')}/${yy}`;
  };

  const parseDisplayToDate = (displayStr: string): string | null => {
    const parts = displayStr.split(/[-/ ]/);
    if (parts.length !== 3) return null;

    let [d, m, y] = parts;

    // Parse Day
    const day = parseInt(d);
    if (isNaN(day) || day < 1 || day > 31) return null;

    // Parse Month
    let monthIndex = -1;
    if (isNaN(parseInt(m))) {
      monthIndex = MONTHS.findIndex(name => name.toLowerCase() === m.toLowerCase());
    } else {
      monthIndex = parseInt(m) - 1;
    }
    if (monthIndex < 0 || monthIndex > 11) return null;

    // Parse Year
    let year = parseInt(y);
    if (isNaN(year)) return null;
    if (year < 100) year += 2000;

    const pad = (n: number) => String(n).padStart(2, '0');
    return `${year}-${pad(monthIndex + 1)}-${pad(day)}`;
  };

  const [formData, setFormData] = useState<Transaction>({
    date: getLocalDateString(),
    amount: 0,
    name: '',
    category: options.length > 1 ? options[0] : (options[0] || '')
  });

  const [displayDate, setDisplayDate] = useState(formatDateToDisplay(getLocalDateString()));
  const [isCustomCategory, setIsCustomCategory] = useState(false);
  const datePickerRef = useRef<HTMLInputElement>(null);
  const textInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (options.length > 0 && !isCustomCategory) {
      if (!formData.category || !options.includes(formData.category)) {
        setFormData(prev => ({ ...prev, category: options[0] }));
      }
    }
  }, [options, isCustomCategory]);

  const handleManualDateChange = (val: string) => {
    setDisplayDate(val);
    const parsed = parseDisplayToDate(val);
    if (parsed) {
      setFormData(prev => ({ ...prev, date: parsed }));
    }
  };

  const handlePickerChange = (isoDate: string) => {
    if (!isoDate) return;
    setFormData(prev => ({ ...prev, date: isoDate }));
    setDisplayDate(formatDateToDisplay(isoDate));
  };

  const triggerPicker = (e?: React.MouseEvent | React.TouchEvent | React.PointerEvent) => {
    if (e) {
      e.preventDefault();
      e.stopPropagation();
    }

    if (datePickerRef.current) {
      try {
        if (typeof (datePickerRef.current as any).showPicker === 'function') {
          (datePickerRef.current as any).showPicker();
        } else {
          datePickerRef.current.click();
        }
      } catch (err) {
        datePickerRef.current.click();
      }
    }
  };

  const handleMouseEnter = () => {
    if (textInputRef.current) {
      textInputRef.current.focus();
      textInputRef.current.select();
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (formData.amount <= 0 || !formData.name || !formData.date) return;
    const finalCategory = formData.category || (options.length > 0 ? options[0] : '');
    onSuccess({ ...formData, category: finalCategory });

    const defaultDate = getLocalDateString();
    setFormData({
      date: defaultDate,
      amount: 0,
      name: '',
      category: options.length > 0 ? options[0] : ''
    });
    setDisplayDate(formatDateToDisplay(defaultDate));
    setIsCustomCategory(false);
  };

  return (
    <div className="bg-zinc-950 p-8 rounded-3xl shadow-2xl border border-zinc-900 h-full relative overflow-hidden group">
      <div className="absolute top-0 right-0 p-4 opacity-5 group-hover:opacity-10 transition-opacity pointer-events-none">
        <Sparkles className="w-24 h-24 text-indigo-500" />
      </div>

      <h3 className="text-xl font-extrabold text-zinc-100 mb-8 flex items-center gap-3">
        <div className="p-2.5 bg-indigo-500/10 rounded-xl">
          {icon}
        </div>
        {title}
      </h3>

      <form onSubmit={handleSubmit} className="space-y-6">
        <div className="space-y-2">
          <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest px-1 flex items-center gap-2">
            <CalendarIcon className="w-3 h-3" />
            Date (DD/MM/YY)
          </label>
          <div 
            className="relative cursor-pointer group/date"
            onMouseEnter={handleMouseEnter}
          >
            <input
              type="text"
              ref={textInputRef}
              placeholder="DD/MM/YY"
              className="w-full px-5 py-4 bg-zinc-900 border border-zinc-800 rounded-2xl focus:outline-none focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 transition-all text-sm font-bold text-zinc-200"
              value={displayDate}
              onChange={(e) => handleManualDateChange(e.target.value)}
              onBlur={() => setDisplayDate(formatDateToDisplay(formData.date))}
              onClick={(e) => triggerPicker()}
            />

            <button 
              type="button"
              className="absolute right-4 top-1/2 -translate-y-1/2 p-2 hover:bg-zinc-800 rounded-xl text-zinc-600 hover:text-indigo-500 transition-all z-20"
              onClick={triggerPicker}
              title="Open Calendar"
            >
              <CalendarIcon className="w-4 h-4 pointer-events-none" />
            </button>

            <input
              id={pickerId}
              type="date"
              ref={datePickerRef}
              className="absolute inset-0 opacity-0 w-full h-full cursor-pointer pointer-events-none -z-10"
              value={formData.date}
              onChange={(e) => handlePickerChange(e.target.value)}
              tabIndex={-1}
            />
          </div>
        </div>

        {options.length > 0 && (
          <div className="space-y-2">
            <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest px-1 flex items-center gap-2">
              <Tag className="w-3 h-3" />
              Category
            </label>

            {!isCustomCategory ? (
              <div className="relative">
                <select
                  required
                  className="w-full px-5 py-4 bg-zinc-900 border border-zinc-800 rounded-2xl focus:outline-none focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 transition-all text-sm font-bold appearance-none cursor-pointer text-zinc-200"
                  value={formData.category}
                  onChange={(e) => {
                    if (e.target.value === 'CUSTOM_NEW') {
                      setIsCustomCategory(true);
                      setFormData({ ...formData, category: '' });
                    } else {
                      setFormData({ ...formData, category: e.target.value });
                    }
                  }}
                >
                  {options.map((opt) => (
                    <option key={opt} value={opt} className="bg-zinc-950">{opt}</option>
                  ))}
                  <option value="CUSTOM_NEW" className="text-indigo-500 font-bold bg-zinc-950">+ Add New...</option>
                </select>
                <ChevronDown className="absolute right-5 top-1/2 -translate-y-1/2 w-4 h-4 text-zinc-600 pointer-events-none" />
              </div>
            ) : (
              <div className="relative">
                <input
                  type="text"
                  required
                  placeholder="New category name..."
                  className="w-full px-5 py-4 bg-zinc-900 border border-zinc-800 rounded-2xl focus:outline-none focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 transition-all text-sm font-bold text-zinc-200"
                  value={formData.category || ''}
                  onChange={(e) => setFormData({ ...formData, category: e.target.value })}
                  autoFocus
                />
                <button 
                  type="button"
                  onClick={() => setIsCustomCategory(false)}
                  className="absolute right-4 top-1/2 -translate-y-1/2 p-2 hover:bg-zinc-800 rounded-lg text-zinc-500 transition-colors"
                  title="Back to list"
                >
                  <Edit3 className="w-3.5 h-3.5" />
                </button>
              </div>
            )}
          </div>
        )}

        <div className="space-y-2">
          <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest px-1 flex items-center gap-2">
            <AlignLeft className="w-3 h-3" />
            Description
          </label>
          <input
            type="text"
            required
            placeholder={placeholder}
            className="w-full px-5 py-4 bg-zinc-900 border border-zinc-800 rounded-2xl focus:outline-none focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 transition-all text-sm font-bold text-zinc-200"
            value={formData.name}
            onChange={(e) => setFormData({ ...formData, name: e.target.value })}
          />
        </div>

        <div className="space-y-2">
          <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest px-1">Amount (MVR)</label>
          <div className="relative">
            <span className="absolute left-5 top-1/2 -translate-y-1/2 text-zinc-600 font-black text-xs">MVR</span>
            <input
              type="number"
              step="0.01"
              required
              placeholder="0.00"
              className="w-full pl-16 pr-5 py-4 bg-zinc-900 border border-zinc-800 rounded-2xl focus:outline-none focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 transition-all text-base font-black text-zinc-100"
              value={formData.amount || ''}
              onChange={(e) => setFormData({ ...formData, amount: parseFloat(e.target.value) || 0 })}
            />
          </div>
        </div>

        <button
          type="submit"
          disabled={isLoading}
          className="w-full bg-zinc-100 hover:bg-indigo-600 disabled:bg-zinc-800 text-zinc-950 hover:text-white font-black py-4 rounded-2xl shadow-xl shadow-black transition-all flex items-center justify-center gap-3 active:scale-[0.98]"
        >
          {isLoading ? (
            <Loader2 className="w-5 h-5 animate-spin" />
          ) : (
            <>
              <PlusCircle className="w-5 h-5" />
              Sync Record
            </>
          )}
        </button>
      </form>
    </div>
  );
};

export default TransactionForm;

import React, { useMemo } from 'react';
import { Transaction, DailyTotal } from '../types';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer,
  Cell
} from 'recharts';
import { Landmark, TrendingUp, Banknote, AlertCircle } from 'lucide-react';
import StatCard from './StatCard';

interface DashboardProps {
  transactions: Transaction[];
  expenses: Transaction[];
}

const Dashboard: React.FC<DashboardProps> = ({ transactions, expenses }) => {
  const getLocalDatePart = (dateInput: string) => {
    if (!dateInput) return '';
    const cleanStr = dateInput.startsWith("'") ? dateInput.slice(1) : dateInput;
    if (cleanStr.includes('T')) {
      const d = new Date(cleanStr);
      if (!isNaN(d.getTime())) {
        const year = d.getFullYear();
        const month = String(d.getMonth() + 1).padStart(2, '0');
        const day = String(d.getDate()).padStart(2, '0');
        return `${year}-${month}-${day}`;
      }
    }
    return cleanStr.split('T')[0];
  };

  const formatForDisplay = (isoDate: string) => {
    if (!isoDate) return '';
    const parts = isoDate.split('-');
    if (parts.length !== 3) return isoDate;
    const [y, m, d] = parts;
    return `${d.padStart(2, '0')}/${m.padStart(2, '0')}/${y.slice(-2)}`;
  };

  const stats = useMemo(() => {
    const totalSales = transactions.reduce((acc, curr) => acc + curr.amount, 0);
    const totalExpenses = expenses.reduce((acc, curr) => acc + curr.amount, 0);
    const profit = totalSales - totalExpenses;
    const now = new Date();
    const todayStr = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}`;
    const todayTotal = transactions
      .filter(t => t.date && getLocalDatePart(t.date) === todayStr)
      .reduce((acc, curr) => acc + curr.amount, 0);
    const dailyMap = transactions.reduce((acc: Record<string, number>, curr) => {
      const dateKey = getLocalDatePart(curr.date);
      if (dateKey) {
        acc[dateKey] = (acc[dateKey] || 0) + curr.amount;
      }
      return acc;
    }, {} as Record<string, number>);
    const dailyData: DailyTotal[] = Object.entries(dailyMap)
      .map(([date, total]) => ({ date, total: total as number }))
      .sort((a, b) => a.date.localeCompare(b.date))
      .slice(-14);
    return { totalSales, todayTotal, dailyData, totalExpenses, profit };
  }, [transactions, expenses]);

  const COLORS = ['#6366f1', '#8b5cf6', '#ec4899', '#f43f5e', '#f97316'];

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        <StatCard 
          label="Total Sales" 
          value={`${stats.totalSales.toLocaleString(undefined, { minimumFractionDigits: 2 })} MVR`} 
          icon={<Landmark className="w-5 h-5 lg:w-6 lg:h-6 text-emerald-500" />}
          color="bg-emerald-500/10"
        />
        <StatCard 
          label="Today's Sales" 
          value={`${stats.todayTotal.toLocaleString(undefined, { minimumFractionDigits: 2 })} MVR`} 
          icon={<TrendingUp className="w-5 h-5 lg:w-6 lg:h-6 text-indigo-500" />}
          color="bg-indigo-500/10"
        />
        <StatCard 
          label="Profit / Loss" 
          value={`${stats.profit.toLocaleString(undefined, { minimumFractionDigits: 2 })} MVR`} 
          icon={stats.profit >= 0 ? <Banknote className="w-5 h-5 lg:w-6 lg:h-6 text-violet-500" /> : <AlertCircle className="w-5 h-5 lg:w-6 lg:h-6 text-rose-500" />}
          color={stats.profit >= 0 ? "bg-violet-500/10" : "bg-rose-500/10"}
          trend={stats.profit >= 0 ? "Positive Net" : "Negative Net"}
        />
      </div>

      <div className="w-full">
        <div className="bg-zinc-950 p-8 rounded-3xl shadow-2xl border border-zinc-900">
          <div className="flex items-center justify-between mb-8">
            <h3 className="text-xl font-bold text-zinc-100 tracking-tight">Daily Sales Performance</h3>
            <div className="text-[10px] font-black uppercase tracking-widest text-zinc-600">Last 14 days</div>
          </div>
          <div className="h-96 w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={stats.dailyData} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#18181b" />
                <XAxis 
                  dataKey="date" 
                  axisLine={false} 
                  tickLine={false} 
                  tick={{ fontSize: 10, fill: '#52525b', fontWeight: 600 }} 
                  dy={10}
                  tickFormatter={formatForDisplay}
                />
                <YAxis 
                  axisLine={false} 
                  tickLine={false} 
                  tick={{ fontSize: 10, fill: '#52525b', fontWeight: 600 }}
                />
                <Tooltip 
                  cursor={{ fill: '#09090b' }}
                  labelFormatter={formatForDisplay}
                  formatter={(value) => [`${Number(value).toFixed(2)} MVR`, 'Total Sales']}
                  contentStyle={{ 
                    backgroundColor: '#000000', 
                    borderRadius: '16px', 
                    border: '1px solid #27272a', 
                    boxShadow: '0 25px 50px -12px rgba(0,0,0,0.5)', 
                    padding: '12px',
                    color: '#fafafa'
                  }}
                  itemStyle={{ color: '#fafafa' }}
                />
                <Bar dataKey="total" radius={[6, 6, 0, 0]} barSize={32}>
                  {stats.dailyData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} opacity={0.9} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useMemo } from 'react';
import { Transaction } from '../types';
import { 
  Table, 
  Calendar, 
  Tag, 
  Landmark, 
  Download, 
  Layers, 
  Trash2, 
  AlertTriangle, 
  Loader2, 
  Search, 
  X 
} from 'lucide-react';

interface TransactionListProps {
  transactions: Transaction[];
  title?: string;
  description?: string;
  nameLabel?: string;
  showCategory?: boolean;
  onDelete?: (transaction: Transaction) => Promise<void>;
}

const TransactionList: React.FC<TransactionListProps> = ({ 
  transactions, 
  title = "History", 
  description = "Detailed log of your records",
  nameLabel = "Description",
  showCategory = false,
  onDelete
}) => {
  const [deletingId, setDeletingId] = useState<number | null>(null);
  const [confirmDeleteId, setConfirmDeleteId] = useState<number | null>(null);
  const [searchTerm, setSearchTerm] = useState('');

  const formatDisplayDate = (dateInput: string) => {
    if (!dateInput) return 'N/A';
    const cleanStr = dateInput.startsWith("'") ? dateInput.slice(1) : dateInput;
    let dateObj: Date;
    if (cleanStr.includes('T')) {
      dateObj = new Date(cleanStr);
    } else {
      const parts = cleanStr.split(/[-/]/);
      if (parts.length === 3) {
        if (parts[0].length === 4) {
          dateObj = new Date(parseInt(parts[0]), parseInt(parts[1]) - 1, parseInt(parts[2]));
        } else if (parts[2].length === 4 || parts[2].length === 2) {
          const year = parts[2].length === 2 ? 2000 + parseInt(parts[2]) : parseInt(parts[2]);
          dateObj = new Date(year, parseInt(parts[1]) - 1, parseInt(parts[0]));
        } else { dateObj = new Date(cleanStr); }
      } else { dateObj = new Date(cleanStr); }
    }
    if (isNaN(dateObj.getTime())) return cleanStr;
    const dd = String(dateObj.getDate()).padStart(2, '0');
    const mm = String(dateObj.getMonth() + 1).padStart(2, '0');
    const yy = String(dateObj.getFullYear()).slice(-2);
    return `${dd}/${mm}/${yy}`;
  };

  const filteredTransactions = useMemo(() => {
    if (!searchTerm.trim()) return transactions;
    const lowerSearch = searchTerm.toLowerCase();
    return transactions.filter(t => {
      const formattedDate = formatDisplayDate(t.date).toLowerCase();
      const nameMatch = t.name.toLowerCase().includes(lowerSearch);
      const categoryMatch = showCategory && t.category?.toLowerCase().includes(lowerSearch);
      const dateMatch = formattedDate.includes(lowerSearch);
      return nameMatch || categoryMatch || dateMatch;
    });
  }, [transactions, searchTerm, showCategory]);

  const handleDeleteClick = async (t: Transaction) => {
    if (t.rowId === undefined || t.rowId === null || !onDelete) return;
    if (confirmDeleteId !== t.rowId) {
      setConfirmDeleteId(t.rowId);
      return;
    }
    try {
      setDeletingId(t.rowId);
      await onDelete(t);
    } finally {
      setDeletingId(null);
      setConfirmDeleteId(null);
    }
  };

  const handleExportCSV = () => {
    const dataToExport = filteredTransactions.length > 0 ? filteredTransactions : transactions;
    if (dataToExport.length === 0) return;

    const headers = ['Date', ...(showCategory ? ['Category'] : []), nameLabel, 'Amount (MVR)'];
    const rows = dataToExport.slice().reverse().map(t => [
      formatDisplayDate(t.date),
      ...(showCategory ? [t.category || 'N/A'] : []),
      `"${t.name.replace(/"/g, '""')}"`,
      t.amount.toFixed(2)
    ]);
    const csvContent = [headers.join(','), ...rows.map(row => row.join(','))].join('\n');
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const now = new Date();
    const stamp = `${String(now.getDate()).padStart(2, '0')}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getFullYear()).slice(-2)}`;
    const link = document.createElement('a');
    link.setAttribute('href', url);
    link.setAttribute('download', `${title.replace(/\s+/g, '_')}_${stamp}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="bg-zinc-950 rounded-3xl shadow-2xl border border-zinc-900 overflow-hidden animate-in fade-in slide-in-from-bottom-8 duration-700">
      <div className="p-8 border-b border-zinc-900 flex flex-col xl:flex-row xl:items-center justify-between gap-6 bg-zinc-950">
        <div>
          <h3 className="text-xl font-extrabold text-zinc-100 flex items-center gap-3">
            <div className="p-2 bg-violet-500/10 rounded-xl">
              <Table className="w-5 h-5 text-violet-500" />
            </div>
            {title}
          </h3>
          <p className="text-sm text-zinc-500 mt-1">{description}</p>
        </div>

        <div className="flex flex-col sm:flex-row items-stretch sm:items-center gap-4 flex-1 xl:max-w-2xl xl:justify-end">
          <div className="relative flex-1">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-zinc-600" />
            <input
              type="text"
              placeholder={`Filter by ${nameLabel.toLowerCase()}${showCategory ? ', category' : ''} or date...`}
              className="w-full pl-11 pr-11 py-3 bg-black border border-zinc-800 rounded-2xl text-sm font-bold text-zinc-200 placeholder:text-zinc-700 focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 transition-all"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
            {searchTerm && (
              <button 
                onClick={() => setSearchTerm('')}
                className="absolute right-4 top-1/2 -translate-y-1/2 p-1 hover:bg-zinc-800 rounded-lg text-zinc-500 transition-colors"
              >
                <X className="w-3.5 h-3.5" />
              </button>
            )}
          </div>

          <div className="flex items-center gap-3">
            <button
              onClick={handleExportCSV}
              disabled={transactions.length === 0}
