              </div>
            </div>
            {(dateFrom || dateTo || searchTerm) && (
              <button 
                onClick={() => { setDateFrom(''); setDateTo(''); setSearchTerm(''); }}
                className="p-3 bg-rose-500/10 hover:bg-rose-500/20 text-rose-500 rounded-2xl transition-colors border border-rose-500/20"
                title="Clear Filters"
              >
                <X className="w-4 h-4" />
