export default Header;

import React, { useState, useEffect, useRef } from 'react';
import { Item } from '../types';
import { PencilIcon, TrashIcon } from './IconComponents';

interface ItemCardProps {
  item: Item;
  onUpdateItem: (item: Item) => void;
  onDeleteItem: (id: string) => void;
  onSelectItem: (item: Item) => void;
  isEditMode: boolean;
}

const ItemCard: React.FC<ItemCardProps> = ({ item, onUpdateItem, onDeleteItem, onSelectItem, isEditMode }) => {
  const [isEditingPrice, setIsEditingPrice] = useState(false);
  const [price, setPrice] = useState(item.price.toFixed(2));

  const priceInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (isEditingPrice && priceInputRef.current) {
      priceInputRef.current.select();
    }
  }, [isEditingPrice]);

  useEffect(() => {
    setPrice(item.price.toFixed(2));
  }, [item]);

  const handlePriceUpdate = () => {
    const newPrice = parseFloat(price);
    if (!isNaN(newPrice) && newPrice >= 0) {
      onUpdateItem({ ...item, price: newPrice });
      setPrice(newPrice.toFixed(2));
    } else {
      setPrice(item.price.toFixed(2));
    }
    setIsEditingPrice(false);
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter') handlePriceUpdate();
    if (e.key === 'Escape') {
      setPrice(item.price.toFixed(2));
      setIsEditingPrice(false);
    }
  };

  const handleDeleteClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    onDeleteItem(item.id);
  }

  const handlePriceEditClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    setIsEditingPrice(true);
  }

  return (
    <div 
      className="group relative flex flex-col glass-card rounded-[2rem] overflow-hidden transition-all duration-500 hover:shadow-2xl hover:shadow-brand-primary/10 hover:-translate-y-2 cursor-pointer border border-white/5 hover:border-brand-primary/30"
      onClick={() => onSelectItem(item)}
    >
      {/* Image Container */}
      <div className="relative aspect-[4/5] overflow-hidden">
        <img
          src={item.imageUrl}
          alt={item.title}
          className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110"
          loading="lazy"
        />
        <div className="absolute inset-0 bg-gradient-to-t from-brand-bg-dark via-transparent to-transparent opacity-60"></div>

        {/* Hover Overlay */}
        <div className="absolute inset-0 flex flex-col items-center justify-center opacity-0 group-hover:opacity-100 transition-all duration-500 backdrop-blur-[2px] bg-brand-primary/5">
          <span className="bg-white/10 border border-white/20 backdrop-blur-xl px-4 py-2 rounded-full text-[10px] font-black uppercase tracking-[0.2em] text-white">
            View Details
          </span>
        </div>

        {isEditMode && (
          <button
            onClick={handleDeleteClick}
            className="absolute top-4 right-4 bg-red-500/80 hover:bg-red-500 text-white p-2.5 rounded-full transition-all duration-300 backdrop-blur-md shadow-xl opacity-0 translate-y-2 group-hover:opacity-100 group-hover:translate-y-0 z-10"
            aria-label="Delete item"
          >
            <TrashIcon className="h-4 w-4" />
          </button>
        )}
      </div>

      {/* Info Container */}
      <div className="p-5 sm:p-6 flex flex-col flex-grow bg-gradient-to-b from-white/[0.02] to-transparent">
        <h3 className="text-sm sm:text-base font-bold text-white mb-3 line-clamp-2 leading-snug group-hover:text-brand-primary transition-colors">
          {item.title}
        </h3>

        <div className="mt-auto flex items-end justify-between">
          <div className="flex flex-col">
            <span className="text-[9px] uppercase tracking-widest font-black text-brand-text-secondary mb-1">Price</span>
            {isEditMode && isEditingPrice ? (
              <div className="flex items-center" onClick={(e) => e.stopPropagation()}>
                <span className="text-brand-primary text-base mr-1 font-bold">$</span>
                <input
                  ref={priceInputRef}
                  type="number"
                  value={price}
                  onChange={(e) => setPrice(e.target.value)}
                  onBlur={handlePriceUpdate}
                  onKeyDown={handleKeyDown}
                  className="bg-brand-bg-dark text-white text-base font-bold w-20 rounded-lg px-2 py-0.5 outline-none ring-1 ring-brand-primary"
                  min="0"
                  step="0.01"
                />
              </div>
            ) : (
              <div className="flex items-center gap-1">
                <span className="text-lg sm:text-xl font-extrabold text-brand-primary tracking-tight">
                  ${item.price.toFixed(2)}
                </span>
                {isEditMode && (
                  <button 
                    onClick={handlePriceEditClick}
                    className="p-1 text-brand-text-secondary hover:text-brand-primary transition-colors"
                  >
                    <PencilIcon className="h-3 w-3" />
                  </button>
                )}
              </div>
            )}
          </div>

          <div className="w-8 h-8 rounded-full bg-white/5 border border-white/10 flex items-center justify-center group-hover:bg-brand-primary/10 group-hover:border-brand-primary/30 transition-all">
             <div className="w-1.5 h-1.5 rounded-full bg-brand-primary"></div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ItemCard;

import React, { useState, useEffect } from 'react';
import { Item } from '../types';
import { XIcon, PencilIcon } from './IconComponents';

interface ItemModalProps {
  item: Item;
  onClose: () => void;
  isEditMode: boolean;
  onUpdateItem: (item: Item) => Promise<void>;
}

const ItemModal: React.FC<ItemModalProps> = ({ item, onClose, isEditMode, onUpdateItem }) => {
  const [isSaving, setIsSaving] = useState(false);
  const [editedItem, setEditedItem] = useState<Item>({ ...item });
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    setEditedItem({ ...item });
  }, [item]);

  const handleSave = async () => {
    if (!editedItem.title.trim()) {
      setError("Title is required");
      return;
    }

    setIsSaving(true);
    setError(null);
    try {
      await onUpdateItem(editedItem);
      onClose();
    } catch (err: any) {
      setError(err.message || "Failed to save changes");
      setIsSaving(false);
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setEditedItem(prev => ({
      ...prev,
      [name]: name === 'price' ? parseFloat(value) || 0 : value
    }));
  };

  return (
    <div
      role="dialog"
      aria-modal="true"
      className="fixed inset-0 z-50 flex items-end sm:items-center justify-center"
    >
      <div 
        className="fixed inset-0 bg-brand-bg-dark/90 backdrop-blur-xl transition-opacity animate-in fade-in duration-300"
        onClick={onClose}
      ></div>

      <div className="relative z-10 w-full max-w-4xl bg-brand-bg-light sm:rounded-[2.5rem] shadow-[0_32px_128px_-16px_rgba(0,0,0,0.8)] overflow-hidden animate-in slide-in-from-bottom-8 duration-500 flex flex-col lg:flex-row h-full sm:h-auto sm:max-h-[85vh]">

        {/* Left: Media Area */}
        <div className="relative w-full lg:w-[45%] shrink-0 h-64 sm:h-96 lg:h-auto">
          <img
            src={item.imageUrl}
            alt={item.title}
            className="w-full h-full object-cover"
          />
          <div className="absolute inset-0 bg-gradient-to-t lg:bg-gradient-to-r from-brand-bg-light/80 via-transparent to-transparent"></div>
          <button
            onClick={onClose}
            className="absolute top-6 left-6 bg-white/10 hover:bg-white/20 text-white p-3 rounded-full transition-all shadow-2xl backdrop-blur-xl border border-white/20"
            aria-label="Close"
          >
            <XIcon className="h-5 w-5" />
          </button>
        </div>

        {/* Right: Details Area */}
        <div className="flex-grow p-8 sm:p-12 overflow-y-auto custom-scrollbar flex flex-col">
          {isEditMode ? (
            <div className="space-y-8 flex-grow">
              <div className="flex items-center gap-3">
                 <div className="bg-brand-primary/10 p-2 rounded-xl border border-brand-primary/20">
                   <PencilIcon className="h-4 w-4 text-brand-primary" />
                 </div>
                 <h3 className="text-xs font-black uppercase tracking-[0.3em] text-brand-primary">Editing Product</h3>
              </div>

              <div className="space-y-6">
                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase tracking-widest text-brand-text-secondary ml-1">Title</label>
                  <input
                    type="text"
                    name="title"
                    value={editedItem.title}
                    onChange={handleChange}
                    className="w-full bg-white/5 text-white text-xl font-bold rounded-2xl px-5 py-4 outline-none border border-white/10 focus:border-brand-primary/50 focus:ring-4 focus:ring-brand-primary/10 transition-all"
                  />
                </div>

                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase tracking-widest text-brand-text-secondary ml-1">Description</label>
                  <textarea
                    name="description"
                    value={editedItem.description}
                    onChange={handleChange}
                    rows={4}
                    className="w-full bg-white/5 text-brand-text-secondary text-sm leading-relaxed rounded-2xl px-5 py-4 outline-none border border-white/10 focus:border-brand-primary/50 focus:ring-4 focus:ring-brand-primary/10 transition-all resize-none"
                  />
                </div>

                <div className="grid grid-cols-1 sm:grid-cols-2 gap-6 pt-4">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase tracking-widest text-brand-text-secondary ml-1">Price ($)</label>
                    <input
                      type="number"
                      name="price"
                      value={editedItem.price}
                      onChange={handleChange}
                      step="0.01"
                      className="w-full bg-white/5 text-brand-primary text-xl font-black rounded-2xl px-5 py-4 outline-none border border-white/10 focus:border-brand-primary/50 transition-all"
                    />
                  </div>
                </div>
              </div>

              <div className="mt-auto pt-8 border-t border-white/5 flex flex-col sm:flex-row items-center justify-between gap-4">
                 {error && <p className="text-red-400 text-[10px] font-bold uppercase">{error}</p>}
                 <button
                    onClick={handleSave}
                    disabled={isSaving}
                    className="w-full sm:w-auto px-10 py-4 bg-brand-primary text-brand-bg-dark font-black rounded-2xl hover:bg-brand-primary-hover transition-all active:scale-95 shadow-xl shadow-brand-primary/10 uppercase tracking-widest text-xs disabled:opacity-50"
                  >
                    {isSaving ? 'Processing...' : 'Save Changes'}
                  </button>
              </div>
            </div>
          ) : (
            <div className="flex-grow flex flex-col space-y-8">
              <div className="space-y-4">
                <div className="flex items-center gap-2">
                   <div className="h-1 w-8 bg-brand-primary rounded-full"></div>
                   <span className="text-[10px] font-black uppercase tracking-[0.3em] text-brand-text-secondary">Marketplace Listing</span>
                </div>
                <h2 className="text-3xl sm:text-5xl font-extrabold text-white leading-tight tracking-tight">
                  {item.title}
                </h2>
              </div>

              <p className="text-brand-text-secondary text-base sm:text-lg leading-relaxed font-medium">
                {item.description}
              </p>

              <div className="mt-auto pt-10 border-t border-white/5">
                 <div className="flex flex-col sm:flex-row sm:items-end justify-between gap-6">
                    <div className="space-y-1">
                       <span className="text-[10px] uppercase tracking-widest font-black text-brand-text-secondary">Current Valuation</span>
                       <div className="text-4xl sm:text-6xl font-black text-brand-primary drop-shadow-[0_0_20px_rgba(34,211,238,0.2)]">
                         ${item.price.toFixed(2)}
                       </div>
                    </div>
                    <button 
                      onClick={onClose}
                      className="group flex items-center gap-2 px-8 py-4 bg-white/5 hover:bg-white/10 rounded-2xl text-white text-xs font-black uppercase tracking-widest transition-all border border-white/10"
                    >
                      Return to Gallery
                      <XIcon className="h-3 w-3 group-hover:rotate-90 transition-transform" />
                    </button>
                 </div>
              </div>
            </div>
          )}
        </div>
      </div>
      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.05); border-radius: 10px; }
      `}</style>
    </div>
  );
};

export default ItemModal;

import React, { useRef } from 'react';
import { UploadIcon } from './IconComponents';

interface FileUploadProps {
  onImageUpload: (file: File) => void;
  isLoading: boolean;
}

const FileUpload: React.FC<FileUploadProps> = ({ onImageUpload, isLoading }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    if (event.target.files && event.target.files[0]) {
      onImageUpload(event.target.files[0]);
      event.target.value = '';
    }
  };

  return (
    <div className="w-full max-w-2xl mx-auto px-4">
      <input
        type="file"
        ref={fileInputRef}
        onChange={handleFileChange}
        className="hidden"
        accept="image/png, image/jpeg, image/webp"
        disabled={isLoading}
      />
      <button
        onClick={() => fileInputRef.current?.click()}
        disabled={isLoading}
        className="relative group w-full overflow-hidden rounded-[2.5rem] bg-brand-bg-light border border-white/10 hover:border-brand-primary/40 transition-all duration-500 hover:shadow-2xl hover:shadow-brand-primary/10"
      >
        <div className="absolute inset-0 bg-gradient-to-br from-brand-primary/5 to-transparent opacity-0 group-hover:opacity-100 transition-opacity"></div>

        <div className="relative flex flex-col items-center justify-center p-8 sm:p-12 text-center">
          <div className="mb-6 relative">
             <div className="absolute inset-0 bg-brand-primary/20 blur-2xl rounded-full scale-0 group-hover:scale-100 transition-transform duration-500"></div>
             <div className="relative bg-brand-bg-dark border border-white/10 p-4 rounded-2xl group-hover:border-brand-primary/30 group-hover:text-brand-primary transition-all duration-300">
               <UploadIcon className={`h-8 w-8 sm:h-10 sm:w-10 ${isLoading ? 'animate-bounce' : 'group-hover:-translate-y-1 transition-transform'}`} />
             </div>
          </div>

          <span className="text-lg sm:text-xl font-extrabold text-white mb-2">
            {isLoading ? 'Aura AI is Analyzing...' : 'Begin New Listing'}
          </span>
          <p className="text-sm text-brand-text-secondary max-w-xs font-medium">
