import React, { useState, useEffect, useMemo } from 'react';
import { Item } from './types';
import { generateItemDetails } from './services/geminiService';
import { resizeAndCompressImage } from './utils/fileUtils';
import { getAllItems, saveItem, deleteItemFromDB } from './utils/dbUtils';
import Header from './components/Header';
import ItemList from './components/ItemList';
import FileUpload from './components/FileUpload';
import Spinner from './components/Spinner';
import ItemModal from './components/ItemModal';
import { SearchIcon, TagIcon } from './components/IconComponents';

const App: React.FC = () => {
  const [items, setItems] = useState<Item[]>([]);
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [isInitializing, setIsInitializing] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);
  const [isEditMode, setIsEditMode] = useState<boolean>(false); // Default to View mode for polished landing
  const [selectedItem, setSelectedItem] = useState<Item | null>(null);
  const [searchQuery, setSearchQuery] = useState<string>('');

  const loadData = async () => {
    try {
      const data = await getAllItems();
      setItems(data);
      setError(null);
    } catch (e: any) {
      console.error("Data fetch failed", e);
      setError(`Sync Error: ${e.message || "Please check database configuration and connectivity."}`);
    } finally {
      setIsInitializing(false);
    }
  };

  useEffect(() => {
    loadData();
  }, []);

  const filteredItems = useMemo(() => {
    const query = searchQuery.toLowerCase().trim();
    if (!query) return items;
    return items.filter(item => 
      item.title.toLowerCase().includes(query) || 
      item.description.toLowerCase().includes(query)
    );
  }, [items, searchQuery]);

  const handleImageUpload = async (file: File) => {
    setIsLoading(true);
    setError(null);
    try {
      const { base64, mimeType } = await resizeAndCompressImage(file);
      const details = await generateItemDetails(base64, mimeType);

      const newItem: Item = {
        id: crypto.randomUUID(),
        imageUrl: `data:${mimeType};base64,${base64}`,
        ...details,
        price: 0,
      };

      await saveItem(newItem);
      setItems(prev => [newItem, ...prev]);
    } catch (err: any) {
      console.error(err);
      setError(err.message || "Operation failed. Check logs for details.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleUpdateItem = async (updatedItem: Item) => {
    try {
      await saveItem(updatedItem);
      setItems(items.map(item => item.id === updatedItem.id ? updatedItem : item));
      setError(null);
    } catch (e: any) {
      setError(`Update Failed: ${e.message}`);
      throw e; 
    }
  };

  const handleDeleteItem = async (id: string) => {
    try {
      await deleteItemFromDB(id);
      setItems(items.filter(item => item.id !== id));
      setError(null);
    } catch (e: any) {
      setError(`Delete Failed: ${e.message}`);
    }
  };

  if (isInitializing) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-brand-bg-dark">
        <div className="flex flex-col items-center">
          <Spinner />
          <div className="mt-8 flex flex-col items-center gap-1">
             <span className="text-[10px] uppercase tracking-[0.4em] font-black text-brand-primary animate-pulse">Establishing Secure Stream</span>
             <span className="text-xs text-brand-text-secondary font-medium">Aura Marketplace v1.4.0</span>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-brand-bg-dark font-sans pb-20 selection:bg-brand-primary/20">
      <Header 
        isEditMode={isEditMode} 
        onToggleEditMode={() => setIsEditMode(!isEditMode)} 
        searchQuery={searchQuery}
        onSearchChange={setSearchQuery}
        isSyncError={!!error}
      />

      <main className="container mx-auto px-6 py-10 sm:py-16">

        {/* Dynamic Section Header */}
        <div className="flex flex-col md:flex-row md:items-end justify-between mb-12 gap-8">
           <div className="space-y-4">
              <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-brand-primary/10 border border-brand-primary/20">
                <TagIcon className="h-3 w-3 text-brand-primary" />
                <span className="text-[10px] font-black uppercase tracking-widest text-brand-primary">Curated Inventory</span>
              </div>
              <h2 className="text-4xl sm:text-6xl font-black text-white tracking-tight">
                {isEditMode ? 'Manage Store' : 'Featured Gallery'}
              </h2>
              <p className="text-brand-text-secondary max-w-lg font-medium">
                {isEditMode 
                  ? 'Update your product listings, set competitive pricing, and let AI streamline your catalog management.' 
                  : 'Discover a hand-picked collection of premium items analyzed and verified by Aura AI intelligence.'}
              </p>
           </div>

           {!isEditMode && items.length > 0 && (
             <div className="hidden sm:flex items-center gap-3 glass-card px-6 py-3 rounded-2xl">
                <div className="flex flex-col text-right">
                   <span className="text-[10px] font-black uppercase tracking-widest text-brand-text-secondary">Total Inventory</span>
                   <span className="text-xl font-bold text-white leading-none">{items.length} Units</span>
                </div>
             </div>
           )}
        </div>

        {isEditMode && (
          <div className="mb-16">
            <FileUpload onImageUpload={handleImageUpload} isLoading={isLoading} />
          </div>
        )}

        {error && (
          <div className="max-w-2xl mx-auto mb-10 p-6 glass-card border-red-500/20 bg-red-500/5 rounded-[2rem] flex items-center gap-4">
            <div className="bg-red-500/10 p-2 rounded-xl text-red-400">
               <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg>
            </div>
            <div>
              <p className="font-black uppercase tracking-[0.2em] text-[10px] text-red-400">System Notification</p>
              <p className="text-sm text-red-200/70 font-medium">{error}</p>
            </div>
          </div>
        )}

        {filteredItems.length > 0 ? (
          <ItemList 
            items={filteredItems} 
            onUpdateItem={handleUpdateItem} 
            onDeleteItem={handleDeleteItem} 
            onSelectItem={setSelectedItem} 
            isEditMode={isEditMode} 
          />
        ) : !isLoading && (
          <div className="text-center py-32 flex flex-col items-center">
            <div className="w-24 h-24 bg-white/5 border border-white/5 rounded-full flex items-center justify-center mb-8 animate-float">
               <SearchIcon className="h-10 w-10 text-brand-text-secondary" />
            </div>
            <h3 className="text-2xl font-bold text-white mb-2 tracking-tight">Zero Results Found</h3>
            <p className="text-brand-text-secondary max-w-xs font-medium mx-auto">
              We couldn't find any matches for your current search or mode. Try changing your filters or add items in Admin Mode.
            </p>
            {isEditMode && (
              <button 
                onClick={() => setSearchQuery('')}
                className="mt-8 text-brand-primary text-xs font-black uppercase tracking-widest hover:underline"
              >
                Clear all filters
              </button>
            )}
          </div>
        )}
      </main>

      {selectedItem && (
        <ItemModal 
          item={selectedItem} 
          onClose={() => setSelectedItem(null)} 
          isEditMode={isEditMode}
          onUpdateItem={handleUpdateItem}
        />
      )}
    </div>
  );
};

export default App;

