import React, { useState, useEffect, useRef } from 'react';
import { Item } from '../types';
import { PencilIcon, TrashIcon } from './IconComponents';

interface ItemCardProps {
  item: Item;
  onUpdateItem: (item: Item) => void;
  onDeleteItem: (id: string) => void;
  onSelectItem: (item: Item) => void;
  isEditMode: boolean;
}

const ItemCard: React.FC<ItemCardProps> = ({ item, onUpdateItem, onDeleteItem, onSelectItem, isEditMode }) => {
  const [isEditingPrice, setIsEditingPrice] = useState(false);
  const [price, setPrice] = useState(item.price.toFixed(2));

  const priceInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (isEditingPrice && priceInputRef.current) {
      priceInputRef.current.select();
    }
  }, [isEditingPrice]);

  useEffect(() => {
    setPrice(item.price.toFixed(2));
  }, [item]);

  const handlePriceUpdate = () => {
    const newPrice = parseFloat(price);
    if (!isNaN(newPrice) && newPrice >= 0) {
      onUpdateItem({ ...item, price: newPrice });
      setPrice(newPrice.toFixed(2));
    } else {
      setPrice(item.price.toFixed(2));
    }
    setIsEditingPrice(false);
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter') handlePriceUpdate();
    if (e.key === 'Escape') {
      setPrice(item.price.toFixed(2));
      setIsEditingPrice(false);
    }
  };

  const handleDeleteClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    onDeleteItem(item.id);
  }

  const handlePriceEditClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    setIsEditingPrice(true);
  }

  return (
    <div 
      className="group relative flex flex-col glass-card rounded-[2.5rem] overflow-hidden transition-all duration-500 hover:shadow-2xl hover:shadow-brand-primary/5 hover:-translate-y-2 cursor-pointer border border-white"
      onClick={() => onSelectItem(item)}
    >
      {/* Image Container */}
      <div className="relative aspect-[4/5] overflow-hidden bg-slate-50">
        <img
          src={item.imageUrl}
          alt={item.title}
          className="w-full h-full object-cover transition-transform duration-1000 group-hover:scale-110"
          loading="lazy"
        />
        <div className="absolute inset-0 bg-gradient-to-t from-white/40 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-500"></div>

        {/* Hover Overlay */}
        <div className="absolute inset-0 flex flex-col items-center justify-center opacity-0 group-hover:opacity-100 transition-all duration-500 bg-white/10 backdrop-blur-[4px]">
          <span className="bg-brand-primary/80 backdrop-blur-xl px-5 py-2.5 rounded-full text-[10px] font-black uppercase tracking-[0.2em] text-white shadow-xl shadow-brand-primary/20">
            Explore Item
          </span>
        </div>

        {isEditMode && (
          <button
            onClick={handleDeleteClick}
            className="absolute top-5 right-5 bg-red-500/90 hover:bg-red-600 text-white p-2.5 rounded-full transition-all duration-300 backdrop-blur-md shadow-lg opacity-0 translate-y-2 group-hover:opacity-100 group-hover:translate-y-0 z-10"
            aria-label="Delete item"
          >
            <TrashIcon className="h-4 w-4" />
          </button>
        )}
      </div>

      {/* Info Container */}
      <div className="p-6 flex flex-col flex-grow bg-white/20">
        <h3 className="text-sm sm:text-base font-bold text-brand-text mb-3 line-clamp-2 leading-snug group-hover:text-brand-primary transition-colors">
          {item.title}
        </h3>

        <div className="mt-auto flex items-end justify-between">
          <div className="flex flex-col">
            <span className="text-[9px] uppercase tracking-widest font-black text-brand-text-secondary/70 mb-1">Pricing</span>
            {isEditMode && isEditingPrice ? (
              <div className="flex items-center" onClick={(e) => e.stopPropagation()}>
                <span className="text-brand-primary text-base mr-1 font-bold">$</span>
                <input
                  ref={priceInputRef}
                  type="number"
                  value={price}
                  onChange={(e) => setPrice(e.target.value)}
                  onBlur={handlePriceUpdate}
                  onKeyDown={handleKeyDown}
                  className="bg-white text-brand-text text-base font-bold w-20 rounded-xl px-2 py-1 outline-none ring-2 ring-brand-primary/20 border border-brand-primary"
                  min="0"
                  step="0.01"
                />
              </div>
            ) : (
              <div className="flex items-center gap-1.5">
                <span className="text-lg sm:text-xl font-extrabold text-brand-text tracking-tight">
                  <span className="text-brand-primary/60 text-sm mr-0.5">$</span>
                  {item.price.toFixed(2)}
                </span>
                {isEditMode && (
                  <button 
                    onClick={handlePriceEditClick}
                    className="p-1.5 text-brand-text-secondary hover:text-brand-primary hover:bg-brand-primary/5 rounded-lg transition-all"
                  >
                    <PencilIcon className="h-3 w-3" />
                  </button>
                )}
              </div>
            )}
          </div>

          <div className="w-10 h-10 rounded-2xl bg-slate-50 border border-slate-100 flex items-center justify-center group-hover:bg-brand-primary group-hover:border-brand-primary transition-all duration-500 shadow-sm">
             <div className="w-1.5 h-1.5 rounded-full bg-brand-primary group-hover:bg-white transition-colors"></div>
          </div>
        </div>
      </div>
    </div>
  );
};

