                    <label className="text-[11px] font-black uppercase tracking-widest text-brand-text-secondary/80 ml-1">Listing Price ($)</label>
                    <div className="relative">
                      <span className="absolute left-6 top-1/2 -translate-y-1/2 text-brand-primary font-bold">$</span>
                      <input
