import React, { useState, useEffect, useMemo } from 'react';
import { Item } from './types';
import { generateItemDetails } from './services/geminiService';
import { resizeAndCompressImage } from './utils/fileUtils';
import { getAllItems, saveItem, deleteItemFromDB } from './utils/dbUtils';
import Header from './components/Header';
import ItemList from './components/ItemList';
import FileUpload from './components/FileUpload';
import Spinner from './components/Spinner';
import ItemModal from './components/ItemModal';
import { SearchIcon, TagIcon } from './components/IconComponents';

const App: React.FC = () => {
  const [items, setItems] = useState<Item[]>([]);
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [isInitializing, setIsInitializing] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);
  const [isEditMode, setIsEditMode] = useState<boolean>(false); 
  const [selectedItem, setSelectedItem] = useState<Item | null>(null);
  const [searchQuery, setSearchQuery] = useState<string>('');

  const loadData = async () => {
    try {
      const data = await getAllItems();
      setItems(data);
      setError(null);
    } catch (e: any) {
      console.error("Data fetch failed", e);
      setError(`Sync Error: ${e.message || "Please check database configuration and connectivity."}`);
    } finally {
      setIsInitializing(false);
    }
  };

  useEffect(() => {
    loadData();
  }, []);

  const filteredItems = useMemo(() => {
    const query = searchQuery.toLowerCase().trim();
    if (!query) return items;
    return items.filter(item => 
      item.title.toLowerCase().includes(query) || 
      item.description.toLowerCase().includes(query)
    );
  }, [items, searchQuery]);

  const handleImageUpload = async (file: File) => {
    setIsLoading(true);
    setError(null);
    try {
      const { base64, mimeType } = await resizeAndCompressImage(file);
      const details = await generateItemDetails(base64, mimeType);

      const newItem: Item = {
        id: crypto.randomUUID(),
        imageUrl: `data:${mimeType};base64,${base64}`,
        ...details,
        price: 0,
      };

      await saveItem(newItem);
      setItems(prev => [newItem, ...prev]);
    } catch (err: any) {
      console.error(err);
      setError(err.message || "Operation failed. Check logs for details.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleUpdateItem = async (updatedItem: Item) => {
    try {
      await saveItem(updatedItem);
      setItems(items.map(item => item.id === updatedItem.id ? updatedItem : item));
      setError(null);
    } catch (e: any) {
      setError(`Update Failed: ${e.message}`);
      throw e; 
    }
  };

  const handleDeleteItem = async (id: string) => {
    try {
      await deleteItemFromDB(id);
      setItems(items.filter(item => item.id !== id));
      setError(null);
    } catch (e: any) {
      setError(`Delete Failed: ${e.message}`);
    }
  };

  if (isInitializing) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-brand-bg-dark">
        <div className="flex flex-col items-center">
          <Spinner />
          <div className="mt-10 flex flex-col items-center gap-1.5">
             <span className="text-[11px] uppercase tracking-[0.5em] font-black text-brand-primary animate-pulse">Initializing Ecosystem</span>
             <span className="text-[10px] text-brand-text-secondary/60 font-bold tracking-widest uppercase">Aura AI Marketplace v1.4.0</span>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-brand-bg-dark font-sans pb-24 selection:bg-brand-primary/10">
      <Header 
        isEditMode={isEditMode} 
        onToggleEditMode={() => setIsEditMode(!isEditMode)} 
        searchQuery={searchQuery}
        onSearchChange={setSearchQuery}
        isSyncError={!!error}
      />

      <main className="container mx-auto px-6 py-12 sm:py-20">

        {/* Dynamic Section Header */}
        <div className="flex flex-col md:flex-row md:items-end justify-between mb-16 gap-10">
           <div className="space-y-6">
              <div className="inline-flex items-center gap-2.5 px-4 py-1.5 rounded-full bg-white border border-slate-100 shadow-sm">
                <TagIcon className="h-3.5 w-3.5 text-brand-primary" />
                <span className="text-[11px] font-black uppercase tracking-[0.2em] text-brand-primary">Curated Registry</span>
              </div>
              <h2 className="text-4xl sm:text-7xl font-black text-brand-text tracking-tightest">
                {isEditMode ? 'Manage Stock' : 'Market Gallery'}
              </h2>
              <p className="text-brand-text-secondary text-lg max-w-xl font-medium leading-relaxed">
                {isEditMode 
                  ? 'Refine your storefront. Upload, verify, and price your items using the integrated Aura Vision AI.' 
                  : 'A curated selection of verified listings. Every item is analyzed for description accuracy and authenticity.'}
              </p>
           </div>

           {!isEditMode && items.length > 0 && (
             <div className="hidden sm:flex items-center gap-4 glass-card px-8 py-5 rounded-[2rem]">
                <div className="flex flex-col text-right">
                   <span className="text-[11px] font-black uppercase tracking-widest text-brand-text-secondary/60 mb-1">Stock Count</span>
                   <span className="text-2xl font-black text-brand-text leading-none">{items.length} <span className="text-sm font-bold text-brand-primary/50">Units</span></span>
                </div>
             </div>
           )}
        </div>

        {isEditMode && (
          <div className="mb-20 animate-in fade-in slide-in-from-top-4 duration-700">
            <FileUpload onImageUpload={handleImageUpload} isLoading={isLoading} />
          </div>
        )}

        {error && (
          <div className="max-w-3xl mx-auto mb-12 p-8 glass-card border-red-200 bg-red-50/30 rounded-[2.5rem] flex items-center gap-6 animate-in slide-in-from-bottom-2">
            <div className="bg-red-100 p-3 rounded-2xl text-red-500 shadow-sm">
               <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg>
            </div>
            <div>
              <p className="font-black uppercase tracking-[0.3em] text-[10px] text-red-500/80 mb-1">System Exception</p>
              <p className="text-base text-red-900 font-bold leading-tight">{error}</p>
            </div>
          </div>
        )}

        {filteredItems.length > 0 ? (
          <div className="animate-in fade-in duration-1000">
            <ItemList 
              items={filteredItems} 
              onUpdateItem={handleUpdateItem} 
              onDeleteItem={handleDeleteItem} 
              onSelectItem={setSelectedItem} 
              isEditMode={isEditMode} 
            />
          </div>
        ) : !isLoading && (
          <div className="text-center py-40 flex flex-col items-center animate-in fade-in zoom-in duration-700">
            <div className="w-28 h-28 bg-white border border-slate-100 rounded-[2.5rem] flex items-center justify-center mb-10 animate-float shadow-xl shadow-slate-200/50">
               <SearchIcon className="h-10 w-10 text-brand-text-secondary/40" />
            </div>
            <h3 className="text-3xl font-black text-brand-text mb-3 tracking-tight">Ecosystem Empty</h3>
            <p className="text-brand-text-secondary text-lg max-w-md font-medium mx-auto leading-relaxed">
              No results found for your inquiry. Try broadening your search terms or populate the market in Admin Mode.
            </p>
            {searchQuery && (
              <button 
                onClick={() => setSearchQuery('')}
                className="mt-10 px-8 py-3 bg-slate-100 text-brand-text text-xs font-black uppercase tracking-widest hover:bg-slate-200 rounded-2xl transition-all active:scale-95"
              >
                Reset Environment
              </button>
            )}
          </div>
        )}
      </main>

      {selectedItem && (
        <ItemModal 
          item={selectedItem} 
          onClose={() => setSelectedItem(null)} 
          isEditMode={isEditMode}
          onUpdateItem={handleUpdateItem}
        />
      )}
    </div>
  );
};

export default App;

