interface HeaderProps {
  isEditMode: boolean;
  onToggleEditMode: () => void;
  searchQuery: string;
  onSearchChange: (query: string) => void;
  isSyncError?: boolean;
}

const Header: React.FC<HeaderProps> = ({ 
  isEditMode, 
  onToggleEditMode, 
  searchQuery, 
  onSearchChange,
  isSyncError = false
}) => {
  const [isSearchOpen, setIsSearchOpen] = useState(false);
  const searchInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (isSearchOpen && searchInputRef.current) {
      searchInputRef.current.focus();
    }
  }, [isSearchOpen]);

  const handleClearSearch = () => {
    onSearchChange('');
    if (searchInputRef.current) {
      searchInputRef.current.focus();
    }
  };

  return (
    <header className="sticky top-0 z-40 w-full glass-card border-b border-white/5 px-6 h-20 sm:h-24 transition-all duration-500">
      <div className="container mx-auto max-w-7xl h-full flex justify-between items-center gap-6">

        {/* Brand */}
        <div className={`flex items-center gap-3 sm:gap-4 transition-all duration-500 ${isSearchOpen && window.innerWidth < 640 ? 'opacity-0 scale-90 w-0' : 'opacity-100 scale-100'}`}>
          <div className="relative group">
            <div className="absolute inset-0 bg-brand-primary/20 blur-lg rounded-full opacity-0 group-hover:opacity-100 transition-opacity"></div>
            <div className="relative bg-brand-primary/10 p-2.5 rounded-[1.25rem] border border-brand-primary/20 group-hover:border-brand-primary/50 transition-all shadow-lg">
              <TagIcon className="h-6 w-6 sm:h-7 sm:w-7 text-brand-primary" />
            </div>
          </div>
          <div className="flex flex-col">
            <h1 className="text-lg sm:text-2xl font-black text-white tracking-tight leading-none">
              AURA <span className="text-brand-primary italic">INV</span>
            </h1>
            <div className="flex items-center mt-1.5">
              <span className={`w-1.5 h-1.5 rounded-full ${isSyncError ? 'bg-red-500 animate-pulse' : 'bg-brand-primary shadow-[0_0_8px_rgba(34,211,238,0.8)]'} mr-2`} />
              <span className="text-[9px] uppercase tracking-[0.3em] font-black text-brand-text-secondary/70">
                {isSyncError ? 'Connection Error' : 'Neural Link Active'}
              </span>
            </div>
          </div>
        </div>

        {/* Dynamic Search Area */}
        <div className={`flex-grow flex items-center justify-end transition-all duration-500 ${isSearchOpen ? 'sm:max-w-lg' : 'sm:max-w-sm'}`}>
          <div className={`relative w-full transition-all duration-500 flex items-center ${isSearchOpen ? 'opacity-100' : 'hidden sm:flex opacity-60 hover:opacity-100'}`}>
             <div className="absolute left-5 text-brand-primary pointer-events-none">
                <SearchIcon className="h-4 w-4" />
             </div>
             <input
                ref={searchInputRef}
                type="text"
                value={searchQuery}
                onChange={(e) => onSearchChange(e.target.value)}
                placeholder="Query database..."
                className="w-full bg-black/40 border border-white/10 text-white pl-12 pr-12 py-3 sm:py-3.5 rounded-2xl focus:outline-none focus:border-brand-primary/50 focus:ring-4 focus:ring-brand-primary/10 transition-all text-sm font-semibold placeholder:text-brand-text-secondary/40 backdrop-blur-md"
              />
              {searchQuery && (
                <button 
                  onClick={handleClearSearch}
                  className="absolute right-4 p-1.5 text-brand-text-secondary hover:text-brand-primary transition-colors bg-white/5 rounded-lg"
                >
                  <XIcon className="h-3 w-3" />
                </button>
              )}
          </div>

          <button 
            onClick={() => setIsSearchOpen(!isSearchOpen)}
            className={`p-3 sm:hidden text-brand-text-secondary hover:text-brand-primary transition-colors bg-white/5 rounded-xl ${isSearchOpen ? 'hidden' : 'block'}`}
          >
            <SearchIcon className="h-6 w-6" />
          </button>

          {isSearchOpen && (
            <button 
              onClick={() => setIsSearchOpen(false)}
              className="p-3 sm:hidden text-brand-text-secondary ml-3 bg-white/5 rounded-xl"
            >
              <XIcon className="h-6 w-6" />
            </button>
          )}
        </div>

        {/* Admin Toggle */}
        <div className={`shrink-0 transition-all duration-500 ${isSearchOpen && window.innerWidth < 640 ? 'opacity-0 scale-90 w-0' : 'opacity-100 scale-100'}`}>
          <button
            onClick={onToggleEditMode}
            className={`group flex items-center gap-3 px-4 py-3 sm:px-6 sm:py-3.5 rounded-2xl text-xs sm:text-sm font-black transition-all shadow-xl active:scale-95 ${
              isEditMode 
              ? 'bg-brand-primary text-brand-bg-dark shadow-[0_0_30px_rgba(34,211,238,0.2)] hover:shadow-[0_0_40px_rgba(34,211,238,0.4)]' 
              : 'bg-white/5 border border-white/10 text-brand-text-secondary hover:text-white hover:bg-white/10 hover:border-white/20'
            }`}
          >
            {isEditMode ? <PencilIcon className="h-4 w-4" /> : <EyeIcon className="h-4 w-4" />}
            <span className="hidden lg:inline uppercase tracking-[0.3em]">{isEditMode ? 'Terminal' : 'Gallery'}</span>
          </button>
        </div>
      </div>
    </header>
  );
};

export default Header;

import React, { useState, useEffect, useRef } from 'react';
import { Item } from '../types';
import { PencilIcon, TrashIcon } from './IconComponents';

interface ItemCardProps {
  item: Item;
  onUpdateItem: (item: Item) => void;
  onDeleteItem: (id: string) => void;
  onSelectItem: (item: Item) => void;
  isEditMode: boolean;
}

const ItemCard: React.FC<ItemCardProps> = ({ item, onUpdateItem, onDeleteItem, onSelectItem, isEditMode }) => {
  const [isEditingPrice, setIsEditingPrice] = useState(false);
  const [price, setPrice] = useState(item.price.toFixed(2));

  const priceInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (isEditingPrice && priceInputRef.current) {
      priceInputRef.current.select();
    }
  }, [isEditingPrice]);

  useEffect(() => {
    setPrice(item.price.toFixed(2));
  }, [item]);

  const handlePriceUpdate = () => {
    const newPrice = parseFloat(price);
    if (!isNaN(newPrice) && newPrice >= 0) {
      onUpdateItem({ ...item, price: newPrice });
      setPrice(newPrice.toFixed(2));
    } else {
      setPrice(item.price.toFixed(2));
    }
    setIsEditingPrice(false);
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter') handlePriceUpdate();
    if (e.key === 'Escape') {
      setPrice(item.price.toFixed(2));
      setIsEditingPrice(false);
    }
  };

  const handleDeleteClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    onDeleteItem(item.id);
  }

  const handlePriceEditClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    setIsEditingPrice(true);
  }

  return (
    <div 
      className="group relative flex flex-col glass-card rounded-[2.5rem] overflow-hidden transition-all duration-700 hover:shadow-[0_20px_60px_rgba(0,0,0,0.8),0_0_40px_rgba(34,211,238,0.1)] hover:-translate-y-4 cursor-pointer border-white/5 hover:border-brand-primary/30"
      onClick={() => onSelectItem(item)}
    >
      {/* Image Container */}
      <div className="relative aspect-[4/5] overflow-hidden bg-black/40">
        <img
          src={item.imageUrl}
          alt={item.title}
          className="w-full h-full object-cover transition-transform duration-[2000ms] ease-out group-hover:scale-125 opacity-80 group-hover:opacity-100"
          loading="lazy"
        />
        <div className="absolute inset-0 bg-gradient-to-t from-brand-bg-dark via-transparent to-transparent opacity-80"></div>

        {/* Hover Overlay */}
        <div className="absolute inset-0 flex flex-col items-center justify-center opacity-0 group-hover:opacity-100 transition-all duration-700 bg-brand-bg-dark/20 backdrop-blur-[2px]">
          <div className="absolute inset-0 bg-brand-primary/5 group-hover:animate-pulse"></div>
          <span className="relative z-10 bg-brand-primary text-brand-bg-dark font-black px-6 py-3 rounded-2xl text-[10px] uppercase tracking-[0.4em] shadow-2xl shadow-brand-primary/40 translate-y-4 group-hover:translate-y-0 transition-transform duration-500">
            Scan Details
          </span>
        </div>

        {isEditMode && (
          <button
            onClick={handleDeleteClick}
            className="absolute top-6 right-6 bg-red-500/80 hover:bg-red-600 text-white p-3 rounded-2xl transition-all duration-500 backdrop-blur-xl shadow-2xl opacity-0 translate-x-4 group-hover:opacity-100 group-hover:translate-x-0 z-20 border border-white/10"
            aria-label="Delete item"
          >
            <TrashIcon className="h-4 w-4" />
          </button>
        )}
      </div>

      {/* Info Container */}
      <div className="p-7 flex flex-col flex-grow bg-gradient-to-b from-white/[0.03] to-transparent">
        <h3 className="text-sm sm:text-base font-bold text-white mb-5 line-clamp-2 leading-tight group-hover:text-brand-primary transition-colors tracking-tight">
          {item.title}
        </h3>

        <div className="mt-auto flex items-end justify-between">
          <div className="flex flex-col">
            <span className="text-[9px] uppercase tracking-[0.3em] font-black text-brand-primary/60 mb-2">Valuation</span>
            {isEditMode && isEditingPrice ? (
              <div className="flex items-center" onClick={(e) => e.stopPropagation()}>
                <span className="text-brand-primary text-lg mr-1 font-black">$</span>
                <input
                  ref={priceInputRef}
                  type="number"
                  value={price}
                  onChange={(e) => setPrice(e.target.value)}
                  onBlur={handlePriceUpdate}
                  onKeyDown={handleKeyDown}
                  className="bg-brand-bg-dark text-white text-lg font-black w-24 rounded-xl px-2 py-1 outline-none ring-2 ring-brand-primary shadow-[0_0_20px_rgba(34,211,238,0.2)] border border-brand-primary/50"
                  min="0"
                  step="0.01"
                />
              </div>
            ) : (
              <div className="flex items-center gap-2 group/price">
                <span className="text-xl sm:text-2xl font-black text-white tracking-tighter flex items-start">
                  <span className="text-xs text-brand-primary mt-1 mr-1 font-bold">$</span>
                  {item.price.toFixed(2)}
                </span>
                {isEditMode && (
                  <button 
                    onClick={handlePriceEditClick}
                    className="p-1.5 text-brand-text-secondary hover:text-brand-primary hover:bg-white/5 rounded-lg transition-all"
                  >
                    <PencilIcon className="h-3 w-3" />
                  </button>
                )}
              </div>
            )}
          </div>

          <div className="w-12 h-12 rounded-[1.25rem] bg-white/5 border border-white/10 flex items-center justify-center group-hover:bg-brand-primary group-hover:border-brand-primary transition-all duration-500 shadow-inner">
             <div className="w-2 h-2 rounded-full bg-brand-primary group-hover:bg-brand-bg-dark transition-all duration-300 animate-pulse"></div>
          </div>
        </div>
      </div>

      {/* Decorative Corner Accent */}
      <div className="absolute bottom-0 right-0 w-8 h-8 opacity-20 pointer-events-none">
        <div className="absolute bottom-4 right-4 w-px h-4 bg-brand-primary"></div>
        <div className="absolute bottom-4 right-4 h-px w-4 bg-brand-primary"></div>
      </div>
    </div>
  );
};

export default ItemCard;

import React, { useState, useEffect } from 'react';
import { Item } from '../types';
import { XIcon, PencilIcon } from './IconComponents';

interface ItemModalProps {
  item: Item;
  onClose: () => void;
  isEditMode: boolean;
  onUpdateItem: (item: Item) => Promise<void>;
}

const ItemModal: React.FC<ItemModalProps> = ({ item, onClose, isEditMode, onUpdateItem }) => {
  const [isSaving, setIsSaving] = useState(false);
  const [editedItem, setEditedItem] = useState<Item>({ ...item });
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    setEditedItem({ ...item });
  }, [item]);

  const handleSave = async () => {
    if (!editedItem.title.trim()) {
      setError("Title is required");
      return;
    }

    setIsSaving(true);
    setError(null);
    try {
      await onUpdateItem(editedItem);
      onClose();
    } catch (err: any) {
      setError(err.message || "Failed to save changes");
      setIsSaving(false);
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setEditedItem(prev => ({
      ...prev,
      [name]: name === 'price' ? parseFloat(value) || 0 : value
    }));
  };

  return (
    <div
      role="dialog"
      aria-modal="true"
      className="fixed inset-0 z-50 flex items-end sm:items-center justify-center p-4 sm:p-8"
    >
      <div 
        className="fixed inset-0 bg-black/80 backdrop-blur-3xl transition-opacity animate-in fade-in duration-500"
        onClick={onClose}
      ></div>

      <div className="relative z-10 w-full max-w-6xl glass-modal sm:rounded-[4rem] shadow-[0_40px_120px_-16px_rgba(0,0,0,1)] overflow-hidden animate-in zoom-in-95 slide-in-from-bottom-20 duration-700 flex flex-col lg:flex-row h-full sm:h-auto sm:max-h-[90vh]">

        {/* Left: Media Area */}
        <div className="relative w-full lg:w-[55%] shrink-0 h-72 sm:h-96 lg:h-auto bg-black flex items-center justify-center overflow-hidden">
          <div className="absolute inset-0 opacity-20 blur-3xl scale-150 animate-pulse bg-brand-primary/20"></div>
          <img
            src={item.imageUrl}
            alt={item.title}
            className="relative z-10 w-full h-full object-cover"
          />
          <div className="absolute inset-0 bg-gradient-to-t lg:bg-gradient-to-r from-brand-bg-dark/90 via-transparent to-transparent z-20"></div>

          <button
            onClick={onClose}
            className="absolute top-10 left-10 z-30 bg-white/10 hover:bg-white/20 text-white p-4 rounded-3xl transition-all shadow-2xl backdrop-blur-2xl border border-white/20 group active:scale-90"
            aria-label="Close"
          >
            <XIcon className="h-6 w-6 group-hover:rotate-180 transition-transform duration-500" />
          </button>

          {/* Scanline Effect Overlay */}
          <div className="absolute inset-0 pointer-events-none z-20 opacity-10 bg-[linear-gradient(rgba(18,16,16,0)_50%,rgba(0,0,0,0.25)_50%),linear-gradient(90deg,rgba(255,0,0,0.06),rgba(0,255,0,0.02),rgba(0,0,255,0.06))] bg-[length:100%_2px,3px_100%]"></div>
        </div>

        {/* Right: Details Area */}
        <div className="flex-grow p-10 sm:p-20 overflow-y-auto custom-scrollbar flex flex-col bg-brand-bg-dark/40 relative">
          {/* Subtle Ambient Glow */}
          <div className="absolute top-0 right-0 w-64 h-64 bg-brand-primary/5 blur-[100px] rounded-full -translate-y-1/2 translate-x-1/2"></div>

          {isEditMode ? (
            <div className="relative z-10 space-y-12 flex-grow">
              <div className="flex items-center gap-5">
                 <div className="bg-brand-primary/10 p-4 rounded-[2rem] border border-brand-primary/20 shadow-[0_0_20px_rgba(34,211,238,0.1)]">
                   <PencilIcon className="h-6 w-6 text-brand-primary" />
                 </div>
                 <div>
                    <h3 className="text-[11px] font-black uppercase tracking-[0.5em] text-brand-primary mb-1">Asset Overwrite</h3>
                    <p className="text-lg font-bold text-white tracking-tight">Manual Metadata Intervention</p>
                 </div>
              </div>

              <div className="space-y-10">
                <div className="space-y-4">
                  <label className="text-[12px] font-black uppercase tracking-[0.3em] text-brand-text-secondary/50 ml-1">Asset Identity</label>
                  <input
                    type="text"
                    name="title"
                    value={editedItem.title}
                    onChange={handleChange}
                    className="w-full bg-black/40 text-white text-2xl font-black rounded-3xl px-8 py-5 outline-none border border-white/10 focus:border-brand-primary/50 focus:ring-8 focus:ring-brand-primary/5 transition-all shadow-inner"
                  />
                </div>

                <div className="space-y-4">
                  <label className="text-[12px] font-black uppercase tracking-[0.3em] text-brand-text-secondary/50 ml-1">Archive Entry</label>
                  <textarea
                    name="description"
                    value={editedItem.description}
                    onChange={handleChange}
                    rows={4}
                    className="w-full bg-black/40 text-brand-text-secondary text-lg leading-relaxed rounded-3xl px-8 py-6 outline-none border border-white/10 focus:border-brand-primary/50 focus:ring-8 focus:ring-brand-primary/5 transition-all resize-none shadow-inner"
                  />
                </div>

                <div className="grid grid-cols-1 sm:grid-cols-2 gap-10 pt-4">
                  <div className="space-y-4">
                    <label className="text-[12px] font-black uppercase tracking-[0.3em] text-brand-text-secondary/50 ml-1">Market Valuation</label>
                    <div className="relative group/input">
                      <span className="absolute left-8 top-1/2 -translate-y-1/2 text-brand-primary font-black text-xl">$</span>
                      <input
                        type="number"
                        name="price"
                        value={editedItem.price}
                        onChange={handleChange}
                        step="0.01"
                        className="w-full bg-black/40 text-white text-3xl font-black rounded-3xl pl-16 pr-8 py-6 outline-none border border-white/10 focus:border-brand-primary/50 transition-all shadow-inner"
                      />
                    </div>
                  </div>
                </div>
              </div>

              <div className="mt-auto pt-12 border-t border-white/5 flex flex-col sm:flex-row items-center justify-between gap-8">
                 {error && (
                   <div className="flex items-center gap-2 text-red-500">
                     <span className="w-1.5 h-1.5 rounded-full bg-red-500 animate-ping"></span>
                     <p className="text-[11px] font-black uppercase tracking-widest">{error}</p>
                   </div>
                 )}
                 <div className="flex items-center gap-6 w-full sm:w-auto">
                   <button
                      onClick={onClose}
                      className="flex-1 sm:flex-none px-8 py-5 text-brand-text-secondary font-black hover:text-white transition-colors text-xs uppercase tracking-[0.3em]"
                    >
                      ABORT
                    </button>
                   <button
                      onClick={handleSave}
                      disabled={isSaving}
                      className="flex-1 sm:flex-none px-12 py-5 bg-brand-primary text-brand-bg-dark font-black rounded-[1.5rem] hover:shadow-[0_0_50px_rgba(34,211,238,0.4)] transition-all active:scale-95 uppercase tracking-[0.3em] text-xs disabled:opacity-50"
                    >
                      {isSaving ? 'UPLOADING...' : 'COMMIT CHANGES'}
                    </button>
                 </div>
              </div>
            </div>
          ) : (
            <div className="relative z-10 flex-grow flex flex-col space-y-12">
              <div className="space-y-6">
                <div className="flex items-center gap-4">
                   <div className="h-0.5 w-16 bg-brand-primary shadow-[0_0_10px_rgba(34,211,238,0.8)]"></div>
                   <span className="text-[11px] font-black uppercase tracking-[0.5em] text-brand-primary/60">Asset Information Service</span>
                </div>
                <h2 className="text-5xl sm:text-7xl font-black text-white leading-none tracking-tighter">
                  {item.title}
                </h2>
              </div>

              <div className="relative">
                <div className="absolute -left-6 top-0 bottom-0 w-1 bg-gradient-to-b from-brand-primary/40 to-transparent"></div>
                <p className="text-brand-text-secondary text-xl sm:text-2xl leading-relaxed font-medium opacity-90">
                  {item.description}
                </p>
              </div>

              <div className="mt-auto pt-16 border-t border-white/5">
                 <div className="flex flex-col sm:flex-row sm:items-end justify-between gap-10">
                    <div className="space-y-4">
                       <span className="text-[12px] uppercase tracking-[0.4em] font-black text-brand-text-secondary/40">Current Market Estimate</span>
                       <div className="text-7xl sm:text-9xl font-black text-white tracking-tighter flex items-start animate-in fade-in slide-in-from-left-4 duration-1000">
                         <span className="text-3xl sm:text-4xl text-brand-primary mt-6 mr-3 font-black">$</span>
                         {item.price.toFixed(2)}
                       </div>
                    </div>
                    <button 
                      onClick={onClose}
                      className="group flex items-center justify-center gap-4 px-12 py-6 bg-white/5 hover:bg-white/10 text-white rounded-[2rem] text-[11px] font-black uppercase tracking-[0.4em] transition-all border border-white/10 shadow-2xl active:scale-95"
                    >
                      EJECT VIEW
                      <XIcon className="h-4 w-4 group-hover:rotate-90 transition-transform duration-500" />
                    </button>
                 </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default ItemModal;

import React, { useRef } from 'react';
import { UploadIcon } from './IconComponents';

interface FileUploadProps {
  onImageUpload: (file: File) => void;
  isLoading: boolean;
}

const FileUpload: React.FC<FileUploadProps> = ({ onImageUpload, isLoading }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    if (event.target.files && event.target.files[0]) {
      onImageUpload(event.target.files[0]);
      event.target.value = '';
    }
  };

  return (
    <div className="w-full max-w-4xl mx-auto px-4">
      <input
        type="file"
        ref={fileInputRef}
        onChange={handleFileChange}
        className="hidden"
        accept="image/png, image/jpeg, image/webp"
        disabled={isLoading}
      />
      <button
        onClick={() => fileInputRef.current?.click()}
        disabled={isLoading}
        className="relative group w-full overflow-hidden rounded-[4rem] bg-black/40 border border-white/10 hover:border-brand-primary/40 transition-all duration-700 hover:shadow-[0_0_50px_rgba(34,211,238,0.1)] backdrop-blur-xl"
      >
        {/* Hover Background Animation */}
        <div className="absolute inset-0 bg-gradient-to-br from-brand-primary/[0.05] via-transparent to-brand-primary/[0.02] opacity-0 group-hover:opacity-100 transition-opacity duration-1000"></div>

        {/* Diagonal Scanline Effect */}
        <div className="absolute inset-0 opacity-[0.03] group-hover:opacity-[0.07] transition-opacity pointer-events-none" style={{ backgroundImage: 'repeating-linear-gradient(45deg, #22d3ee 0, #22d3ee 1px, transparent 0, transparent 50%)', backgroundSize: '10px 10px' }}></div>

        <div className="relative flex flex-col items-center justify-center p-16 sm:p-24 text-center">
          <div className="mb-12 relative">
             <div className="absolute inset-0 bg-brand-primary/20 blur-[80px] rounded-full scale-0 group-hover:scale-150 transition-transform duration-1000 animate-pulse"></div>
             <div className="relative bg-white/5 border border-white/10 p-7 rounded-[2.5rem] group-hover:border-brand-primary/40 group-hover:text-brand-primary transition-all duration-700 shadow-2xl group-hover:shadow-[0_0_40px_rgba(34,211,238,0.3)] group-hover:-translate-y-4">
               <UploadIcon className={`h-12 w-12 sm:h-16 sm:w-16 ${isLoading ? 'animate-bounce' : 'group-hover:scale-110 transition-transform'}`} />
             </div>
          </div>

          <span className="text-2xl sm:text-4xl font-black text-white mb-5 tracking-tighter">
            {isLoading ? 'ANALYZING VISUAL DATA...' : 'INITIALIZE ASSET INGESTION'}
          </span>
          <p className="text-lg text-brand-text-secondary max-w-md font-medium mx-auto leading-relaxed opacity-60">
            {isLoading 
              ? 'Our neural network is currently parsing image artifacts, material composition, and branding signatures...' 
              : 'Drag and drop high-resolution captures or browse local storage. Aura Vision™ will handle descriptive mapping.'}
          </p>
        </div>

        {/* Animated Progress bar for loading */}
        {isLoading && (
          <div className="absolute bottom-0 left-0 h-2 bg-white/5 w-full overflow-hidden">
            <div className="h-full bg-brand-primary w-1/3 animate-[shimmer_2s_infinite_ease-in-out] shadow-[0_0_25px_rgba(34,211,238,0.8)]"></div>
          </div>
        )}
      </button>
    </div>
  );
