import React, { useState, useEffect, useRef } from 'react';
import { Item } from '../types';
import { PencilIcon, TrashIcon } from './IconComponents';

interface ItemCardProps {
  item: Item;
  onUpdateItem: (item: Item) => void;
  onDeleteItem: (id: string) => void;
  onSelectItem: (item: Item) => void;
  isEditMode: boolean;
}

const ItemCard: React.FC<ItemCardProps> = ({ item, onUpdateItem, onDeleteItem, onSelectItem, isEditMode }) => {
  const [isEditingPrice, setIsEditingPrice] = useState(false);
  const [price, setPrice] = useState(item.price.toFixed(2));
  const priceInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (isEditingPrice && priceInputRef.current) {
      priceInputRef.current.select();
    }
  }, [isEditingPrice]);

  useEffect(() => {
    setPrice(item.price.toFixed(2));
  }, [item]);

  const handlePriceUpdate = () => {
    const newPrice = parseFloat(price);
    if (!isNaN(newPrice) && newPrice >= 0) {
      onUpdateItem({ ...item, price: newPrice });
      setPrice(newPrice.toFixed(2));
    } else {
      setPrice(item.price.toFixed(2));
    }
    setIsEditingPrice(false);
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter') handlePriceUpdate();
    if (e.key === 'Escape') {
      setPrice(item.price.toFixed(2));
      setIsEditingPrice(false);
    }
  };

  const handleDeleteClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    onDeleteItem(item.id);
  }

  const handlePriceEditClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    setIsEditingPrice(true);
  }

  return (
    <div 
      className="group relative flex flex-col glass-card rounded-2xl overflow-hidden transition-all duration-300 hover:-translate-y-1 cursor-pointer"
      onClick={() => onSelectItem(item)}
    >
      {/* Image */}
      <div className="relative aspect-square overflow-hidden bg-black/40">
        <img
          src={item.imageUrl}
          alt={item.title}
          className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-105"
          loading="lazy"
        />

        {isEditMode && (
          <button
            onClick={handleDeleteClick}
            className="absolute top-2 right-2 bg-red-500/80 hover:bg-red-500 text-white p-2 rounded-full transition-all opacity-0 group-hover:opacity-100 z-10"
          >
            <TrashIcon className="h-3 w-3" />
          </button>
        )}
      </div>

      {/* Info */}
      <div className="p-3 sm:p-4 flex flex-col gap-1.5">
        <h3 className="text-xs sm:text-sm font-bold text-white line-clamp-1 opacity-90 group-hover:text-brand-primary transition-colors">
          {item.title}
        </h3>

        <div className="flex items-center justify-between mt-auto">
          {isEditMode && isEditingPrice ? (
            <div className="flex items-center" onClick={(e) => e.stopPropagation()}>
              <span className="text-brand-primary text-xs font-bold">$</span>
              <input
                ref={priceInputRef}
                type="number"
                value={price}
                onChange={(e) => setPrice(e.target.value)}
                onBlur={handlePriceUpdate}
                onKeyDown={handleKeyDown}
                className="bg-black/50 text-white text-xs font-bold w-16 rounded-md px-1 outline-none border border-brand-primary/30"
                min="0"
                step="0.01"
              />
            </div>
          ) : (
            <div className="flex items-center gap-1 group/price">
              <span className="text-xs sm:text-sm font-black text-brand-primary tracking-tight">
                ${item.price.toFixed(2)}
              </span>
              {isEditMode && (
                <button 
                  onClick={handlePriceEditClick}
                  className="p-0.5 text-brand-text-secondary hover:text-brand-primary opacity-0 group-hover/price:opacity-100 transition-all"
                >
                  <PencilIcon className="h-2.5 w-2.5" />
                </button>
              )}
            </div>
          )}

          <div className="w-5 h-5 rounded-full border border-white/5 flex items-center justify-center group-hover:border-brand-primary/30 transition-all">
             <div className="w-1 h-1 rounded-full bg-brand-primary group-hover:scale-125 transition-transform"></div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ItemCard;

