import React, { useState, useEffect, useMemo } from 'react';
import { Item } from './types';
import { generateItemDetails } from './services/geminiService';
import { resizeAndCompressImage } from './utils/fileUtils';
import { getAllItems, saveItem, deleteItemFromDB } from './utils/dbUtils';
import Header from './components/Header';
import ItemList from './components/ItemList';
import FileUpload from './components/FileUpload';
import Spinner from './components/Spinner';
import ItemModal from './components/ItemModal';
import CartDrawer from './components/CartDrawer';

const CATEGORIES = ["All", "Visuals", "Audio", "Text", "Video"];

const App: React.FC = () => {
  const [items, setItems] = useState<Item[]>([]);
  const [cart, setCart] = useState<Item[]>([]);
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [isInitializing, setIsInitializing] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);
  const [isEditMode, setIsEditMode] = useState<boolean>(false); 
  const [selectedItem, setSelectedItem] = useState<Item | null>(null);
  const [searchQuery, setSearchQuery] = useState<string>('');
  const [activeCategory, setActiveCategory] = useState<string>("All");
  const [isCartOpen, setIsCartOpen] = useState(false);

  const loadData = async () => {
    try {
      const data = await getAllItems();
      setItems(data);
    } catch (e: any) {
      setError(`Sync Error: ${e.message}`);
    } finally {
      setIsInitializing(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  const filteredItems = useMemo(() => {
    return items.filter(item => {
      const matchesSearch = item.title.toLowerCase().includes(searchQuery.toLowerCase());
      const matchesCategory = activeCategory === "All" || item.description.toLowerCase().includes(activeCategory.toLowerCase());
      return matchesSearch && matchesCategory;
    });
  }, [items, searchQuery, activeCategory]);

  const handleImageUpload = async (file: File) => {
    setIsLoading(true);
    setError(null);
    try {
      const { base64, mimeType } = await resizeAndCompressImage(file);
      const details = await generateItemDetails(base64, mimeType);
      const newItem: Item = { id: crypto.randomUUID(), imageUrl: `data:${mimeType};base64,${base64}`, ...details, price: 18.00 };
      await saveItem(newItem);
      setItems(prev => [newItem, ...prev]);
    } catch (err: any) {
      setError(err.message || "Upload failed");
    } finally {
      setIsLoading(false);
    }
  };

  const handleUpdateItem = async (updatedItem: Item) => {
    await saveItem(updatedItem);
    setItems(items.map(item => item.id === updatedItem.id ? updatedItem : item));
  };

  const handleDeleteItem = async (id: string) => {
    await deleteItemFromDB(id);
    setItems(items.filter(item => item.id !== id));
  };

  const toggleCartItem = (item: Item) => {
    setCart(prev => prev.some(i => i.id === item.id) ? prev.filter(i => i.id !== item.id) : [...prev, item]);
  };

  if (isInitializing) return <div className="min-h-screen flex items-center justify-center bg-brand-bg"><Spinner /></div>;

  return (
    <div className="min-h-screen bg-brand-bg pb-24">
      <Header 
        isEditMode={isEditMode} 
        onToggleEditMode={() => setIsEditMode(!isEditMode)} 
        searchQuery={searchQuery}
        onSearchChange={setSearchQuery}
      />

      <main className="container mx-auto px-6 py-4 max-w-4xl">
        <div className="mb-8">
          <h2 className="text-2xl font-extrabold text-brand-black leading-tight">
            Order From The <br/>Best Of <span className="text-brand-text-secondary">Assets</span>
          </h2>

          <div className="flex gap-3 overflow-x-auto no-scrollbar py-6">
            {CATEGORIES.map(cat => (
              <button
                key={cat}
                onClick={() => setActiveCategory(cat)}
                className={`px-6 py-2 rounded-full text-xs font-bold transition-all whitespace-nowrap ${
                  activeCategory === cat ? 'bg-brand-black text-white' : 'bg-white text-brand-text-secondary shadow-sm'
                }`}
              >
                {cat}
              </button>
            ))}
          </div>
        </div>

        {isEditMode && (
          <div className="mb-10">
            <FileUpload onImageUpload={handleImageUpload} isLoading={isLoading} />
          </div>
        )}

        <ItemList 
          items={filteredItems} 
          onUpdateItem={handleUpdateItem} 
          onDeleteItem={handleDeleteItem} 
          onSelectItem={setSelectedItem} 
          onAddToCart={toggleCartItem}
          isEditMode={isEditMode} 
          cart={cart}
        />
      </main>

      {/* Bottom Cart Bar */}
      <div className="fixed bottom-6 left-6 right-6 z-40">
        <button 
          onClick={() => setIsCartOpen(true)}
          className="w-full bg-brand-black text-white p-4 rounded-3xl flex items-center justify-between shadow-2xl transition-transform active:scale-95"
        >
          <div className="flex items-center gap-4">
            <div className="bg-brand-yellow text-brand-black w-8 h-8 rounded-full flex items-center justify-center font-bold text-sm">
              {cart.length}
            </div>
            <div className="text-left">
              <p className="font-bold text-sm uppercase tracking-wider">Cart</p>
              <p className="text-[10px] text-brand-text-secondary">{cart.length} Items</p>
            </div>
          </div>
          <div className="flex -space-x-2">
            {cart.slice(0, 3).map(i => (
              <img key={i.id} src={i.imageUrl} className="w-8 h-8 rounded-full border-2 border-brand-black object-cover" />
            ))}
          </div>
        </button>
      </div>

      <CartDrawer 
        isOpen={isCartOpen} 
        onClose={() => setIsCartOpen(false)} 
        items={cart} 
        onRemove={toggleCartItem} 
      />

      {selectedItem && (
        <ItemModal 
          item={selectedItem} 
          onClose={() => setSelectedItem(null)} 
          isEditMode={isEditMode}
          onUpdateItem={handleUpdateItem}
          onAddToCart={() => toggleCartItem(selectedItem)}
          isInCart={cart.some(i => i.id === selectedItem.id)}
        />
      )}
    </div>
  );
};

export default App;

