        <button className="w-16 h-16 bg-brand-yellow text-brand-black rounded-3xl flex items-center justify-center shadow-lg active:scale-95 transition-all">
          <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3">
            <circle cx="9" cy="21" r="1"/><circle cx="20" cy="21" r="1"/><path d="M1 1h4l2.68 13.39a2 2 0 0 0 2 1.61h9.72a2 2 0 0 0 2-1.61L23 6H6"/>
          </svg>
        </button>
      </footer>
    </div>
  );
};

export default ItemModal;

import React from 'react';
import { Item, CartItem } from '../types';

interface CartDrawerProps {
  isOpen: boolean;
  onClose: () => void;
  items: CartItem[];
  onRemove: (itemId: string) => void;
  onUpdateQuantity: (item: Item, delta: number) => void;
}

const CartDrawer: React.FC<CartDrawerProps> = ({ isOpen, onClose, items, onRemove, onUpdateQuantity }) => {
  const total = items.reduce((sum, i) => sum + (i.price * i.quantity), 0);
  const cartItemsCount = items.reduce((acc, curr) => acc + curr.quantity, 0);

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-end justify-center animate-fade-in">
      <div className="absolute inset-0 bg-black/20 backdrop-blur-sm" onClick={onClose} />

      <div className="relative w-full max-w-lg bg-brand-black text-white rounded-t-5xl p-8 pt-4 animate-slide-up shadow-[0_-20px_60px_rgba(0,0,0,0.5)]">
        <div className="w-12 h-1 bg-white/20 rounded-full mx-auto mb-8" />

        <div className="flex justify-between items-center mb-10">
          <h2 className="text-2xl font-black">Cart</h2>
          <div className="bg-brand-yellow text-brand-black w-8 h-8 rounded-full flex items-center justify-center font-bold text-sm">
            {cartItemsCount}
          </div>
        </div>

        <div className="space-y-6 mb-12 max-h-[350px] overflow-y-auto no-scrollbar">
          {items.map(item => (
            <div key={item.id} className="flex items-center gap-4">
              <div className="w-14 h-14 bg-white rounded-full flex items-center justify-center p-2 shrink-0">
                <img src={item.imageUrl} className="w-full h-full object-contain" />
              </div>
              <div className="flex-grow">
                <h4 className="font-bold text-sm line-clamp-1">{item.title}</h4>
                <div className="flex items-center gap-2 mt-1">
                  <button 
                    onClick={() => onUpdateQuantity(item, -1)}
                    className="w-6 h-6 rounded-full bg-white/10 flex items-center justify-center text-xs"
                  >
                    -
                  </button>
                  <span className="text-xs font-bold w-4 text-center">{item.quantity}</span>
                  <button 
                    onClick={() => onUpdateQuantity(item, 1)}
                    className="w-6 h-6 rounded-full bg-white/10 flex items-center justify-center text-xs"
                  >
                    +
                  </button>
                </div>
              </div>
              <div className="flex items-center gap-4">
                <span className="font-black text-sm whitespace-nowrap">Rf {(item.price * item.quantity).toFixed(2)}</span>
                <button onClick={() => onRemove(item.id)} className="text-brand-text-secondary hover:text-white">
                  <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>
                </button>
              </div>
            </div>
          ))}
          {items.length === 0 && <p className="text-center text-brand-text-secondary py-10">Your cart is empty.</p>}
        </div>

        <div className="bg-brand-yellow rounded-4xl p-6 mb-8 text-brand-black">
          <div className="flex justify-between items-center">
            <div>
              <p className="text-xs font-bold opacity-70 uppercase tracking-widest">Total Amount</p>
              <p className="text-2xl font-black tracking-tighter">Rf {total.toFixed(2)}</p>
            </div>
            <div className="flex -space-x-3">
              {items.slice(0, 3).map(i => (
                <div key={i.id} className="relative">
                  <img src={i.imageUrl} className="w-10 h-10 rounded-xl border-2 border-brand-yellow bg-white object-contain p-1" />
                  {i.quantity > 1 && (
                    <span className="absolute -top-1 -right-1 bg-brand-black text-white text-[8px] w-4 h-4 rounded-full flex items-center justify-center font-bold">
                      {i.quantity}
                    </span>
                  )}
                </div>
              ))}
            </div>
          </div>
        </div>

        <button 
          className="w-full bg-white text-brand-black p-5 rounded-[2.5rem] flex items-center justify-between font-black text-sm uppercase tracking-widest transition-transform active:scale-95 group"
          onClick={onClose}
        >
          <span className="pl-6">Make Payment</span>
          <div className="bg-brand-yellow w-12 h-12 rounded-full flex items-center justify-center group-hover:translate-x-1 transition-transform">
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><polyline points="13 17 18 12 13 7"/><polyline points="6 17 11 12 6 7"/></svg>
          </div>
        </button>
      </div>
    </div>
  );
};

export default CartDrawer;

