            className="w-full bg-brand-black text-white p-5 rounded-3xl font-black text-sm uppercase tracking-widest shadow-lg active:scale-95 transition-all mt-6 disabled:opacity-50"
          >
            {isLoading ? 'Verifying...' : 'Sign In'}
