import React, { useState, useRef, useEffect } from 'react';
import { PencilIcon, EyeIcon, SearchIcon, XIcon, DatabaseIcon } from './IconComponents';
import { Item } from '../types';

interface HeaderProps {
  isEditMode: boolean;
  onToggleEditMode: () => void;
  searchQuery: string;
  onSearchChange: (query: string) => void;
  items: Item[];
  isAdmin: boolean;
  onLogout: () => void;
  onOpenAuth: () => void;
}

const Header: React.FC<HeaderProps> = ({ 
  isEditMode, 
  onToggleEditMode, 
  searchQuery, 
  onSearchChange, 
  items, 
  isAdmin, 
  onLogout,
  onOpenAuth 
}) => {
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [isExpanded, setIsExpanded] = useState(false);
  const searchRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  const suggestions = items
    .filter(item => 
      searchQuery.length > 0 && 
      item.title.toLowerCase().includes(searchQuery.toLowerCase()) &&
      item.title.toLowerCase() !== searchQuery.toLowerCase()
    )
    .slice(0, 5);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (searchRef.current && !searchRef.current.contains(event.target as Node)) {
        setShowSuggestions(false);
        if (searchQuery === '') {
          setIsExpanded(false);
        }
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [searchQuery]);

  const handleExpand = () => {
    setIsExpanded(true);
    setTimeout(() => inputRef.current?.focus(), 100);
  };

  return (
    <header className="px-6 py-6 flex flex-col gap-4">
      <div className="flex justify-between items-center w-full">
        <div className="flex items-center gap-2">
           <div className="w-8 h-8 bg-brand-yellow rounded-lg flex items-center justify-center">
             <span className="font-black text-xs">A</span>
           </div>
           <h1 className="font-black text-sm uppercase tracking-tighter">Aura</h1>
        </div>

        <div className="flex items-center gap-2">
          {isAdmin ? (
            <>
              <button
                onClick={onToggleEditMode}
                className={`flex items-center gap-2 px-5 py-2 rounded-full text-[10px] font-black uppercase tracking-widest transition-all shadow-sm active:scale-95 ${
                  isEditMode ? 'bg-brand-black text-white' : 'bg-white text-brand-black'
                }`}
              >
                {isEditMode ? <PencilIcon className="h-3 w-3" /> : <EyeIcon className="h-3 w-3" />}
                <span>{isEditMode ? 'Admin' : 'View'}</span>
              </button>
              <button
                onClick={onLogout}
                className="p-2 bg-white rounded-full shadow-sm text-brand-text-secondary hover:text-brand-black transition-colors"
                title="Logout"
              >
                <XIcon className="h-3 w-3" />
              </button>
            </>
          ) : (
            <button
              onClick={onOpenAuth}
              className="flex items-center gap-2 px-5 py-2 rounded-full text-[10px] font-black uppercase tracking-widest bg-white text-brand-black shadow-sm active:scale-95 transition-all"
            >
              <DatabaseIcon className="h-3 w-3" />
              <span>Login</span>
            </button>
          )}
        </div>
      </div>

      <div className="relative w-full flex justify-end" ref={searchRef}>
        <div 
          className={`relative flex items-center bg-white rounded-2xl shadow-sm transition-all duration-300 ease-in-out h-14 ${
            isExpanded || searchQuery ? 'w-full' : 'w-14'
          }`}
        >
          <button 
            onClick={handleExpand}
            className={`absolute left-0 w-14 h-14 flex items-center justify-center z-10 text-brand-text-secondary hover:text-brand-black transition-colors ${
               isExpanded || searchQuery ? 'pointer-events-none' : 'pointer-events-auto'
            }`}
          >
            <SearchIcon className="h-5 w-5" />
          </button>

          <div className={`flex-grow flex items-center transition-opacity duration-200 ${
            isExpanded || searchQuery ? 'opacity-100 pl-14' : 'opacity-0 pointer-events-none'
          }`}>
            <input
              ref={inputRef}
              type="text"
              placeholder="Search products..."
              className="w-full bg-transparent border-none py-4 pr-12 text-sm font-bold focus:ring-0 outline-none"
              value={searchQuery}
              onChange={(e) => {
                onSearchChange(e.target.value);
                setShowSuggestions(true);
              }}
              onFocus={() => {
                setIsExpanded(true);
                setShowSuggestions(true);
              }}
              onBlur={() => {
                if (searchQuery === '') {
                  setTimeout(() => {
                    if (document.activeElement !== inputRef.current) {
                       setIsExpanded(false);
                    }
                  }, 200);
                }
              }}
            />

            {searchQuery && (
              <button 
                onClick={() => {
                  onSearchChange('');
                  inputRef.current?.focus();
                }}
                className="absolute right-4 flex items-center text-brand-text-secondary hover:text-brand-black transition-colors"
              >
                <XIcon className="h-4 w-4" />
              </button>
            )}
          </div>
        </div>

        {showSuggestions && suggestions.length > 0 && isExpanded && (
          <div className="absolute top-full left-0 right-0 mt-2 bg-white rounded-2xl shadow-xl z-50 overflow-hidden border border-brand-bg animate-fade-in">
            {suggestions.map((item) => (
              <button
                key={item.id}
                className="w-full px-6 py-4 text-left text-sm font-bold hover:bg-brand-bg transition-colors flex items-center gap-3"
                onClick={() => {
                  onSearchChange(item.title);
                  setShowSuggestions(false);
                }}
              >
                <img src={item.imageUrl} className="w-8 h-8 rounded-lg object-cover bg-brand-bg" alt="" />
                <span className="truncate">{item.title}</span>
              </button>
            ))}
          </div>
        )}
      </div>
    </header>
  );
};

export default Header;

import React, { useState, useEffect, useMemo } from 'react';
import { Item, CartItem } from './types';
import { generateItemDetails } from './services/geminiService';
import { resizeAndCompressImage } from './utils/fileUtils';
import { getAllItems, saveItem, deleteItemFromDB } from './utils/dbUtils';
import Header from './components/Header';
import ItemList from './components/ItemList';
import FileUpload from './components/FileUpload';
import Spinner from './components/Spinner';
import ItemModal from './components/ItemModal';
import CartDrawer from './components/CartDrawer';
import AuthModal from './components/AuthModal';

const App: React.FC = () => {
  const [items, setItems] = useState<Item[]>([]);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [isInitializing, setIsInitializing] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);
  const [isEditMode, setIsEditMode] = useState<boolean>(false); 
  const [selectedItem, setSelectedItem] = useState<Item | null>(null);
  const [searchQuery, setSearchQuery] = useState<string>('');
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [isCheckoutLoading, setIsCheckoutLoading] = useState(false);
  const [isAdmin, setIsAdmin] = useState<boolean>(false);
  const [isAuthModalOpen, setIsAuthModalOpen] = useState(false);

  useEffect(() => {
    // Check local persistence for admin session
    const session = localStorage.getItem('aura_admin_session');
    if (session === 'true') {
      setIsAdmin(true);
    }
  }, []);

  const loadData = async () => {
    try {
      const data = await getAllItems();
      setItems(data);
    } catch (e: any) {
      setError(`Sync Error: ${e.message}`);
    } finally {
      setIsInitializing(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  const filteredItems = useMemo(() => {
    return items.filter(item => {
      return item.title.toLowerCase().includes(searchQuery.toLowerCase());
    });
  }, [items, searchQuery]);

  const handleImageUpload = async (file: File) => {
    if (!isAdmin) return;
    setIsLoading(true);
    setError(null);
    try {
      const { base64, mimeType } = await resizeAndCompressImage(file);
      const details = await generateItemDetails(base64, mimeType);
      const newItem: Item = { id: crypto.randomUUID(), imageUrl: `data:${mimeType};base64,${base64}`, ...details, price: 18.00 };
      await saveItem(newItem);
      setItems(prev => [newItem, ...prev]);
    } catch (err: any) {
      setError(err.message || "Upload failed");
    } finally {
      setIsLoading(false);
    }
  };

  const handleUpdateItem = async (updatedItem: Item) => {
    if (!isAdmin) return;
    await saveItem(updatedItem);
    setItems(items.map(item => item.id === updatedItem.id ? updatedItem : item));
    setCart(prev => prev.map(i => i.id === updatedItem.id ? { ...updatedItem, quantity: i.quantity } : i));
  };

  const handleDeleteItem = async (id: string) => {
    if (!isAdmin) return;
    await deleteItemFromDB(id);
    setItems(items.filter(item => item.id !== id));
    setCart(prev => prev.filter(i => i.id !== id));
  };

  const handleLogin = () => {
    setIsAdmin(true);
    localStorage.setItem('aura_admin_session', 'true');
  };

  const handleLogout = () => {
    setIsAdmin(false);
    setIsEditMode(false);
    localStorage.removeItem('aura_admin_session');
  };

  const updateCartQuantity = (item: Item, delta: number) => {
    setCart(prev => {
      const existing = prev.find(i => i.id === item.id);
      if (existing) {
        const newQuantity = existing.quantity + delta;
        if (newQuantity <= 0) {
          return prev.filter(i => i.id !== item.id);
        }
        return prev.map(i => i.id === item.id ? { ...i, quantity: newQuantity } : i);
      }
      if (delta > 0) {
        return [...prev, { ...item, quantity: delta }];
      }
      return prev;
    });
  };

  const removeFromCart = (itemId: string) => {
    setCart(prev => prev.filter(i => i.id !== itemId));
  };

  const handleCheckout = async () => {
    if (cart.length === 0) return;

    setIsCheckoutLoading(true);
    const total = cart.reduce((sum, i) => sum + (i.price * i.quantity), 0);

    const orderData = {
      total: total,
      items: cart.map(item => ({ 
        name: item.title, 
        quantity: item.quantity 
      }))
    };

    try {
      await fetch("https://script.google.com/macros/s/AKfycbzyaAG0r-ARF6bcKw-Kkn8o_vAbOZFNu8h92p-uRDatYrwAsu_t47Qqp6As8o1Cmy3QSQ/exec", {
        method: "POST",
        mode: "no-cors",
        body: JSON.stringify(orderData)
      });

      console.log("Notification sent to Telegram");
      alert("Order Placed Successfully!");
      setCart([]);
      setIsCartOpen(false);
    } catch (err) {
      console.error("Failed to send notification", err);
      alert("There was an error placing your order. Please try again.");
    } finally {
      setIsCheckoutLoading(false);
    }
  };

  const cartItemsCount = cart.reduce((acc, curr) => acc + curr.quantity, 0);

  if (isInitializing) return <div className="min-h-screen flex items-center justify-center bg-brand-bg"><Spinner /></div>;

  return (
    <div className="min-h-screen bg-brand-bg pb-24">
      <Header 
        isEditMode={isEditMode} 
        onToggleEditMode={() => isAdmin ? setIsEditMode(!isEditMode) : setIsAuthModalOpen(true)} 
        searchQuery={searchQuery}
        onSearchChange={setSearchQuery}
        items={items}
        isAdmin={isAdmin}
        onLogout={handleLogout}
        onOpenAuth={() => setIsAuthModalOpen(true)}
      />

      <main className="container mx-auto px-6 py-4 max-w-4xl">
        <div className="mb-8 text-center sm:text-left">
          <h2 className="text-3xl font-extrabold text-brand-black leading-tight tracking-tight">
            Curated <span className="text-brand-text-secondary">Essentials</span> <br/> 
            <span className="text-brand-black">Available for order</span>
          </h2>
        </div>

        {isEditMode && isAdmin && (
          <div className="mb-10">
            <FileUpload onImageUpload={handleImageUpload} isLoading={isLoading} />
          </div>
        )}

        <ItemList 
          items={filteredItems} 
          onUpdateItem={handleUpdateItem} 
          onDeleteItem={handleDeleteItem} 
          onSelectItem={setSelectedItem} 
          onAddToCart={(item) => updateCartQuantity(item, 1)}
          onUpdateCartQuantity={updateCartQuantity}
          isEditMode={isEditMode && isAdmin} 
          cart={cart}
        />
      </main>

      <div className="fixed bottom-6 left-6 right-6 z-40 lg:max-w-xl lg:mx-auto">
        <button 
          onClick={() => setIsCartOpen(true)}
          className="w-full bg-brand-black/80 backdrop-blur-xl border border-white/10 text-white p-4 rounded-4xl flex items-center justify-between shadow-2xl transition-all active:scale-95 hover:bg-brand-black/90"
        >
          <div className="flex items-center gap-4 pl-2">
            <div className="bg-brand-yellow text-brand-black w-9 h-9 rounded-full flex items-center justify-center font-black text-sm shadow-inner">
              {cartItemsCount}
            </div>
            <div className="text-left">
              <p className="font-black text-xs uppercase tracking-[0.2em]">Your Bag</p>
              <p className="text-[10px] text-white/50 font-bold uppercase">{cartItemsCount} items added</p>
            </div>
          </div>
          <div className="flex -space-x-3 mr-2">
            {cart.slice(0, 3).map(i => (
              <div key={i.id} className="relative group/mini">
                <img 
                  src={i.imageUrl} 
                  className="w-9 h-9 rounded-full border-2 border-brand-black/50 object-cover bg-white shadow-lg transition-transform group-hover/mini:-translate-y-1" 
                  alt="" 
                />
              </div>
            ))}
          </div>
        </button>
      </div>

      <CartDrawer 
        isOpen={isCartOpen} 
        onClose={() => setIsCartOpen(false)} 
        items={cart} 
        onRemove={removeFromCart} 
        onUpdateQuantity={updateCartQuantity}
        onCheckout={handleCheckout}
        isCheckoutLoading={isCheckoutLoading}
      />

      {selectedItem && (
        <ItemModal 
          item={selectedItem} 
          onClose={() => setSelectedItem(null)} 
          isEditMode={isEditMode && isAdmin}
          onUpdateItem={handleUpdateItem}
          onAddToCart={() => updateCartQuantity(selectedItem, 1)}
          onUpdateCartQuantity={updateCartQuantity}
          onOpenCart={() => {
            setIsCartOpen(true);
            setSelectedItem(null);
          }}
          cartItem={cart.find(i => i.id === selectedItem.id)}
        />
      )}

      {isAuthModalOpen && (
        <AuthModal onLogin={handleLogin} onClose={() => setIsAuthModalOpen(false)} />
      )}
    </div>
  );
};

export default App;

