          <span className="pl-6">{isCheckoutLoading ? 'Wait...' : 'Make Payment'}</span>
          <div className="bg-brand-yellow w-12 h-12 rounded-full flex items-center justify-center group-hover:translate-x-1 transition-transform shadow-lg border-2 border-brand-black text-brand-black">
