import React, { useState, useRef, useEffect } from 'react';
import { PencilIcon, EyeIcon, SearchIcon, XIcon, DatabaseIcon } from './IconComponents';
import { Item } from '../types';

interface HeaderProps {
  isEditMode: boolean;
  onToggleEditMode: () => void;
  searchQuery: string;
  onSearchChange: (query: string) => void;
  items: Item[];
  isAdmin: boolean;
  onLogout: () => void;
  onOpenAuth: () => void;
}

const Header: React.FC<HeaderProps> = ({ 
  isEditMode, 
  onToggleEditMode, 
  searchQuery, 
  onSearchChange, 
  items, 
  isAdmin, 
  onLogout,
  onOpenAuth 
}) => {
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [isExpanded, setIsExpanded] = useState(false);
  const searchRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  const suggestions = items
    .filter(item => 
      searchQuery.length > 0 && 
      item.title.toLowerCase().includes(searchQuery.toLowerCase()) &&
      item.title.toLowerCase() !== searchQuery.toLowerCase()
    )
    .slice(0, 5);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (searchRef.current && !searchRef.current.contains(event.target as Node)) {
        setShowSuggestions(false);
        if (searchQuery === '') {
          setIsExpanded(false);
        }
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [searchQuery]);

  const handleExpand = () => {
    setIsExpanded(true);
    setTimeout(() => inputRef.current?.focus(), 100);
  };

  return (
    <header className="px-6 py-6 flex flex-col gap-4">
      <div className="flex justify-between items-center w-full">
        <div className="flex items-center gap-2">
           <div className="w-8 h-8 bg-brand-yellow rounded-lg flex items-center justify-center">
             <span className="font-black text-xs">L</span>
           </div>
           <h1 className="font-black text-sm uppercase tracking-tighter whitespace-nowrap">Load Badhige</h1>
        </div>

        <div className="flex items-center gap-2">
          {isAdmin ? (
            <>
              <button
                onClick={onToggleEditMode}
                className={`flex items-center gap-2 px-5 py-2 rounded-full text-[10px] font-black uppercase tracking-widest transition-all shadow-sm active:scale-95 ${
                  isEditMode ? 'bg-brand-black text-white' : 'bg-white text-brand-black'
                }`}
              >
                {isEditMode ? <PencilIcon className="h-3 w-3" /> : <EyeIcon className="h-3 w-3" />}
                <span>{isEditMode ? 'Admin' : 'View'}</span>
              </button>
              <button
                onClick={onLogout}
                className="p-2 bg-white rounded-full shadow-sm text-brand-text-secondary hover:text-brand-black transition-colors"
                title="Logout"
              >
                <XIcon className="h-3 w-3" />
              </button>
            </>
          ) : (
            <button
              onClick={onOpenAuth}
              className="flex items-center gap-2 px-5 py-2 rounded-full text-[10px] font-black uppercase tracking-widest bg-white text-brand-black shadow-sm active:scale-95 transition-all"
            >
              <DatabaseIcon className="h-3 w-3" />
              <span>Login</span>
            </button>
          )}
        </div>
      </div>

      <div className="relative w-full flex justify-end" ref={searchRef}>
        <div 
          className={`relative flex items-center bg-white rounded-2xl shadow-sm transition-all duration-300 ease-in-out h-14 ${
            isExpanded || searchQuery ? 'w-full' : 'w-14'
          }`}
        >
          <button 
            onClick={handleExpand}
            className={`absolute left-0 w-14 h-14 flex items-center justify-center z-10 text-brand-text-secondary hover:text-brand-black transition-colors ${
               isExpanded || searchQuery ? 'pointer-events-none' : 'pointer-events-auto'
            }`}
          >
            <SearchIcon className="h-5 w-5" />
          </button>

          <div className={`flex-grow flex items-center transition-opacity duration-200 ${
            isExpanded || searchQuery ? 'opacity-100 pl-14' : 'opacity-0 pointer-events-none'
          }`}>
            <input
              ref={inputRef}
              type="text"
              placeholder="Search products..."
              className="w-full bg-transparent border-none py-4 pr-12 text-sm font-bold focus:ring-0 outline-none"
              value={searchQuery}
              onChange={(e) => {
                onSearchChange(e.target.value);
                setShowSuggestions(true);
              }}
              onFocus={() => {
                setIsExpanded(true);
                setShowSuggestions(true);
              }}
              onBlur={() => {
                if (searchQuery === '') {
                  setTimeout(() => {
                    if (document.activeElement !== inputRef.current) {
                       setIsExpanded(false);
                    }
                  }, 200);
                }
              }}
            />

            {searchQuery && (
              <button 
                onClick={() => {
                  onSearchChange('');
                  inputRef.current?.focus();
                }}
                className="absolute right-4 flex items-center text-brand-text-secondary hover:text-brand-black transition-colors"
              >
                <XIcon className="h-4 w-4" />
              </button>
            )}
          </div>
        </div>

        {showSuggestions && suggestions.length > 0 && isExpanded && (
          <div className="absolute top-full left-0 right-0 mt-2 bg-white rounded-2xl shadow-xl z-50 overflow-hidden border border-brand-bg animate-fade-in">
            {suggestions.map((item) => (
              <button
                key={item.id}
                className="w-full px-6 py-4 text-left text-sm font-bold hover:bg-brand-bg transition-colors flex items-center gap-3"
                onClick={() => {
                  onSearchChange(item.title);
                  setShowSuggestions(false);
                }}
              >
                <img src={item.imageUrl} className="w-8 h-8 rounded-lg object-cover bg-brand-bg" alt="" />
                <span className="truncate">{item.title}</span>
              </button>
            ))}
          </div>
        )}
      </div>
    </header>
  );
};

export default Header;

import React, { useState, useEffect } from 'react';
import { Item, CartItem } from '../types';

interface ItemModalProps {
  item: Item;
  onClose: () => void;
  isEditMode: boolean;
  onUpdateItem: (item: Item) => Promise<void>;
  onAddToCart: () => void;
  onUpdateCartQuantity: (item: Item, delta: number) => void;
  onOpenCart: () => void;
  cartItem?: CartItem;
}

const ItemModal: React.FC<ItemModalProps> = ({ item, onClose, isEditMode, onUpdateItem, onAddToCart, onUpdateCartQuantity, onOpenCart, cartItem }) => {
  const [editedItem, setEditedItem] = useState<Item>(item);
  const [isSaving, setIsSaving] = useState(false);

  useEffect(() => {
    setEditedItem(item);
  }, [item]);

  const handleSave = async () => {
    setIsSaving(true);
    try {
      await onUpdateItem(editedItem);
    } finally {
      setIsSaving(false);
    }
  };

  const isInCart = !!cartItem;

  return (
    <div className="fixed inset-0 z-50 bg-white animate-fade-in flex flex-col overflow-hidden">
      <header className="px-6 py-6 flex justify-between items-center shrink-0">
        <button onClick={onClose} className="w-12 h-12 bg-white shadow-lg rounded-full flex items-center justify-center active:scale-90 transition-transform">
          <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="#1A1A1A" strokeWidth="3"><polyline points="15 18 9 12 15 6"/></svg>
        </button>
        {isEditMode && (
          <button 
            onClick={handleSave}
            disabled={isSaving}
            className="px-6 py-2 bg-brand-black text-white rounded-full font-black text-xs uppercase tracking-widest disabled:opacity-50"
          >
            {isSaving ? 'Saving...' : 'Save Changes'}
          </button>
        )}
      </header>

      <div className="flex-grow px-8 flex flex-col items-center overflow-y-auto no-scrollbar pb-10">
        <div className="text-center mb-6 w-full max-w-sm">
          {isEditMode ? (
            <input 
              className="text-3xl font-black tracking-tight leading-none mb-2 w-full text-center border-b-2 border-brand-yellow focus:outline-none"
              value={editedItem.title}
              onChange={(e) => setEditedItem({...editedItem, title: e.target.value})}
            />
          ) : (
            <h2 className="text-3xl font-black tracking-tight leading-none mb-2">{item.title}</h2>
          )}

          <p className="text-brand-text-secondary font-bold text-xs uppercase tracking-widest mb-4">Load Badhige Marketplace</p>

          <div className="px-4 py-3 bg-brand-bg/50 rounded-2xl w-full">
            {isEditMode ? (
              <textarea 
                className="text-sm text-brand-black leading-relaxed font-medium w-full bg-transparent border-none focus:outline-none resize-none h-24 text-center"
                value={editedItem.description}
                onChange={(e) => setEditedItem({...editedItem, description: e.target.value})}
              />
            ) : (
              <p className="text-sm text-brand-black leading-relaxed font-medium">
                {item.description}
              </p>
            )}
          </div>
        </div>

        <div className="relative w-full max-w-[280px] sm:max-w-[320px] my-4 sm:my-8 shrink-0">
          <div className="absolute inset-0 bg-brand-bg rounded-5xl -rotate-6 transform scale-110 opacity-50" />
          <img 
            src={item.imageUrl} 
            className="relative z-10 w-full h-auto drop-shadow-3xl transform rotate-3 transition-transform hover:rotate-0 duration-500" 
            alt={item.title}
          />
        </div>

        <div className="flex flex-col items-center gap-6 mt-4 shrink-0">
          <div className="bg-brand-yellow rounded-full px-10 py-4 flex items-center gap-6 shadow-xl">
             <div className="flex items-center gap-2">
                {isInCart ? (
                  <div className="flex items-center gap-4">
                    <button 
                      onClick={() => onUpdateCartQuantity(item, -1)}
                      className="w-10 h-10 rounded-full bg-brand-black text-white flex items-center justify-center font-black"
                    >
                      -
                    </button>
                    <span className="text-2xl font-black min-w-[30px] text-center">{cartItem.quantity}</span>
                    <button 
                      onClick={() => onUpdateCartQuantity(item, 1)}
                      className="w-10 h-10 rounded-full bg-brand-black text-white flex items-center justify-center font-black"
                    >
                      +
                    </button>
                  </div>
                ) : (
                  <span className="text-2xl font-black">01</span>
                )}
             </div>
            <div className="h-6 w-[2px] bg-brand-black/20" />

            {isEditMode ? (
              <div className="flex items-center font-black text-2xl tracking-tighter">
                <span className="mr-1">Rf</span>
                <input 
                  type="number"
                  className="w-20 bg-transparent border-b border-brand-black/20 focus:outline-none"
                  value={editedItem.price}
                  onChange={(e) => setEditedItem({...editedItem, price: parseFloat(e.target.value) || 0})}
                />
              </div>
            ) : (
              <span className="text-2xl font-black tracking-tighter">Rf {item.price.toFixed(2)}</span>
            )}
          </div>
        </div>
      </div>

      <footer className="p-8 flex items-center gap-4 bg-white/80 backdrop-blur-md shrink-0">
        {!isInCart ? (
          <button 
            onClick={onAddToCart}
            className="flex-grow h-16 rounded-3xl font-black text-sm bg-brand-black text-white transition-all shadow-lg active:scale-95 uppercase tracking-widest"
          >
            Add to cart
          </button>
        ) : (
          <button 
            onClick={() => onUpdateCartQuantity(item, -cartItem.quantity)}
            className="flex-grow h-16 rounded-3xl font-black text-sm bg-brand-yellow text-brand-black transition-all shadow-lg active:scale-95 uppercase tracking-widest"
          >
            Remove from cart
          </button>
