import { GoogleGenAI, Type } from "@google/genai";

const responseSchema = {
  type: Type.OBJECT,
  properties: {
    title: {
      type: Type.STRING,
      description: "A professional product title."
    },
    description: {
      type: Type.STRING,
      description: "A brief one-sentence factual description."
    }
  },
  required: ["title", "description"]
};

export const generateItemDetails = async (base64ImageData: string, mimeType: string): Promise<{ title: string; description: string }> => {
  const apiKey = process.env.API_KEY;

  if (!apiKey) {
    console.warn("Gemini API_KEY is not defined in environment variables.");
    throw new Error("AI service not configured. Please add an environment variable named 'API_KEY' in your dashboard settings. Hyphens are not allowed in the name.");
  }

  const ai = new GoogleGenAI({ apiKey });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          {
            text: "Analyze this product image and extract its title and a short factual description for a marketplace inventory system.",
          },
          {
            inlineData: {
              data: base64ImageData,
              mimeType: mimeType,
            },
          },
        ],
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
      },
    });

    const jsonText = response.text;
    if (!jsonText) throw new Error("AI returned no content.");

    return JSON.parse(jsonText);

  } catch (error: any) {
    console.error("AI Analysis Error:", error);
    throw new Error(`AI Verification Failed: ${error.message || "Unknown Error"}`);
  }
};

/**
 * Resizes and compresses an image for storage in IndexedDB.
 * We use image/webp to preserve transparency (alpha channel) while maintaining 
 * small file sizes and high visual quality.
 */
export const resizeAndCompressImage = (file: File, maxWidth = 1024, maxHeight = 1024): Promise<{ base64: string, mimeType: string }> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = (event) => {
      const img = new Image();
      img.src = event.target?.result as string;
      img.onload = () => {
        const canvas = document.createElement('canvas');
        let width = img.width;
        let height = img.height;

        if (width > height) {
          if (width > maxWidth) {
            height *= maxWidth / width;
            width = maxWidth;
          }
        } else {
          if (height > maxHeight) {
            width *= maxHeight / height;
            height = maxHeight;
          }
        }

        canvas.width = width;
        canvas.height = height;
        const ctx = canvas.getContext('2d');
        if (!ctx) return reject(new Error('Canvas context not found'));

        // Ensure the canvas is clear before drawing
        ctx.clearRect(0, 0, width, height);
        ctx.drawImage(img, 0, 0, width, height);

        /**
         * We use image/webp as it supports transparency and offers superior compression.
         * If a browser doesn't support webp, toDataURL defaults to image/png, 
         * which also preserves transparency.
         */
        const dataUrl = canvas.toDataURL('image/webp', 0.8);
        const mimeType = dataUrl.substring(dataUrl.indexOf(":") + 1, dataUrl.indexOf(";"));
        const base64 = dataUrl.split(',')[1];

        resolve({ base64, mimeType });
      };
      img.onerror = () => reject(new Error('Image loading failed'));
    };
    reader.onerror = () => reject(new Error('File reading failed'));
  });
};

export const downloadAsJSON = (data: any, fileName: string) => {
  const json = JSON.stringify(data, null, 2);
  const blob = new Blob([json], { type: 'application/json' });
  const href = URL.createObjectURL(blob);
  const link = document.createElement('a');
  link.href = href;
  link.download = fileName;
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
  URL.revokeObjectURL(href);
};

