              {/* Premium Segmented Control for Mode Toggling */}
              <div className="flex bg-white/60 p-1 rounded-2xl shadow-sm border border-black/5 items-center">
                <button
                  onClick={() => !isEditMode && onToggleEditMode()}
                  className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
                    isEditMode ? 'bg-brand-black text-white shadow-md' : 'text-brand-text-secondary hover:text-brand-black'
                  }`}
                >
                  <PencilIcon className="h-3 w-3" />
                  <span className="hidden xs:inline">Manage</span>
                </button>
                <button
                  onClick={() => isEditMode && onToggleEditMode()}
                  className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
                    !isEditMode ? 'bg-brand-black text-white shadow-md' : 'text-brand-text-secondary hover:text-brand-black'
                  }`}
                >
                  <EyeIcon className="h-3 w-3" />
                  <span className="hidden xs:inline">Preview</span>
