            <button
              onClick={onOpenAuth}
              className="flex items-center gap-2 px-6 py-2.5 rounded-full text-[10px] font-black uppercase tracking-widest bg-brand-black text-white shadow-lg active:scale-95 transition-all"
            >
              <DatabaseIcon className="h-3 w-3" />
              <span>Sign In</span>
            </button>
          )}
        </div>
      </div>

      <div className="relative w-full flex justify-center" ref={searchRef}>
        <div 
          className={`relative flex items-center bg-white rounded-3xl shadow-sm transition-all duration-300 ease-in-out h-14 ${
            isExpanded || searchQuery ? 'w-full ring-2 ring-brand-yellow/30' : 'w-14'
          }`}
        >
          <button 
            onClick={handleExpand}
            className={`absolute left-0 w-14 h-14 flex items-center justify-center z-10 text-brand-text-secondary hover:text-brand-black transition-colors ${
               isExpanded || searchQuery ? 'pointer-events-none' : 'pointer-events-auto'
            }`}
          >
            <SearchIcon className="h-5 w-5" />
          </button>

          <div className={`flex-grow flex items-center transition-opacity duration-200 ${
            isExpanded || searchQuery ? 'opacity-100 pl-14' : 'opacity-0 pointer-events-none'
          }`}>
            <input
              ref={inputRef}
              type="text"
              placeholder="Search inventory..."
              className="w-full bg-transparent border-none py-4 pr-12 text-sm font-bold focus:ring-0 outline-none placeholder:text-brand-text-secondary/40"
              value={searchQuery}
              onChange={(e) => {
                onSearchChange(e.target.value);
                setShowSuggestions(true);
              }}
              onFocus={() => {
                setIsExpanded(true);
                setShowSuggestions(true);
              }}
              onBlur={() => {
                if (searchQuery === '') {
                  setTimeout(() => {
                    if (document.activeElement !== inputRef.current) {
                       setIsExpanded(false);
                    }
                  }, 200);
                }
              }}
            />

            {searchQuery && (
              <button 
                onClick={() => {
                  onSearchChange('');
                  inputRef.current?.focus();
