      isSelected: row.isselected === null || row.isselected === undefined ? true : row.isselected
    })) as Item[];
  } catch (err: any) {
    console.warn("Cloud fetch failed, using local fallback", err);
    const db = await initIndexedDB();
    return new Promise((resolve, reject) => {
      const transaction = db.transaction(STORE_NAME, 'readonly');
      const store = transaction.objectStore(STORE_NAME);
      const request = store.getAll();
      request.onsuccess = () => resolve(request.result);
      request.onerror = () => reject('Error fetching local items');
    });
  }
};

export const saveItem = async (item: Item): Promise<void> => {
  const payload: any = {
    id: item.id,
    title: item.title,
    description: item.description,
    price: item.price,
    imageurl: item.imageUrl,
    isselected: item.isSelected
  };

  try {
    // 1. Try to save with all fields (including visibility)
    const { error } = await supabase.from('items').upsert(payload, { onConflict: 'id' });

    if (error) {
      // 2. Check if the error is specifically about the missing 'isselected' column
      // Supabase/PostgREST error messages for missing columns usually contain the column name
      if (error.message.includes('isselected') || error.code === '42703') {
        console.warn("Supabase schema missing 'isselected' column. Retrying without visibility sync...");

        // Remove the problematic key and retry
        const { isselected, ...fallbackPayload } = payload;
        const { error: retryError } = await supabase.from('items').upsert(fallbackPayload, { onConflict: 'id' });

        if (retryError) throw new Error(`Database Sync Failed: ${retryError.message}`);
      } else {
        throw new Error(`Database Sync Failed: ${error.message}`);
      }
    }
  } catch (err: any) {
    console.error("Supabase Save Exception:", err);
    // We don't throw here to ensure the local DB still updates even if cloud sync is partially restricted
  }

  // 3. Always sync to Local IndexedDB (Visibility will work locally even if cloud sync fails)
  try {
    const db = await initIndexedDB();
    const transaction = db.transaction(STORE_NAME, 'readwrite');
    transaction.objectStore(STORE_NAME).put(item);
  } catch (e) {
    console.warn("Local cache sync failed", e);
  }
};

export const deleteItemFromDB = async (id: string): Promise<void> => {
