 * Attempts to sync visibility, but falls back gracefully if the column is missing.
 */
export const saveItem = async (item: Item): Promise<void> => {
  const fullPayload = {
    id: item.id,
    title: item.title,
    description: item.description,
    price: item.price,
    imageurl: item.imageUrl,
    isselected: item.isSelected 
  };

  try {
    // 1. Try full sync (including visibility)
    const { error } = await supabase.from('items').upsert(fullPayload, { onConflict: 'id' });

    if (error) {
      // 2. Check for missing column error specifically (Code 42703 is "undefined_column" in Postgres)
      if (error.message.includes('isselected') || error.code === '42703') {
        console.warn("Retrying save without 'isselected' column. Please add the column to your Supabase 'items' table.");

        const { isselected, ...fallbackPayload } = fullPayload;
        const { error: retryError } = await supabase.from('items').upsert(fallbackPayload, { onConflict: 'id' });

        if (retryError) throw new Error(retryError.message);
      } else {
        throw new Error(error.message);
      }
    }
  } catch (err: any) {
    console.error("Cloud Sync Error:", err.message);
    // Rethrow to let App.tsx handle UI notifications
    throw new Error(`Database Error: ${err.message}. If this mentions 'isselected', add the column to Supabase.`);
