  onAddToCart: (item: Item) => void;
  onUpdateCartQuantity: (item: Item, delta: number) => void;
  onToggleVisibility: (id: string) => void;
  onDelete: (id: string) => void;
  isEditMode: boolean;
  cartItem?: CartItem;
  variant: 'pink' | 'blue';
