const ItemCard: React.FC<ItemCardProps> = ({ 
  item, 
  onSelectItem, 
  onAddToCart, 
  onUpdateCartQuantity, 
  onToggleVisibility,
  onDelete, 
  isEditMode, 
  cartItem, 
  variant 
}) => {
  const isHidden = !item.isSelected;
  const bgColor = variant === 'pink' ? 'bg-brand-pink' : 'bg-brand-blue';
  const isInCart = !!cartItem;

  return (
    <div 
      className={`relative rounded-4xl sm:rounded-5xl overflow-hidden p-4 sm:p-6 shadow-sm transition-all active:scale-95 ${bgColor} ${isHidden && isEditMode ? 'ring-1 ring-brand-black/10' : ''}`}
      onClick={() => onSelectItem(item)}
    >
      <div className={`flex flex-col h-full min-h-[220px] sm:min-h-[320px] transition-all duration-500 ${isHidden && isEditMode ? 'opacity-40 grayscale blur-[1px]' : 'opacity-100'}`}>
        <div className="flex justify-between items-start relative z-10">
          <div className="max-w-full flex flex-col gap-1">
            <h3 className="text-sm sm:text-xl font-extrabold text-brand-black leading-tight line-clamp-2 pr-8">
              {item.title}
            </h3>
          </div>
          {isEditMode && (
            <button 
              onClick={(e) => { 
                e.stopPropagation(); 
                onDelete(item.id); 
              }}
              className="absolute -top-1 -right-1 bg-white/60 p-3 rounded-full hover:bg-red-500 hover:text-white transition-all shadow-sm active:scale-75 z-20"
              aria-label="Delete item"
            >
              <TrashIcon className="w-4 h-4 sm:w-5 sm:h-5" />
            </button>
          )}
        </div>

        <div className="flex-grow flex items-center justify-center p-2 sm:p-4">
          <img 
            src={item.imageUrl} 
            alt={item.title} 
            className="w-full max-h-[120px] sm:max-h-[180px] object-contain drop-shadow-2xl"
          />
        </div>

        <div className="flex items-center justify-between mt-auto relative z-10">
          <span className="font-extrabold text-brand-black text-xs sm:text-sm">
            Rf {item.price.toFixed(2)}
          </span>

          <div className="flex items-center gap-1">
            {!isEditMode && isInCart ? (
              <div className="flex items-center bg-brand-black rounded-full p-0.5 gap-2">
                <button
                  onClick={(e) => { e.stopPropagation(); onUpdateCartQuantity(item, -1); }}
                  className="w-7 h-7 sm:w-8 sm:h-8 rounded-full flex items-center justify-center bg-white/20 text-white hover:bg-white/30 transition-colors"
                >
                  <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><line x1="5" y1="12" x2="19" y2="12"/></svg>
                </button>
                <span className="text-white font-black text-xs sm:text-sm min-w-[12px] text-center">{cartItem.quantity}</span>
                <button
                  onClick={(e) => { e.stopPropagation(); onUpdateCartQuantity(item, 1); }}
                  className="w-7 h-7 sm:w-8 sm:h-8 rounded-full flex items-center justify-center bg-brand-yellow text-brand-black hover:bg-yellow-300 transition-colors"
                >
                  <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><path d="M12 5v14M5 12h14"/></svg>
                </button>
              </div>
            ) : !isEditMode ? (
              <button
                onClick={(e) => { e.stopPropagation(); onAddToCart(item); }}
                className="w-8 h-8 sm:w-10 sm:h-10 rounded-full flex items-center justify-center bg-brand-black text-white hover:scale-110 transition-all"
              >
                <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><path d="M6 12h12M12 6v12"/></svg>
              </button>
            ) : null}
          </div>
        </div>
      </div>

      {/* Visibility Status Toggle Overlay */}
      {isEditMode && (
        <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-10">
          <button
             onClick={(e) => { 
               e.stopPropagation(); 
               onToggleVisibility(item.id); 
             }}
             className={`pointer-events-auto flex items-center gap-2 px-4 py-2 rounded-full font-black text-[9px] uppercase tracking-widest shadow-xl transition-all active:scale-90 ${
               item.isSelected 
                ? 'bg-brand-yellow text-brand-black border border-brand-black/5' 
                : 'bg-white text-brand-black/40 border border-brand-black/5'
             }`}
             style={{ opacity: item.isSelected ? 0.3 : 1 }}
           >
             {item.isSelected ? <EyeIcon className="w-3 h-3" /> : <EyeOffIcon className="w-3 h-3" />}
             {item.isSelected ? 'Visible' : 'Hidden'}
          </button>
        </div>
      )}
    </div>
  );
};

