const DB_NAME = 'ai_marketplace_local';
const DB_VERSION = 3; 
const STORE_NAME = 'items';

export const supabase: SupabaseClient = createClient(SUPABASE_URL, SUPABASE_ANON_KEY);

const initIndexedDB = (): Promise<IDBDatabase> => {
  return new Promise((resolve, reject) => {
    const request = indexedDB.open(DB_NAME, DB_VERSION);
    request.onerror = () => reject('Error opening local database');
    request.onsuccess = () => resolve(request.result);
    request.onupgradeneeded = (event) => {
      const db = (event.target as IDBOpenDBRequest).result;
      if (!db.objectStoreNames.contains(STORE_NAME)) {
        db.createObjectStore(STORE_NAME, { keyPath: 'id' });
      }
    };
  });
};

/**
 * Fetches all items from Supabase.
 */
export const getAllItems = async (): Promise<Item[]> => {
  try {
    const { data, error } = await supabase
      .from('items')
      .select('*')
      .order('created_at', { ascending: false });

    if (error) throw new Error(`Supabase Fetch Error: ${error.message}`);

    return (data || []).map((row: any) => ({
      id: row.id,
      title: row.title,
      description: row.description,
      price: row.price,
      imageUrl: row.imageurl || row.imageUrl,
      isSelected: row.isselected !== undefined ? row.isselected : true
    })) as Item[];
  } catch (err: any) {
    console.warn("Cloud fetch failed, using local fallback", err);
    const db = await initIndexedDB();
    return new Promise((resolve, reject) => {
      const transaction = db.transaction(STORE_NAME, 'readonly');
      const store = transaction.objectStore(STORE_NAME);
      const request = store.getAll();
      request.onsuccess = () => resolve(request.result);
      request.onerror = () => reject('Error fetching local items');
    });
  }
};

/**
 * Saves or updates an item in Supabase.
 */
export const saveItem = async (item: Item): Promise<void> => {
  const fullPayload = {
    id: item.id,
    title: item.title,
    description: item.description,
    price: item.price,
    imageurl: item.imageUrl,
    isselected: item.isSelected 
  };

  try {
    const { error } = await supabase.from('items').upsert(fullPayload, { onConflict: 'id' });

    if (error) {
      // Handle cases where column names might be lowercase or missing
      if (error.message.includes('isselected') || error.code === '42703') {
        const { isselected, ...fallbackPayload } = fullPayload;
        const { error: retryError } = await supabase.from('items').upsert(fallbackPayload, { onConflict: 'id' });
        if (retryError) throw new Error(retryError.message);
      } else {
        throw new Error(error.message);
      }
    }
  } catch (err: any) {
    throw new Error(`Database Error: ${err.message}. If this is a 403, check your Supabase INSERT/UPDATE policies.`);
  }

  // Local sync
  try {
    const db = await initIndexedDB();
    const transaction = db.transaction(STORE_NAME, 'readwrite');
    transaction.objectStore(STORE_NAME).put(item);
  } catch (e) {
    console.warn("Local cache update failed", e);
  }
};

/**
 * Deletes an item from Supabase and local DB.
 */
export const deleteItemFromDB = async (id: string): Promise<void> => {
  console.log(`[Database] Triggering delete for ID: ${id}`);

  // 1. Cloud Delete
  // We use .select() to confirm if a row was actually deleted.
  // If the policy blocks it, data will be [] and error will be null.
  const { data, error } = await supabase
    .from('items')
    .delete()
    .eq('id', id)
    .select();

  if (error) {
    console.error("[Database] Supabase returned error:", error);
    throw new Error(`Cloud Delete Failed: ${error.message} (Code: ${error.code})`);
  }

  // RLS logic: Supabase returns 200 OK but empty array if policy denies the delete
  if (!data || data.length === 0) {
    console.error("[Database] Delete executed but 0 rows affected.");
    throw new Error("PERMISSION DENIED: The item was not deleted. You must enable 'DELETE' policies for the 'anon' role in your Supabase Dashboard > Authentication > Policies.");
  }

  console.log("[Database] Cloud delete successful for:", id);

  // 2. Local Delete fallback
  try {
    const db = await initIndexedDB();
    const transaction = db.transaction(STORE_NAME, 'readwrite');
    transaction.objectStore(STORE_NAME).delete(id);
  } catch (e) {
    console.warn("[Database] Local IndexedDB delete failed (non-critical):", e);
  }
};

import React, { useState, useEffect, useMemo } from 'react';
import { Item, CartItem } from './types';
import { generateItemDetails } from './services/geminiService';
import { resizeAndCompressImage } from './utils/fileUtils';
import { getAllItems, saveItem, deleteItemFromDB } from './utils/dbUtils';
import Header from './components/Header';
import ItemList from './components/ItemList';
import FileUpload from './components/FileUpload';
import Spinner from './components/Spinner';
import ItemModal from './components/ItemModal';
import CartDrawer from './components/CartDrawer';
import AuthModal from './components/AuthModal';
import WelcomeOverlay from './components/WelcomeOverlay';

export default function App() {
  const [items, setItems] = useState<Item[]>([]);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [isInitializing, setIsInitializing] = useState<boolean>(true);
  const [showWelcome, setShowWelcome] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);
  const [isEditMode, setIsEditMode] = useState<boolean>(false); 
  const [selectedItem, setSelectedItem] = useState<Item | null>(null);
  const [searchQuery, setSearchQuery] = useState<string>('');
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [isCheckoutLoading, setIsCheckoutLoading] = useState(false);
  const [isAdmin, setIsAdmin] = useState<boolean>(false);
  const [isAuthModalOpen, setIsAuthModalOpen] = useState(false);

  useEffect(() => {
    const session = localStorage.getItem('aura_admin_session');
    if (session === 'true') {
      setIsAdmin(true);
      setIsEditMode(true);
    }
    loadData();
  }, []);

  const loadData = async () => {
    try {
      const data = await getAllItems();
      setItems(data);
    } catch (e: any) {
      setError(`Sync Error: ${e.message}`);
    } finally {
      setIsInitializing(false);
    }
  };

  const filteredItems = useMemo(() => {
    return items.filter(item => {
      const matchesSearch = item.title.toLowerCase().includes(searchQuery.toLowerCase());
      const isVisible = (isAdmin && isEditMode) || item.isSelected;
      return matchesSearch && isVisible;
    });
  }, [items, searchQuery, isAdmin, isEditMode]);

  const handleImageUpload = async (file: File) => {
    if (!isAdmin) return;
    setIsLoading(true);
    setError(null);
    try {
      const { base64, mimeType } = await resizeAndCompressImage(file);
      const details = await generateItemDetails(base64, mimeType);
      const newItem: Item = { 
        id: crypto.randomUUID(), 
        imageUrl: `data:${mimeType};base64,${base64}`, 
        ...details, 
        price: 18.00,
        isSelected: true 
      };
      await saveItem(newItem);
      setItems(prev => [newItem, ...prev]);
    } catch (err: any) {
      setError(err.message || "Upload failed");
    } finally {
      setIsLoading(false);
    }
  };

  const handleUpdateItem = async (updatedItem: Item) => {
    if (!isAdmin) return;
    try {
      await saveItem(updatedItem);
      setItems(prev => prev.map(item => item.id === updatedItem.id ? updatedItem : item));
      setCart(prev => prev.map(i => i.id === updatedItem.id ? { ...updatedItem, quantity: i.quantity } : i));
    } catch (err: any) {
      setError(err.message);
      setItems(prev => prev.map(item => item.id === updatedItem.id ? updatedItem : item));
    }
  };

  const handleToggleVisibility = async (id: string) => {
    if (!isAdmin) return;
    const item = items.find(i => i.id === id);
    if (!item) return;
    const updated = { ...item, isSelected: !item.isSelected };
    await handleUpdateItem(updated);
  };

  const handleDeleteItem = async (id: string) => {
    if (!isAdmin) {
      alert("Access Denied: You must be signed in as an admin to delete items.");
      return;
    }

    const confirmDelete = window.confirm('Are you absolutely sure? This will remove the item from the cloud database permanently.');
    if (!confirmDelete) return;

    setError(null);
    try {
      // Close modal before attempt for smooth UI
      const wasSelected = selectedItem?.id === id;
      if (wasSelected) setSelectedItem(null);

      await deleteItemFromDB(id);

      // Successfully deleted from cloud, now update local state
      setItems(prev => prev.filter(item => item.id !== id));
      setCart(prev => prev.filter(item => item.id !== id));

      console.log(`[App] Successfully deleted item ${id}`);
    } catch (err: any) {
      console.error("[App] Deletion error:", err);
      // Use alert for critical DB errors so user doesn't miss them
      window.alert(`Database Error: ${err.message}`);
      setError(err.message);

      // Refresh to ensure UI matches DB state
      loadData();
    }
  };

  const handleLogin = () => {
    setIsAdmin(true);
    setIsEditMode(true);
    localStorage.setItem('aura_admin_session', 'true');
  };

  const handleLogout = () => {
    setIsAdmin(false);
    setIsEditMode(false);
    localStorage.removeItem('aura_admin_session');
  };

  const updateCartQuantity = (item: Item, delta: number) => {
    setCart(prev => {
      const existing = prev.find(i => i.id === item.id);
      if (existing) {
        const newQuantity = existing.quantity + delta;
        if (newQuantity <= 0) {
          return prev.filter(i => i.id !== item.id);
        }
        return prev.map(i => i.id === item.id ? { ...i, quantity: newQuantity } : i);
      }
      if (delta > 0) {
        return [...prev, { ...item, quantity: delta }];
      }
      return prev;
    });
  };

  const removeFromCart = (itemId: string) => {
    setCart(prev => prev.filter(i => i.id !== itemId));
  };

  const handleCheckout = async () => {
    if (cart.length === 0) return;
    setIsCheckoutLoading(true);
    const total = cart.reduce((sum, i) => sum + (i.price * i.quantity), 0);
    const orderData = {
      total: total,
      items: cart.map(item => ({ name: item.title, quantity: item.quantity }))
    };
    try {
      await fetch("https://script.google.com/macros/s/AKfycbzyaAG0r-ARF6bcKw-Kkn8o_vAbOZFNu8h92p-uRDatYrwAsu_t47Qqp6As8o1Cmy3QSQ/exec", {
        method: "POST",
        mode: "no-cors",
        body: JSON.stringify(orderData)
      });
      alert("Order Placed Successfully!");
      setCart([]);
      setIsCartOpen(false);
    } catch (err) {
      alert("There was an error placing your order.");
    } finally {
      setIsCheckoutLoading(false);
    }
  };

  const cartItemsCount = cart.reduce((acc, curr) => acc + curr.quantity, 0);

  if (isInitializing) return <div className="min-h-screen flex items-center justify-center bg-brand-bg"><Spinner /></div>;

  return (
    <div className="min-h-screen bg-brand-bg pb-24">
      {showWelcome && <WelcomeOverlay onDismiss={() => setShowWelcome(false)} items={items.filter(i => i.isSelected)} />}

