interface ItemModalProps {
  item: Item;
  onClose: () => void;
  isEditMode: boolean;
  onUpdateItem: (item: Item) => Promise<void>;
  onDeleteItem: (id: string) => Promise<void>;
  onAddToCart: () => void;
  onUpdateCartQuantity: (item: Item, delta: number) => void;
  onOpenCart: () => void;
  cartItem?: CartItem;
}

const ItemModal: React.FC<ItemModalProps> = ({ 
  item, 
  onClose, 
  isEditMode, 
  onUpdateItem, 
