const DB_NAME = 'ai_marketplace_local';
const DB_VERSION = 3; 
const STORE_NAME = 'items';

export const supabase: SupabaseClient = createClient(SUPABASE_URL, SUPABASE_ANON_KEY);

const initIndexedDB = (): Promise<IDBDatabase> => {
  return new Promise((resolve, reject) => {
    const request = indexedDB.open(DB_NAME, DB_VERSION);
    request.onerror = () => reject('Error opening local database');
    request.onsuccess = () => resolve(request.result);
    request.onupgradeneeded = (event) => {
      const db = (event.target as IDBOpenDBRequest).result;
      if (!db.objectStoreNames.contains(STORE_NAME)) {
        db.createObjectStore(STORE_NAME, { keyPath: 'id' });
      }
    };
  });
};

/**
 * Fetches all items from Supabase.
 */
export const getAllItems = async (): Promise<Item[]> => {
  try {
    const { data, error } = await supabase
      .from('items')
      .select('*')
      .order('created_at', { ascending: false });

    if (error) throw new Error(`Supabase Fetch Error: ${error.message}`);

    return (data || []).map((row: any) => ({
      id: row.id,
      title: row.title,
      description: row.description,
      price: row.price,
      imageUrl: row.imageurl || row.imageUrl,
      isSelected: row.isselected !== undefined ? row.isselected : true
    })) as Item[];
  } catch (err: any) {
    console.warn("Cloud fetch failed, using local fallback", err);
    const db = await initIndexedDB();
    return new Promise((resolve, reject) => {
      const transaction = db.transaction(STORE_NAME, 'readonly');
      const store = transaction.objectStore(STORE_NAME);
      const request = store.getAll();
      request.onsuccess = () => resolve(request.result);
      request.onerror = () => reject('Error fetching local items');
    });
  }
};

/**
 * Saves or updates an item in Supabase.
 */
export const saveItem = async (item: Item): Promise<void> => {
  const fullPayload = {
    id: item.id,
    title: item.title,
    description: item.description,
    price: item.price,
    imageurl: item.imageUrl,
    isselected: item.isSelected 
  };

  try {
    const { error } = await supabase.from('items').upsert(fullPayload, { onConflict: 'id' });

    if (error) {
      if (error.message.includes('isselected') || error.code === '42703') {
        const { isselected, ...fallbackPayload } = fullPayload;
        const { error: retryError } = await supabase.from('items').upsert(fallbackPayload, { onConflict: 'id' });
        if (retryError) throw new Error(retryError.message);
      } else {
        throw new Error(error.message);
      }
    }
  } catch (err: any) {
    throw new Error(`Database Error: ${err.message}`);
  }

  // Local sync
  try {
    const db = await initIndexedDB();
    const transaction = db.transaction(STORE_NAME, 'readwrite');
    transaction.objectStore(STORE_NAME).put(item);
  } catch (e) {
    console.warn("Local cache update failed", e);
  }
};

/**
 * Deletes an item from Supabase and local DB.
 */
export const deleteItemFromDB = async (id: string): Promise<void> => {
  console.log(`[DB] Attempting to delete: ${id}`);

  // 1. Cloud Delete
  // Note: .select() is used to verify if the row was actually found and deleted.
  const { data, error } = await supabase
    .from('items')
    .delete()
    .eq('id', id)
    .select();

  if (error) {
    console.error("[DB] Supabase error:", error);
    throw new Error(`Cloud Delete Failed: ${error.message}`);
  }

  // If data is empty but no error, it means the ID wasn't in Supabase 
  // OR RLS policies blocked the deletion.
  if (!data || data.length === 0) {
    console.warn("[DB] Deletion targeted a non-existent cloud record or was blocked by RLS.");
    // We don't throw here so that local-only items (Initial Items) can still be deleted.
  }

  // 2. Local Delete (Always happens to ensure UI consistency)
  try {
    const db = await initIndexedDB();
    const transaction = db.transaction(STORE_NAME, 'readwrite');
    transaction.objectStore(STORE_NAME).delete(id);
    console.log("[DB] Local record removed successfully.");
  } catch (e) {
    console.warn("[DB] Local delete failed", e);
  }
};

import React, { useState, useEffect, useMemo } from 'react';
import { Item, CartItem } from './types';
import { generateItemDetails } from './services/geminiService';
import { resizeAndCompressImage } from './utils/fileUtils';
import { getAllItems, saveItem, deleteItemFromDB } from './utils/dbUtils';
import Header from './components/Header';
import ItemList from './components/ItemList';
import FileUpload from './components/FileUpload';
import Spinner from './components/Spinner';
import ItemModal from './components/ItemModal';
import CartDrawer from './components/CartDrawer';
import AuthModal from './components/AuthModal';
import WelcomeOverlay from './components/WelcomeOverlay';

export default function App() {
  const [items, setItems] = useState<Item[]>([]);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [isInitializing, setIsInitializing] = useState<boolean>(true);
  const [showWelcome, setShowWelcome] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);
  const [isEditMode, setIsEditMode] = useState<boolean>(false); 
  const [selectedItem, setSelectedItem] = useState<Item | null>(null);
  const [searchQuery, setSearchQuery] = useState<string>('');
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [isCheckoutLoading, setIsCheckoutLoading] = useState(false);
  const [isAdmin, setIsAdmin] = useState<boolean>(false);
  const [isAuthModalOpen, setIsAuthModalOpen] = useState(false);

  useEffect(() => {
    const session = localStorage.getItem('aura_admin_session');
    if (session === 'true') {
      setIsAdmin(true);
      setIsEditMode(true);
    }
    loadData();
  }, []);

  const loadData = async () => {
    try {
      const data = await getAllItems();
      setItems(data);
    } catch (e: any) {
      setError(`Sync Error: ${e.message}`);
    } finally {
      setIsInitializing(false);
    }
  };

  const filteredItems = useMemo(() => {
    return items.filter(item => {
      const matchesSearch = item.title.toLowerCase().includes(searchQuery.toLowerCase());
      const isVisible = (isAdmin && isEditMode) || item.isSelected;
      return matchesSearch && isVisible;
    });
  }, [items, searchQuery, isAdmin, isEditMode]);

  const handleImageUpload = async (file: File) => {
    if (!isAdmin) return;
    setIsLoading(true);
    setError(null);
    try {
      const { base64, mimeType } = await resizeAndCompressImage(file);
      const details = await generateItemDetails(base64, mimeType);
      const newItem: Item = { 
        id: crypto.randomUUID(), 
        imageUrl: `data:${mimeType};base64,${base64}`, 
        ...details, 
        price: 18.00,
        isSelected: true 
      };
      await saveItem(newItem);
      setItems(prev => [newItem, ...prev]);
    } catch (err: any) {
      setError(err.message || "Upload failed");
    } finally {
      setIsLoading(false);
    }
  };

  const handleUpdateItem = async (updatedItem: Item) => {
    if (!isAdmin) return;
    try {
      await saveItem(updatedItem);
      setItems(prev => prev.map(item => item.id === updatedItem.id ? updatedItem : item));
      setCart(prev => prev.map(i => i.id === updatedItem.id ? { ...updatedItem, quantity: i.quantity } : i));
    } catch (err: any) {
      setError(err.message);
      setItems(prev => prev.map(item => item.id === updatedItem.id ? updatedItem : item));
    }
  };

  const handleToggleVisibility = async (id: string) => {
    if (!isAdmin) return;
    const item = items.find(i => i.id === id);
    if (!item) return;
    const updated = { ...item, isSelected: !item.isSelected };
    await handleUpdateItem(updated);
  };

  const handleDeleteItem = async (id: string) => {
    if (!isAdmin) {
      setError("You must be logged in as an administrator to perform deletions.");
      return;
    }

    const confirmDelete = window.confirm('Permanently delete this item? This action will remove it from the cloud catalog.');
    if (!confirmDelete) return;

    // Optimistic UI update: Remove it immediately from the view
    const originalItems = [...items];
    const originalCart = [...cart];

    setItems(prev => prev.filter(item => item.id !== id));
    setCart(prev => prev.filter(item => item.id !== id));
    if (selectedItem?.id === id) setSelectedItem(null);

    setError(null);
    try {
      await deleteItemFromDB(id);
      console.log(`[App] Item ${id} deleted successfully.`);
    } catch (err: any) {
      console.error("[App] Deletion logic failure:", err);
      // Rollback if there was a critical error (not just a 0-row affected case)
      setItems(originalItems);
      setCart(originalCart);
      setError(`Deletion Failed: ${err.message}. Please check your Supabase "DELETE" policies.`);

      // Refresh items to be safe
      loadData();
    }
  };

  const handleLogin = () => {
    setIsAdmin(true);
    setIsEditMode(true);
    localStorage.setItem('aura_admin_session', 'true');
  };

  const handleLogout = () => {
    setIsAdmin(false);
    setIsEditMode(false);
    localStorage.removeItem('aura_admin_session');
  };

  const updateCartQuantity = (item: Item, delta: number) => {
    setCart(prev => {
      const existing = prev.find(i => i.id === item.id);
      if (existing) {
        const newQuantity = existing.quantity + delta;
        if (newQuantity <= 0) {
          return prev.filter(i => i.id !== item.id);
        }
        return prev.map(i => i.id === item.id ? { ...i, quantity: newQuantity } : i);
      }
      if (delta > 0) {
        return [...prev, { ...item, quantity: delta }];
      }
      return prev;
    });
  };

  const removeFromCart = (itemId: string) => {
    setCart(prev => prev.filter(i => i.id !== itemId));
  };

  const handleCheckout = async () => {
    if (cart.length === 0) return;
    setIsCheckoutLoading(true);
    const total = cart.reduce((sum, i) => sum + (i.price * i.quantity), 0);
    const orderData = {
      total: total,
      items: cart.map(item => ({ name: item.title, quantity: item.quantity }))
    };
    try {
      await fetch("https://script.google.com/macros/s/AKfycbzyaAG0r-ARF6bcKw-Kkn8o_vAbOZFNu8h92p-uRDatYrwAsu_t47Qqp6As8o1Cmy3QSQ/exec", {
        method: "POST",
        mode: "no-cors",
        body: JSON.stringify(orderData)
      });
      alert("Order Placed Successfully!");
      setCart([]);
      setIsCartOpen(false);
    } catch (err) {
      alert("There was an error placing your order.");
    } finally {
      setIsCheckoutLoading(false);
    }
  };

  const cartItemsCount = cart.reduce((acc, curr) => acc + curr.quantity, 0);

  if (isInitializing) return <div className="min-h-screen flex items-center justify-center bg-brand-bg"><Spinner /></div>;

  return (
    <div className="min-h-screen bg-brand-bg pb-24">
      {showWelcome && <WelcomeOverlay onDismiss={() => setShowWelcome(false)} items={items.filter(i => i.isSelected)} />}

      <Header 
        isEditMode={isEditMode} 
        onToggleEditMode={() => isAdmin ? setIsEditMode(!isEditMode) : setIsAuthModalOpen(true)} 
        searchQuery={searchQuery}
        onSearchChange={setSearchQuery}
        items={filteredItems}
        isAdmin={isAdmin}
        onLogout={handleLogout}
        onOpenAuth={() => setIsAuthModalOpen(true)}
      />

      <main className="container mx-auto px-6 py-4 max-w-4xl">
        <div className="mb-8 text-center sm:text-left">
          <h2 className="text-3xl font-extrabold text-brand-black leading-tight tracking-tight">
            Curated <span className="text-brand-text-secondary">Essentials</span> <br/> 
            <span className="text-brand-black">
              {isAdmin && isEditMode ? 'Managing Inventory' : 'Available for Purchase'}
            </span>
          </h2>
        </div>

        {isEditMode && isAdmin && (
          <div className="mb-10">
            <FileUpload onImageUpload={handleImageUpload} isLoading={isLoading} />
          </div>
        )}

        {error && (
          <div className="mb-6 p-6 bg-white rounded-3xl border-2 border-red-500/20 shadow-xl animate-fade-in">
             <div className="flex items-start gap-4">
               <div className="w-10 h-10 rounded-full bg-red-500/10 flex items-center justify-center shrink-0">
                  <svg className="w-5 h-5 text-red-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
               </div>
               <div className="flex-grow">
                 <p className="text-xs font-black uppercase tracking-widest text-red-600 mb-1">Attention Required</p>
                 <p className="text-sm font-bold text-brand-black/70 mb-4">{error}</p>
                 <button 
                  onClick={() => setError(null)}
                  className="px-4 py-2 bg-brand-black text-white text-[10px] font-black uppercase tracking-widest rounded-xl hover:bg-brand-black/80 transition-all"
                 >
                   Dismiss
                 </button>
               </div>
             </div>
          </div>
        )}

        <ItemList 
          items={filteredItems} 
          onUpdateItem={handleUpdateItem} 
          onToggleVisibility={handleToggleVisibility}
          onDeleteItem={handleDeleteItem} 
          onSelectItem={setSelectedItem} 
          onAddToCart={(item) => updateCartQuantity(item, 1)}
          onUpdateCartQuantity={updateCartQuantity}
          isEditMode={isEditMode && isAdmin} 
          cart={cart}
        />
      </main>

      {(!isAdmin || !isEditMode) && (
        <div className="fixed bottom-6 left-6 right-6 z-40 lg:max-w-xl lg:mx-auto">
          <button 
            onClick={() => setIsCartOpen(true)}
            className="w-full bg-white/40 backdrop-blur-2xl border border-white/60 text-brand-black p-4 rounded-4xl flex items-center justify-between shadow-[0_20px_50px_rgba(0,0,0,0.1)] transition-all active:scale-95 hover:bg-white/50 ring-1 ring-black/5"
          >
            <div className="flex items-center gap-4 pl-2">
              <div className="bg-brand-black text-brand-yellow w-9 h-9 rounded-full flex items-center justify-center font-black text-sm shadow-lg">
                {cartItemsCount}
              </div>
              <div className="text-left">
                <p className="font-black text-xs uppercase tracking-[0.2em] text-brand-black/80">Your Bag</p>
                <p className="text-[10px] text-brand-black/40 font-bold uppercase tracking-tight">{cartItemsCount} items ready</p>
              </div>
            </div>
            <div className="flex -space-x-3 mr-2">
              {cart.slice(0, 3).map(i => (
                <div key={i.id} className="relative group/mini">
                  <img src={i.imageUrl} className="w-10 h-10 rounded-full border-2 border-white object-cover bg-white shadow-xl transition-transform group-hover/mini:-translate-y-1" alt="" />
                </div>
              ))}
              {cart.length > 3 && (
                <div className="w-10 h-10 rounded-full border-2 border-white bg-brand-yellow flex items-center justify-center text-[10px] font-black shadow-xl">
                  +{cart.length - 3}
                </div>
              )}
            </div>
          </button>
        </div>
      )}

      <CartDrawer 
        isOpen={isCartOpen} 
        onClose={() => setIsCartOpen(false)} 
        items={cart} 
        onRemove={removeFromCart} 
        onUpdateQuantity={updateCartQuantity}
        onCheckout={handleCheckout}
        isCheckoutLoading={isCheckoutLoading}
      />

      {selectedItem && (
        <ItemModal 
          item={selectedItem} 
          onClose={() => setSelectedItem(null)} 
          isEditMode={isEditMode && isAdmin}
          onUpdateItem={handleUpdateItem}
          onDeleteItem={handleDeleteItem}
          onAddToCart={() => updateCartQuantity(selectedItem, 1)}
          onUpdateCartQuantity={updateCartQuantity}
          onOpenCart={() => {
            setIsCartOpen(true);
            setSelectedItem(null);
          }}
          cartItem={cart.find(i => i.id === selectedItem.id)}
        />
      )}

      {isAuthModalOpen && (
        <AuthModal onLogin={handleLogin} onClose={() => setIsAuthModalOpen(false)} />
      )}
    </div>
  );
}

import React from 'react';
import { Item, CartItem } from '../types';
import { TrashIcon, EyeIcon, EyeOffIcon } from './IconComponents';

interface ItemCardProps {
  item: Item;
  onSelectItem: (item: Item) => void;
  onAddToCart: (item: Item) => void;
  onUpdateCartQuantity: (item: Item, delta: number) => void;
  onToggleVisibility: (id: string) => void;
  onDelete: (id: string) => void;
  isEditMode: boolean;
