  variant: 'pink' | 'blue';
}

const ItemCard: React.FC<ItemCardProps> = ({ 
  item, 
  onSelectItem, 
  onAddToCart, 
  onUpdateCartQuantity, 
  onToggleVisibility,
  onDelete, 
  isEditMode, 
  cartItem, 
  variant 
}) => {
  const isHidden = !item.isSelected;
