        <ItemCard
          key={item.id}
          item={item}
          onSelectItem={onSelectItem}
          onAddToCart={onAddToCart}
          onUpdateCartQuantity={onUpdateCartQuantity}
          onToggleVisibility={onToggleVisibility}
          onDelete={onDeleteItem}
          isEditMode={isEditMode}
