  return (
    <div 
      className={`relative rounded-4xl sm:rounded-5xl overflow-hidden p-4 sm:p-6 shadow-sm transition-all active:scale-95 ${bgColor} ${isHidden && isEditMode ? 'opacity-40 grayscale-[0.6] ring-1 ring-black/5' : ''}`}
