const DB_NAME = 'ai_marketplace_local';
const DB_VERSION = 4; 
const STORE_NAME = 'items';

// Initialize Supabase Client
export const supabase: SupabaseClient = createClient(SUPABASE_URL, SUPABASE_ANON_KEY);

const initIndexedDB = (): Promise<IDBDatabase> => {
  return new Promise((resolve, reject) => {
    const request = indexedDB.open(DB_NAME, DB_VERSION);
    request.onerror = () => reject('Error opening local database');
    request.onsuccess = () => resolve(request.result);
    request.onupgradeneeded = (event) => {
      const db = (event.target as IDBOpenDBRequest).result;
      if (!db.objectStoreNames.contains(STORE_NAME)) {
        db.createObjectStore(STORE_NAME, { keyPath: 'id' });
      }
    };
  });
};

export const getAllItems = async (): Promise<Item[]> => {
  try {
    const { data, error } = await supabase
      .from('items')
      .select('*')
      .order('created_at', { ascending: false });

    if (error) throw new Error(`Supabase Fetch Error: ${error.message}`);

    const mappedData = (data || []).map((row: any) => ({
      id: row.id,
      title: row.title,
      description: row.description,
      price: row.price,
      imageUrl: row.imageurl || row.imageUrl,
      // Defensive check: if the column doesn't exist in Supabase yet, use local array or empty
      imageUrls: row.additional_images || row.image_urls || row.imageUrls || [],
      isSelected: row.isselected !== undefined ? row.isselected : true 
    }));

    return mappedData as Item[];
  } catch (err: any) {
    console.warn("Cloud fetch failed or column missing, using local fallback", err);
    const db = await initIndexedDB();
    return new Promise((resolve, reject) => {
      const transaction = db.transaction(STORE_NAME, 'readonly');
      const store = transaction.objectStore(STORE_NAME);
      const request = store.getAll();
      request.onsuccess = () => resolve(request.result);
      request.onerror = () => reject('Error fetching local items');
    });
  }
};

export const saveItem = async (item: Item): Promise<void> => {
  // Always sync locally first to ensure no data loss
  try {
    const db = await initIndexedDB();
    const transaction = db.transaction(STORE_NAME, 'readwrite');
    const store = transaction.objectStore(STORE_NAME);
    store.put(item);
  } catch (localErr) {
    console.warn("Local sync failed", localErr);
  }

  // Cloud sync with retry logic for missing columns
  try {
    const basePayload = {
      id: item.id,
      title: item.title,
      description: item.description,
      price: item.price,
      imageurl: item.imageUrl,
      isselected: item.isSelected
    };

    // Attempt save with carousel images
    const { error } = await supabase.from('items').upsert({
      ...basePayload,
      additional_images: item.imageUrls || []
    }, { onConflict: 'id' });

    if (error) {
      // Check if error is due to missing column 'additional_images'
      if (error.message.includes('additional_images') || error.code === 'PGRST204') {
        console.warn("Supabase 'additional_images' column missing. Syncing basic info only.");
        const { error: retryError } = await supabase.from('items').upsert(basePayload, { onConflict: 'id' });
        if (retryError) throw new Error(`Cloud Sync Failed: ${retryError.message}`);
      } else {
        throw new Error(`Cloud Sync Failed: ${error.message}`);
      }
    }
  } catch (err: any) {
    console.error("Supabase Save Exception:", err);
    // Note: We don't throw here so the UI stays responsive and local data remains the source of truth
  }
};

export const deleteItemFromDB = async (id: string): Promise<void> => {
  const { error } = await supabase.from('items').delete().eq('id', id);
  if (error) {
    console.warn("Cloud delete failed, proceeding with local delete", error.message);
  }

  try {
    const db = await initIndexedDB();
    const transaction = db.transaction(STORE_NAME, 'readwrite');
    transaction.objectStore(STORE_NAME).delete(id);
  } catch (e) {
    console.warn("Local delete failed");
  }
};

import React, { useState } from 'react';
